/* map q06 (520 mục) — engine-API đợt 1063-1092 Ch.1092 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]=window.__LIBQ["pham-nhan-tu-tien"]["q06"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]["map"]={"updatedAt":"2026-07-16","count":520,"nodes":[{"id":"dong-du-quoc","name":"Đông Dụ quốc","cn":"東嵛國","capDo":"quoc-gia","parentId":"thien-nam","blurb":"Quốc gia nhỏ ở Thiên Nam, không thuộc bốn đại thế lực, trung lập suốt mấy trăm năm. Tài nguyên tu luyện phong phú xếp top mười Thiên Nam.","detail":"Vị trí đặc thù cách Cửu Quốc Minh quá xa, bị ba thế lực quốc gia xung quanh bao vây. Không phe nào đủ mạnh thống nhất nên duy trì trung lập. Các tông môn nơi đây đầu nhập vào chánh ma lưỡng đạo hoặc Thiên Đạo Minh. Nhiều tu sĩ bên ngoài tìm đến lập thế lực, làm nơi này phồn vinh.","theLucLienQuan":["Quỷ Linh Môn","Thiên Đạo Minh"],"nguon":["@c0793"]},{"id":"xuong-chau","name":"Xương Châu","cn":"昌州","capDo":"chau","parentId":"dong-du-quoc","blurb":"Vùng phía bắc Đông Dụ quốc, hai phần ba diện tích bằng phẳng, quá nửa rừng rậm. Nơi tu sĩ tụ tập chờ nhập Trụy Ma Cốc.","detail":"Trung tâm có Vạn Lĩnh Sơn Mạch. Mỗi đợt Trụy Ma Cốc mở, tu sĩ từ khắp nơi đổ về đây, vùng phụ cận hình thành phường thị thu mua linh dược, linh thú.","theLucLienQuan":[],"nguon":["@c0793"]},{"id":"van-linh-son-mach","name":"Vạn Lĩnh Sơn Mạch","cn":"萬嶺山脈","capDo":"vuc","parentId":"xuong-chau","blurb":"Dãy núi đồi rộng lớn bất tận ở trung tâm Xương Châu, quanh năm bị chướng khí nhiều màu sắc che phủ.","detail":"Chướng khí vừa kịch độc vừa tạo cấm chế khiến người không nhìn rõ, mất phương hướng. Cứ cách mười năm chướng khí tan đi một lần, cốc khẩu Trụy Ma Cốc mở ra khe hở không gian cho tu sĩ vào.","theLucLienQuan":[],"nguon":["@c0793"]},{"id":"thanh-diep-hoa","name":"Thành Diệp Hoa","cn":"叶华城","capDo":"thanh","parentId":"xuong-chau","blurb":"Tòa thành lớn ở Xương Châu, cách Vạn Lĩnh Sơn Mạch hơn một ngàn dặm, nơi tập trung nhiều tu sĩ chờ nhập Trụy Ma Cốc.","detail":"Tiểu tông phái quản lý thành hoảng sợ trước lượng tu sĩ đông đảo tới chờ cơ hội nhập Trụy Ma Cốc nên rút về sơn môn, giả câm giả điếc. Bên trong thành có nhiều khách điếm bị các đoàn tu sĩ thuê hết phòng.","theLucLienQuan":[],"nguon":["@c0794"]},{"id":"khach-diem-hong-phuc","name":"Khách điếm Hồng Phúc","capDo":"khac","parentId":"thanh-diep-hoa","blurb":"Khách điếm trung bình tại thành Diệp Hoa, nơi Tử Linh, Mai Ngưng và nữ tử họ Tống ở chờ Hàn Lập.","detail":"Bên trong chia ra hai ba đoàn tu sĩ thuê hết phòng. Phòng của ba nữ tử có cấm chế cách âm, bốn bức tường ẩn hiện bạch quang.","theLucLienQuan":[],"nguon":["@c0794"]},{"id":"cuc-tay-chi-dia","name":"Cực Tây chi địa","cn":"极西之地","capDo":"vuc","parentId":"thien-nam","blurb":"Vùng sa mạc phía cực Tây Thiên Nam, do Đại Diễn Thần Quân đánh chiếm và dùng làm nơi lập Thiên Trúc Giáo.","detail":"Đại Diễn Thần Quân đánh bại hai tu sĩ Chánh Ma đệ nhất Thiên Nam, bức họ phát thệ trong vạn năm không xâm phạm vùng Cực Tây, chiếm lấy làm địa bàn lập Thiên Trúc Giáo. Vùng đất tuy nghèo nàn nhưng vẫn có hai quốc gia, đủ an trí nhiều đại tông môn. Đến nay chánh ma tu sĩ vẫn không xâm phạm.","theLucLienQuan":["Thiên Trúc Giáo"],"nguon":["@c0796"]},{"id":"mat-that-thien-truc-giao","name":"Mật thất Thiên Trúc Giáo","cn":"","capDo":"khac","parentId":"cuc-tay-chi-dia","blurb":"Nơi Đại Diễn Thần Quân ẩn nấp sau khi dùng Ký Thần Thuật, được bảo vệ bởi trận pháp cực lợi hại và hơn trăm Khôi Lỗi.","detail":"Mật thất bí mật trong lãnh địa Thiên Trúc Giáo, nơi Đại Diễn Thần Quân ẩn thân sau khi dùng Ký Thần Thuật nhập thần thức vào Khôi Lỗi đặc chế. Bảo vệ bởi trận pháp cực kỳ lợi hại cùng hơn trăm Khôi Lỗi thủ vệ. Không ai biết vị trí, kể cả đệ tử Kết Đan Kỳ của Thiên Trúc Giáo. Hàn Lập tìm được và phát hiện lão hấp hối tại đây.","theLucLienQuan":["Thiên Trúc Giáo"],"nguon":["@c0796"]},{"id":"thuong-co-ma-gioi","name":"Thượng Cổ Ma Giới","cn":"上古魔界","capDo":"gioi-dien","parentId":null,"blurb":"Thế giới khác ngoài Tiên giới, Linh giới, Âm Tư chi giới. Nơi sinh sống của Cổ ma — sinh vật không phải nhân tộc không phải yêu thú, hình thái đa dạng, thần thông quỷ dị.","detail":"Thượng Cổ Ma Giới là một thế giới tồn tại bên ngoài Tiên giới, Linh giới và Âm Tư chi giới. Nơi đây sinh sống của Cổ ma — loại sinh vật không phải nhân tộc cũng không phải yêu thú, hình thái đa dạng, thần thông quỷ dị. Thời thượng cổ, Ma giới từng mở thông đạo tới nhân giới, cổ ma cấp cao tàn phá bừa bãi. Thượng cổ tu sĩ dựa vào số lượng đông đảo trải qua vô số năm tháng mới tiêu diệt hết nhưng tử thương vô số, nguyên khí tổn thương trầm trọng, nhiều thượng cổ công pháp và linh thú diệt tuyệt — đây là nguyên nhân quan trọng khiến thượng cổ tu sĩ suy tàn. Ma đạo tu sĩ hiện tại tu luyện thượng cổ ma công vốn bắt nguồn từ đường lối tu luyện của Cổ ma giới.","theLucLienQuan":[],"nguon":["@c0797"]},{"id":"bac-cuc-hoang-nguyen","name":"Bắc Cực hoang nguyên","cn":"北极荒原","capDo":"khac","parentId":"truy-ma-coc","blurb":"Khu vực bên trong Trụy Ma Cốc, Hàn Lập suy đoán đây là thông đạo bên trong cốc chứ không phải lối vào.","detail":"Hàn Lập nhận định Bắc Cực hoang nguyên không phải lối vào cốc mà là thông đạo bên trong, bởi Quỷ Linh Môn không thể đưa hơn trăm tu sĩ đồng thời tránh Bắc cực viễn quang để vào cốc.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0798"]},{"id":"phuong-thi-moi-van-linh-son","name":"Phường thị mới mở (phía tây Vạn Linh Sơn)","capDo":"khac","parentId":"van-linh-son-mach","blurb":"Phường thị đơn sơ mới mở cách tiểu sơn hơn bốn trăm dặm về hướng tây, tòa nhà xây bằng hóa thạch thuật, tu sĩ rất ít.","detail":"Hàn Lập bay đến đây mua khối lượng lớn tài liệu luyện khí để chuẩn bị luyện chế Khôi Lỗi.","theLucLienQuan":[],"nguon":["@c0799"]},{"id":"diep-hoa-thanh","name":"Diệp Hoa Thành","capDo":"thanh","parentId":"dong-du-quoc","blurb":"Thành phố gần Vạn Linh Sơn, từ đây tiến vào sơn mạch gần Trụy Ma Cốc nhất. Tu sĩ cao giai tụ tập đông đảo chuẩn bị vào Trụy Ma Cốc.","detail":"Nằm gần Vạn Linh Sơn Mạch, là tuyến đường ngắn nhất tiến vào Trụy Ma Cốc (gần hơn phân nửa lộ trình so với các hướng khác). Tu sĩ cao giai đổ về đông đảo, kéo bè kết cánh thành nhóm ba-năm người hoặc đoàn thể lớn chuẩn bị thám hiểm.","theLucLienQuan":[],"nguon":["@c0800"]},{"id":"truy-ma-coc","name":"Trụy Ma Cốc","cn":"墜魔谷","capDo":"khac","parentId":"van-linh-son-mach","blurb":"Đệ nhất hung địa, nằm ở tây bắc Vạn Lĩnh Sơn Mạch, diện tích chừng mười vạn dặm, bao quanh bởi thượng cổ cấm chế.","detail":"Trụy Ma Cốc nằm ở tây bắc Vạn Lĩnh Sơn Mạch, diện tích chừng mười vạn dặm, được mệnh danh đệ nhất hung địa. Xung quanh bị vô số thượng cổ cấm chế bao bọc hoàn toàn đồng bộ, không thể phá. Lối vào duy nhất là thông đạo rộng hơn trăm trượng nhưng tràn ngập khe không gian nguy hiểm — kích thước lớn nhất mười trượng, nhỏ nhất cỡ một thước, di chuyển khép mở không theo quy luật. Khe không gian đã giết vô số tu sĩ kể cả lão quái Nguyên Anh Kỳ. Quỷ Linh Môn có biện pháp đưa người vào an toàn, phát hành mấy trăm Trụy Ma Lệnh đã bán hết sạch.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0801","@c0844","@c0856","@c0955"]},{"id":"dong-phu-lo-truong-lao","name":"Động phủ Lỗ trưởng lão","cn":"","capDo":"khac","parentId":"van-linh-son-mach","blurb":"Thạch ốc đơn sơ bảy tám trượng, thông đạo khoảng hai mươi trượng, nơi Hàn Lập, Nam Lũng Hầu và Lỗ Vệ Anh hội họp đàm phán nhập Trụy Ma Cốc.","detail":"Động phủ của Lỗ trưởng lão (Lỗ Vệ Anh) Thiên Cực Môn tại Vạn Lĩnh Sơn Mạch, nơi ba người hội họp bàn bạc chiến lược nhập Trụy Ma Cốc.","theLucLienQuan":["Thiên Cực Môn"],"nguon":["@c0801"]},{"id":"tieu-coc-can-cu-bi-mat","name":"Tiểu cốc (căn cứ bí mật)","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Tiểu cốc ẩn giấu gần Trụy Ma Cốc, được dây leo chằng chịt và quang mạc che phủ. Bên trong có pháp trận ngũ giác, một thế lực bí mật đóng trú theo dõi Quỷ Linh Môn.","detail":"Nằm trong phụ cận Trụy Ma Cốc, dây leo chằng chịt trải dài che phủ, bên dưới có quang mạc ẩn giấu. Bên trong lão giả ngồi giữa pháp trận ngũ giác khoảng sáu bảy trượng, năm tu sĩ áo lục ngồi ở năm đỉnh.","theLucLienQuan":[],"nguon":["@c0802"]},{"id":"coc-khau-truy-ma-coc","name":"Cốc khẩu Trụy Ma Cốc","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Khu vực tập kết trước Truyền Tống Trận, nơi các tu sĩ chờ đợi và lần lượt giao Trụy Ma lệnh để được truyền tống vào Trụy Ma Cốc.","detail":"Nằm ở cửa Trụy Ma Cốc, là điểm tập kết của hơn 300 tu sĩ trước khi truyền tống. Quỷ Linh Môn bố trí Truyền Tống Trận tại đây, đệ tử bay trên không trung cầm trận kỳ kích hoạt.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0804"]},{"id":"ngoai-coc-truy-ma-coc","name":"Trụy Ma Cốc (ngoại cốc)","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Khu vực bên ngoài Trụy Ma Cốc, nơi tu sĩ được Truyền Tống Trận đưa tới. Thiên không bị cấm chế bao trùm, khe hở không gian rải rác khắp nơi, còn có các cấm chế cổ đại.","detail":"Ngoại cốc Trụy Ma Cốc là nơi tu sĩ dùng Trụy Ma lệnh được truyền tống tới, vị trí ngẫu nhiên. Thiên không bị mây vàng che phủ, bay quá năm sáu mươi trượng sẽ bị lam sắc thiểm điện đánh xuống. Khe hở không gian có hai loại: hữu hình (quang hồ bạch sắc hình trăng non, cỡ một trượng, nuốt hết kiếm khí) và vô ảnh vô hình (không thể phát hiện, giết chết tức khắc). Còn có các cấm chế cổ đại như bảy sắc thái hà nhốt người trong phạm vi mười trượng. Có hố tròn trăm trượng do thần thông thượng cổ hoặc cổ bảo hỏa thuộc tính tạo thành, bên trong dung nham đỏ sậm bóng loáng.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0805"]},{"id":"phia-tay-truy-ma-coc","name":"Phía tây Trụy Ma Cốc","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Điểm hẹn hội hợp của Hàn Lập với Nam Lũng Hầu, nơi hỏa thiềm cổ thú trông coi di hài thượng cổ tu sĩ.","detail":"Khu vực phía tây Trụy Ma Cốc, là điểm hẹn hội hợp giữa Hàn Lập và đám người Nam Lũng Hầu. Nơi đây có hỏa thiềm cổ thú trông coi di hài thượng cổ tu sĩ cùng bảo vật.","theLucLienQuan":[],"nguon":["@c0805"]},{"id":"noi-coc-truy-ma-coc","name":"Nội cốc Trụy Ma Cốc","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Khu vực sâu bên trong Trụy Ma Cốc, một số tu sĩ nóng lòng hoặc tự tin bắt đầu đi sâu vào.","detail":"Khu vực nằm sâu bên trong Trụy Ma Cốc, phân biệt với ngoại cốc. Một số tu sĩ nóng lòng hoặc tự tin về thực lực bắt đầu tiến vào nội cốc sau khi ngoại cốc không có nhiều thu hoạch.","theLucLienQuan":[],"nguon":["@c0806","@c0807"]},{"id":"tieu-son-nau-tay-truy-ma-coc","name":"Tiểu sơn màu nâu (phía tây Trụy Ma Cốc)","cn":"","capDo":"khac","parentId":"phia-tay-truy-ma-coc","blurb":"Đỉnh tiểu sơn màu nâu nơi Nam Lũng Hầu và Lỗ Vệ Anh chờ đợi Hàn Lập trước khi tiến vào nội cốc.","detail":"Tòa tiểu sơn màu nâu nằm ở phía tây Trụy Ma Cốc, nơi Nam Lũng Hầu đứng lo âu nhìn xa và Lỗ Vệ Anh ngồi xếp bằng dưỡng thần chờ Hàn Lập đến hội hợp.","theLucLienQuan":[],"nguon":["@c0807"]},{"id":"thong-dao-noi-coc-truy-ma-coc","name":"Thông đạo nội cốc Trụy Ma Cốc","cn":"","capDo":"khac","parentId":"noi-coc-truy-ma-coc","blurb":"Khu vực giữa hai sườn núi dẫn vào nội cốc Trụy Ma Cốc, ở giữa là dải sương mù xám rộng hơn trăm trượng chứa cự mãng yêu thú, hai bên là huyết sắc quang hà đỏ như máu.","detail":"Thông đạo nằm giữa hai sườn núi phủ đầy đá trắng hình tròn bóng loáng, là lối duy nhất vào nội cốc. Ở giữa là dải sương mù xám rộng hơn trăm trượng do cự mãng yêu thú phun yêu vụ tạo thành. Hai bên có huyết sắc quang hà đỏ như máu không ngừng đè ép nhưng không xâm nhập được vào sương mù. Di thư Thương Khôn Thượng Nhân không đề cập đến sương mù này, suy luận cự mãng đến sau.","theLucLienQuan":[],"nguon":["@c0808"]},{"id":"son-dong-dan-vao-noi-coc","name":"Sơn động dẫn vào nội cốc","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Sơn động tối đen rộng bảy tám trượng nằm trên thạch bích vàng nhạt cao lớn, cách vị trí giết cự mãng khoảng hai mươi dặm. Xuyên qua sơn động hơn mười dặm có bắc cực nguyên quang, qua đó sẽ vào nội cốc Trụy Ma Cốc.","detail":"Thạch bích màu vàng nhạt cao lớn với sơn động rộng bảy tám trượng, tối đen bên trong. Theo Nam Lũng Hầu, xuyên qua sơn động hơn mười dặm sẽ gặp bắc cực nguyên quang, cần lưỡng nghi hoàn mới có thể vượt qua. Không thể đục thạch bích đi đường khác.","theLucLienQuan":[],"nguon":["@c0810"]},{"id":"thung-lung-bang-tuyet","name":"Thung lũng băng tuyết","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Thung lũng trong Trụy Ma Cốc, nơi nhóm Quỷ Linh Môn giao chiến bích hổ cổ thú và phát hiện khe băng có bạch quang dẫn vào khu vực bí mật.","detail":"Thung lũng phủ băng tuyết bên trong Trụy Ma Cốc. Nhóm tu sĩ Quỷ Linh Môn do lão giả họ Chung dẫn đầu chiến đấu với bích hổ cổ thú tại đây. Dưới thi thể cổ thú lộ ra một khe băng khá rộng có bạch quang phát ra, là lối vào khu vực sâu hơn.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0812"]},{"id":"hap-coc-lon-cam-che-noi-coc","name":"Hạp cốc lớn (cấm chế nội cốc)","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Hạp cốc lớn trước lối vào nội cốc Trụy Ma Cốc, có cấm chế nhiều màu cực lợi hại, bên trong có huyết quang lập lòe.","detail":"Hạp cốc lớn nằm trước thông đạo vào nội cốc Trụy Ma Cốc. Cửa vào bị phủ cấm chế nhiều màu cổ xưa cực kỳ lợi hại. Bên trong mơ hồ có huyết quang lập lòe. Thiên Tinh Chân Nhân và Đông Môn Đồ (Ngự Linh Tông) thỏa thuận liên thủ phá trận tại đây.","theLucLienQuan":["Ngự Linh Tông"],"nguon":["@c0812"]},{"id":"hai-ngon-nui-cao-lon-noi-coc","name":"Hai ngọn núi cao lớn (nội cốc)","cn":"","capDo":"khac","parentId":"noi-coc-truy-ma-coc","blurb":"Hai ngọn núi cực kỳ cao lớn nằm hai bên trái phải lộ tuyến trong nội cốc Trụy Ma Cốc, Nam Lũng Hầu cảnh báo phiền toái và nguy hiểm liên quan đến chúng.","detail":"Xa xa hai bên trái phải lộ tuyến phi hành trong nội cốc, hai ngọn núi cực kỳ cao lớn bắt mắt. Nam Lũng Hầu đột ngột dừng lại khi nhìn thấy chúng, sắc mặt âm tình bất định, cảnh báo rằng bọn họ có thể gặp phiền toái thậm chí nguy hiểm liên quan đến hai ngọn núi này. Chưa rõ cụ thể phiền toái là gì.","theLucLienQuan":[],"nguon":["@c0813"]},{"id":"vong-thuy-quoc","name":"Vọng Thủy Quốc","cn":"望水国","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia nơi Phi Thiên Tử Vân hạt từng xuất hiện và diệt sát toàn bộ tu sĩ Lam Hải tông, dẫn đến cuộc vây sát có sự tham gia của Thiên Cực Môn.","detail":"Vọng Thủy Quốc là nơi Tử Vân hạt từng xuất hiện và tàn sát toàn bộ tu sĩ Lam Hải tông. Sự kiện này dẫn đến cuộc vây sát quy mô lớn mà Lỗ Vệ Anh khi còn trẻ đã đại biểu cho Thiên Cực Môn trực tiếp tham gia.","theLucLienQuan":["Lam Hải tông","Thiên Cực Môn"],"nguon":["@c0814"]},{"id":"dung-nham-chi-dia","name":"Dung Nham Chi Địa","cn":"熔岩之地","capDo":"khac","parentId":null,"blurb":"Khu vực không khí cực nóng, cây cối không mọc, đá núi màu đỏ yêu dị, có khe dung nham phun tro xám. Nổi bật là tòa núi cao mấy ngàn trượng màu đỏ đậm bị mây lửa bao phủ, dưới chân núi có động quật là sào huyệt Hỏa Thiềm thú, bên trong có di hài tu sĩ thượng cổ.","detail":"Khu vực nằm cách lãnh địa Tử Vân hạt khoảng nửa ngày phi hành. Càng tiến sâu, không khí càng nóng, cây cối thưa dần rồi biến mất hoàn toàn, đá núi chuyển sang màu đỏ yêu dị, xuất hiện khe dung nham nhỏ phun tro xám và hơi nóng cực lớn. Trung tâm là tòa núi cao mấy ngàn trượng màu đỏ đậm, hơn nửa ngọn bị mây lửa bao phủ. Dưới chân núi có động quật lớn là sào huyệt Hỏa Thiềm thú, nửa sào huyệt nằm trong dung nham — thú có thể nhảy vào dung nham khôi phục nguyên trạng dù bị trọng thương đến mức nào. Di hài tu sĩ thượng cổ cũng nằm trong sào huyệt này, là mục tiêu chính của nhóm Hàn Lập.","theLucLienQuan":[],"nguon":["@c0815"]},{"id":"dinh-nui-lanh-dia-tu-van-hat","name":"Đỉnh núi lãnh địa Tử Vân hạt","cn":"","capDo":"khac","parentId":null,"blurb":"Đỉnh núi nơi đàn Tử Vân hạt 13-14 con trú ngụ, ba người phải dùng mưu dẫn dụ đàn hạt rời đi mới vượt qua được.","detail":"Đỉnh núi có khoảng 13-14 con Tử Vân hạt trú ngụ, con thủ lĩnh dài hơn hai trượng. Đàn hạt có thiên phú công kích bằng âm thanh quái dị tác động trực tiếp lên chân nguyên chứ không phải thần thức, khiến ngay cả tu sĩ mạnh cũng chật vật. Cách sào huyệt Hỏa Thiềm thú tại Dung Nham Chi Địa khoảng nửa ngày phi hành.","theLucLienQuan":[],"nguon":["@c0815"]},{"id":"hang-dong-hoa-thiem-thu","name":"Hang động Hỏa Thiềm Thú","cn":"","capDo":"khac","parentId":"dung-nham-chi-dia","blurb":"Hang động thiên nhiên dưới chân núi lửa trong Trụy Ma Cốc, nơi Hỏa Thiềm Thú trú ngụ cùng di hài tu sĩ cổ.","detail":"Thông đạo thiên nhiên cao bảy tám trượng, hai bên đỏ đậm phun tia lửa, nhiệt độ cực cao. Bên trong là thế giới ngầm rộng khoảng trăm trượng, hồ dung nham chiếm hơn nửa diện tích đang sôi sục bong bóng lửa. Giữa hồ có khối nham thạch lớn — nơi Hỏa Thiềm Thú nằm ngủ. Đối diện hồ có thạch thai cổ xưa khắc hoa văn ký hiệu, bốn góc vỡ nát, trên đặt di hài tu sĩ mặc trường bào xanh. Quanh hồ mọc linh thảo xanh trên đất đá đỏ.","theLucLienQuan":[],"nguon":["@c0816"]},{"id":"sao-huyet-hoa-thiem-thu","name":"Sào huyệt Hỏa Thiềm thú","cn":"","capDo":"khac","parentId":"hang-dong-hoa-thiem-thu","blurb":"Hang động dưới chân núi trong Trụy Ma Cốc, bên trong có hồ dung nham và thạch thai nơi nằm bộ hài cốt cổ tu sĩ mặc Thanh Tàm bào.","detail":"Sào huyệt của Hỏa Thiềm cổ thú. Bên trong có hồ dung nham, trên thạch thai bên hồ có bộ hài cốt cổ tu sĩ mặc thanh bào (Thanh Tàm bào), mang túi trữ vật chứa linh liệu và nhiều cổ bảo. Ba tu sĩ Hàn Lập, Nam Lũng Hầu và Lỗ Vệ Anh bay qua hồ dung nham đáp xuống thạch thai để khám xét di hài.","theLucLienQuan":[],"nguon":["@c0818"]},{"id":"huyet-chu-chi-mon","name":"Huyết chú chi môn","cn":"血咒之門","capDo":"khac","parentId":"noi-coc-truy-ma-coc","blurb":"Cánh cửa bị phong bế bằng cấm chế huyết chú thượng cổ nằm trong nội cốc Trụy Ma Cốc, phía sau chứa trọng bảo.","detail":"Cánh cửa được phong bế bằng cấm chế huyết chú thượng cổ, nằm trong nội cốc Trụy Ma Cốc, cách vị trí phân chia bảo vật của ba người không xa. Phía sau chứa trọng bảo do cổ tu sĩ phong ấn. Chìa khóa phá giải là bộ hài cốt cổ tu sĩ trong suốt — người đã thi triển huyết chú rồi tọa hóa tại chỗ. Nam Lũng Hầu và Lỗ Vệ Anh dựa theo di thư Thương Khôn thượng nhân quyết định đến đây lấy bảo.","theLucLienQuan":[],"nguon":["@c0820"]},{"id":"thuy-dam-bich-luc","name":"Thủy đàm bích lục","cn":"","capDo":"khac","parentId":"dinh-nui-lanh-dia-tu-van-hat","blurb":"Thủy đàm màu bích lục nằm trong động thạch nhũ dưới sào huyệt Tử Vân Hạt, rộng mười trượng, sâu khoảng ba trăm trượng. Đáy đàm ẩn giấu Huyết Chú Chi Môn.","detail":"Động thạch nhũ rộng ba mươi trượng, trung tâm có thủy đàm màu bích lục rộng mười trượng, sâu khoảng ba trăm trượng. Đáy đàm tròn, rộng hơn chục trượng, có tảng đá bóng loáng. Phía sau màn nước ẩn giấu thạch môn hình vòm cao ba trượng, lóe huyết sắc hồng quang, điêu khắc đầu quỷ một sừng — chính là Huyết Chú Chi Môn mà Thương Khôn Thượng Nhân dùng cấm chế che giấu.","theLucLienQuan":[],"nguon":["@c0821"]},{"id":"linh-mieu-vien","name":"Linh Miểu Viên","cn":"灵淼渊","capDo":"khac","parentId":"truy-ma-coc","blurb":"Nơi truyền thuyết mà không gian linh giới và nhân giới giao nhau. Trụy Ma Cốc được Thượng cổ tu sĩ tu kiến chuyên để trông coi Linh Miểu Viên. Cửa vào do Thượng cổ tu sĩ dùng tinh huyết toàn thân phong ấn, Quỷ Linh Môn có bảy tám phần nắm chắc sự tồn tại.","detail":"Linh Miểu Viên là nơi không gian linh giới và nhân giới giao nhau theo truyền thuyết. Cả Trụy Ma Cốc do Thượng cổ tu sĩ chuyên môn tu kiến để trông coi nơi này. Cửa vào nằm ở đáy thủy đàm, là phiến thạch môn không lớn bị phong ấn bằng tinh huyết toàn thân của Thượng cổ tu sĩ, huyết khí và ma khí nồng nặc. Quỷ Linh Môn khẳng định có bảy tám phần nắm chắc sự tồn tại và có chứng cớ chưa tiết lộ.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0822","@c0833","@c1017"]},{"id":"nui-lua-do-dam","name":"Núi lửa đỏ đậm","capDo":"khac","parentId":"dung-nham-chi-dia","blurb":"Tòa núi lửa màu đỏ đậm cao ước mấy ngàn trượng ở Dung Nham Chi Địa, hơn phân nửa bị mây lửa bao phủ.","detail":"Nổi bật giữa các đỉnh thấp xung quanh, là đích đến của lộ tuyến Nam Lũng Hầu dẫn đường. Dưới chân núi có động quật là sào huyệt Hỏa Thiềm thú, bên trong có di hài tu sĩ thượng cổ.","theLucLienQuan":[],"nguon":["@c0815"]},{"id":"dai-sanh-duoi-long-dat-huyet-chu","name":"Đại sảnh dưới lòng đất (sau Huyết chú chi môn)","cn":null,"capDo":"khac","parentId":null,"blurb":"Gian phòng rộng bảy tám trượng nằm dưới lòng đất, vào bằng cầu thang đen dài hai mươi trượng sau thạch môn bị phong ấn bởi Huyết chú chi môn.","detail":"Bên trong chỉ có một cái bàn bày sáu bảy thứ linh dược quý hiếm gồm Thiên nguyên quả, tử sắc linh chi hơn ngàn năm tuổi và một cây gậy trúc nghi là Kim Lôi Trúc (tam đại thần mộc). Vách tường bốn phía có ký hiệu ẩn hiện của Tiểu tu di kim cương trận — một Phật tông pháp trận bảo vệ bảo vật, khiến Lỗ Vệ Anh bất ngờ vì gặp pháp trận Phật tông ở nơi vốn phong ấn bằng tà thuật.","theLucLienQuan":[],"nguon":["@c0823"]},{"id":"huyet-quang-thach-mon","name":"Huyết quang thạch môn","cn":null,"capDo":"khac","parentId":null,"blurb":"Cánh cửa đá có điêu khắc quỷ đầu, được phong ấn bằng Huyết chú cấm chế, nằm tại khu vực hồ nước.","detail":"Thạch môn phong ấn bằng huyết quang, khi bị công kích thì ngưng tụ thành mặt quỷ to cỡ một trượng giống hệt quỷ đầu điêu khắc trên cửa, có thể nuốt chửng mọi đợt công kích. Nam Lũng Hầu dùng cốt phấn chứa tinh nguyên cổ tu hóa giải mặt quỷ, sau đó hợp lực với Lỗ Vệ Anh phá hủy hoàn toàn thạch môn. Mảnh vỡ chảy ra dòng máu đỏ sậm hôi thối. Sau cửa lộ ra cầu thang đen dẫn xuống đại sảnh chứa linh dược dưới lòng đất.","theLucLienQuan":[],"nguon":["@c0823"]},{"id":"truy-ma-coc-noi-coc","name":"Trụy Ma Cốc — nội cốc","cn":"坠魔谷内谷","capDo":"khac","parentId":"truy-ma-coc","blurb":"Khu vực sâu bên trong Trụy Ma Cốc, được xưng là Thiên Nam đệ nhất hung địa. Linh cầm vào nội cốc đều cực kỳ sợ hãi nổi điên không khống chế được.","detail":"Hàn Lập bay nhanh qua đỉnh núi có Tử vân hạt hướng về sơn động vào nội cốc. Nhạc thượng sư gọi đây là Thiên Nam đệ nhất hung địa, mọi linh cầm kể cả ô sí điêu ngũ cấp vào nội cốc đều sợ hãi nổi điên, nghi nơi đây có vật chuyên khắc chế yêu thú.","theLucLienQuan":["Mộ Lan tộc"],"nguon":["@c0824"]},{"id":"dai-sanh-chua-linh-duoc","name":"Đại sảnh chứa linh dược","cn":"","capDo":"khac","parentId":"dai-sanh-duoi-long-dat-huyet-chu","blurb":"Căn phòng trong nội cốc Trụy Ma Cốc nơi Nam Lũng Hầu và Lỗ Vệ Anh phát hiện Tiểu Tu Di Kim Cương Trận bảo vệ linh dược cùng ngân viên bát và ba pháp khí Phật tông.","detail":"Nằm phía sau huyết chú chi môn, bên trong có bàn đặt linh dược với cấm chế cổ quái bảo vệ. Khi kích hoạt, cấm chế hiện màn hào quang kim sắc với phật văn thượng cổ, lộ ra ngân viên bát và ba pháp khí ẩn giấu ở trung tâm.","theLucLienQuan":["Phật Tông"],"nguon":["@c0824"]},{"id":"vach-nui-cua-dong-noi-coc","name":"Vách núi cửa động nội cốc","cn":null,"capDo":"khac","parentId":"truy-ma-coc","blurb":"Vách núi phía ngoại cốc nơi thông đạo dẫn ra từ nội cốc, cũng là nơi đặt mỏ cương ngân sa do Phệ Kim Trùng khai thác.","detail":"Hàn Lập xuyên qua thông đạo, vượt Bắc Cực Nguyên Quang ra đến vách núi này. Bầu trời hôn ám nhưng khá hơn huyết sắc hà quang bên trong nội cốc. Mỏ quặng cương ngân sa nằm trong vách đá cửa động, đàn Phệ Kim Trùng từ quang mạc bay ra nhả tinh thể cương ngân sa đã tinh luyện với trữ lượng vượt xa dự liệu.","theLucLienQuan":[],"nguon":["@c0825"]},{"id":"bon-dia-te-dan","name":"Bồn địa chứa tế đàn","cn":"","capDo":"khac","parentId":"truy-ma-coc-noi-coc","blurb":"Phiến bồn địa âm u ẩm ướt nằm phía sau cự sơn trong Hư Thiên cốc, trung tâm có tòa tế đàn đá trắng khổng lồ hình thang cao hơn trăm trượng.","detail":"Vũng nước khắp nơi, bụi cây rậm rạp. Cấm chế cực mạnh: bay lên bị huyết sắc thiểm điện phách xuống kích nát hộ thân pháp bảo, càng gần trung tâm càng khắc nghiệt. Có khe hở không gian ẩn hình mới xuất hiện, cực kỳ nguy hiểm. Là kiến trúc hoàn chỉnh đầu tiên đoàn người gặp từ khi vào cốc, nghi liên quan đến Linh Miểu Viên.","theLucLienQuan":[],"nguon":["@c0826"]},{"id":"te-dan-da-trang","name":"Tế đàn đá trắng","cn":"","capDo":"khac","parentId":"bon-dia-te-dan","blurb":"Tòa tế đàn hoàn toàn bằng đá trắng, tứ phía trải rộng hình thang, cao vút hơn trăm trượng, nằm ở trung tâm bồn địa.","detail":"Kiến trúc hoàn chỉnh đầu tiên đoàn người phát hiện từ khi vào cốc, khiến tinh thần ai nấy phấn chấn, tin rằng nơi này liên quan đến Linh Miểu Viên.","theLucLienQuan":[],"nguon":["@c0826"]},{"id":"bang-phung-noi-coc","name":"Băng phùng (khe nứt trên mặt băng)","cn":"","capDo":"khac","parentId":"truy-ma-coc-noi-coc","blurb":"Khe nứt rộng hơn hai mươi trượng trên mặt băng, là lối vào nội cốc Trụy Ma Cốc.","detail":"Linh thú bình thường qua đây bị mất khống chế (phi thử của Tử Linh, linh cầm Mộ Lan pháp sĩ), trong khi kỳ trùng đặc biệt như Phệ Kim Trùng và Đề Hồn Thú không bị ảnh hưởng.","theLucLienQuan":[],"nguon":["@c0827"]},{"id":"dam-loan-thach-ho-trong","name":"Đám loạn thạch lớn (hố trống)","cn":"","capDo":"khac","parentId":"truy-ma-coc-noi-coc","blurb":"Một trong ba địa điểm có dấu hiệu tìm được linh chúc quả bên trong nội cốc Trụy Ma Cốc.","detail":"Hàn Lập và Tử Linh bay tới đây phát hiện hố trống trơn — Quỷ Linh Môn đã qua trước lấy mất.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0827"]},{"id":"hoang-tho-cam-che-co","name":"Hoang thổ (nơi Quỷ Linh Môn bị kẹt)","cn":null,"capDo":"khac","parentId":"truy-ma-coc-noi-coc","blurb":"Vùng hoang thổ có thượng cổ tiểu cấm chế, đám người Quỷ Linh Môn bị kẹt tại đây do đệ tử phạm sai lầm kích hoạt cấm chế.","detail":"Khu vực hoang thổ trên lộ tuyến tiến vào nội cốc Trụy Ma Cốc. Ẩn chứa thượng cổ tiểu cấm chế, khi bị kích hoạt có thể vây khốn tu sĩ nhưng không đủ mạnh để cầm chân Nguyên Anh Trung Kỳ lâu dài. Hàn Lập dùng thần thức cường đại quan sát từ xa, xác nhận cấm chế không đủ uy lực rồi đi chếch lộ tuyến vượt qua.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0828"]},{"id":"phi-dieu-son-phong","name":"Phi điểu sơn phong (tiêu ký trung gian)","cn":null,"capDo":"khac","parentId":"truy-ma-coc-noi-coc","blurb":"Sơn mạch có ngọn núi hình đại điểu, là tiêu ký trung gian chỉ phương hướng đến tiêu ký tối hậu ở khu vực sa mạc trong vòng ngàn dặm.","detail":"Khu vực núi non xanh biếc ẩm ướt, đỉnh núi có hình dáng như con đại điểu đang đậu (phi điểu sơn phong). Mỏ phi điểu chỉ phương hướng tiêu ký tối hậu (nơi có linh quả mục tiêu). Hàn Lập đã dùng kiếm khí tay không cắt sập hai cánh đỉnh núi khiến ngọn núi trở nên bình thường, sau đó Ngân Nguyệt bố trí huyễn thuật biến cả ngọn núi thành rừng rậm ảo để che giấu tiêu ký trước Quỷ Linh Môn.","theLucLienQuan":[],"nguon":["@c0828"]},{"id":"dien-tho-duoi-day-thuy-dam","name":"Điện thờ dưới đáy thủy đàm","cn":"","capDo":"khac","parentId":null,"blurb":"Điện thờ ẩn dưới đáy thủy đàm, bày linh dược cùng bảo vật, thực chất là nơi phong ấn viên bát cổ bảo chứa tà hồn.","detail":"Điện thờ nằm dưới đáy thủy đàm, trên bàn thờ bày nhiều linh dược quý như thiên nguyên quả có công dụng tăng trưởng thọ nguyên cùng tử sắc linh chi, kèm theo viên bát cổ bảo, ba kiện pháp khí và ngọc phù. Nam Lũng Hầu và Lỗ Vệ Anh vào đây phân chia bảo vật: Lỗ Vệ Anh thu ba pháp khí cùng ngọc phù — thực chất là vật thượng cổ tu sĩ dùng trấn áp viên bát — khiến phong ấn bị giải trừ. Toàn bộ linh dược trên điện thờ lóe lục quang rồi tan thành hư không khi hai người định thu lấy, cho thấy nơi này có thể là bẫy hoặc ảo ảnh. Viên bát sau đó bùng nổ, giải phóng ô quang đoạt xá thân xác Nam Lũng Hầu ngay trong điện thờ; Lỗ Vệ Anh chạy về lối ra thì bị kẻ đoạt xá chặn đường, đánh cắm sâu vào thạch bích. Bên ngoài điện thờ, dưới đáy thủy đàm còn có pháp trận chưa rõ công dụng.","theLucLienQuan":[],"nguon":["@c0829"]},{"id":"oc-dao-linh-chuc-qua","name":"Ốc đảo Linh Chúc Quả","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Ốc đảo bị cấm chế che giấu, bên ngoài chỉ hiện ra sa mạc vàng kéo dài. Bên trong có lục hồ, giữa hồ có mảnh đất nhỏ mọc linh thảo kết bốn quả Linh Chúc Quả.","detail":"Hàn Lập và Tử Linh Tiên Tử đứng trong một ốc đảo được cấm chế che phủ, từ bên ngoài nhìn vào chỉ thấy sa mạc. Trung tâm ốc đảo là hồ nước xanh, giữa hồ có một mảnh đất nhỏ mọc cây linh thảo xanh mướt cao vài thước, trên đỉnh kết bốn quả Linh Chúc Quả hỏa hồng, tỏa dược hương nồng đậm. Hai người xác nhận linh quả rồi chuẩn bị hái ngay để tránh phát sinh biến cố.","theLucLienQuan":[],"nguon":["@c0830"]},{"id":"vung-cao-nguyen-mau-vang","name":"Vùng cao nguyên màu vàng","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Vùng địa hình sau khi rời sa mạc trong Trụy Ma Cốc.","detail":"Hàn Lập và Tử Linh đi Ngự Phong Xa rời sa mạc, thấy phía trước là vùng cao nguyên màu vàng chập chùng. Cảnh tượng này khiến Hàn Lập cảm thán Trụy Ma Cốc bao la, một góc đã gom đủ nhiều dạng địa hình.","theLucLienQuan":[],"nguon":["@c0832"]},{"id":"day-nui-truy-ma-coc","name":"Dãy núi (Trụy Ma Cốc)","cn":"","capDo":"khac","parentId":"truy-ma-coc","blurb":"Dãy núi nơi Hàn Lập và Tử Linh dừng lại để luyện Tạo Hóa đan.","detail":"Sau khi rời sa mạc và vượt qua vùng cao nguyên, Hàn Lập cùng Tử Linh tới một dãy núi trong Trụy Ma Cốc. Hàn Lập đi sâu thêm mấy trăm dặm, chọn một đỉnh núi nhỏ bình thường, dùng thần thức xác nhận không có cấm chế thượng cổ hay khe hở không gian rồi mở động phủ tạm luyện đan; Tử Linh sang ngọn núi gần đó mở mật thất riêng.","theLucLienQuan":[],"nguon":["@c0832"]},{"id":"khe-ho-khong-gian-tren-te-dan","name":"Khe hở không gian (trên tế đàn)","cn":"","capDo":"khac","parentId":"te-dan-da-trang","blurb":"Khe hở không gian hình vầng trăng khuyết xuất hiện phía trên tế đàn, là lối được nho sinh chỉ ra để tiến vào khu vực vốn được cho là Linh Miểu Viên.","detail":"Khe hở nằm trên tế đàn hơn trăm trượng, dài hơn ba mươi trượng, chỗ rộng nhất khoảng bốn năm trượng, trước đó bị cấm chế che lấp nên ngay cả tu sĩ Nguyên Anh cũng khó phát hiện. Bên trong có lực cắt không gian đáng sợ; nho sinh cảnh báo người tu vi không đủ, đặc biệt tu sĩ Kết Đan Kỳ, đi vào gần như chịu chết. Về sau Phá Giới Châu được dùng để kích phát lục quang trong khe hở, mở ra thông đạo màu đen dẫn sang không gian xám.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0834"]},{"id":"khong-gian-xam-giao-gioi-nhan-gioi-thanh-gioi","name":"Không gian xám (giao giới Nhân giới – Thánh giới)","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian toàn màu xám ở đầu kia thông đạo, không giống Linh Miểu Viên trong truyền thuyết và có ma khí nồng đậm hơn Nhân giới.","detail":"Bên trong không gian này là đất xám, sương mù xám, trần cao hơn mười trượng; phạm vi thần thức của Ngụy Vô Nhai chỉ dò được khoảng mười dặm. Môn chủ Quỷ Linh Môn và Vương Thiên Cổ phát hiện ma khí nơi đây ít nhất gấp đôi Nhân giới, có thể tăng uy lực ma công và có lợi cho việc đột phá. Gần trung tâm có một yêu vật khổng lồ bị phong ấn trong khối thủy tinh như lửa, ma khí chung quanh càng nồng đặc. Nho sinh tiết lộ đây không phải Linh Miểu Viên mà là không gian giao giữa Nhân giới và Thánh giới.","theLucLienQuan":["Quỷ Linh Môn"],"nguon":["@c0834"]},{"id":"thanh-gioi","name":"Thánh giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Thánh giới được nho sinh nhắc đến khi tiết lộ bản chất thật của không gian xám.","detail":"Theo lời nho sinh, không gian xám chỉ là nơi giao giữa Nhân giới và Thánh giới. Khi nghe đến tên Thánh giới, Ngụy Vô Nhai lập tức hoảng sợ, gọi nho sinh là Cổ ma và vội vận lục sắc độc vụ phòng thân.","theLucLienQuan":[],"nguon":["@c0834"]},{"id":"linh-gioi","name":"Linh giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Linh giới được nhắc như một trong hai giới mà Linh Miểu Viên vốn nằm ở khoảng giữa.","detail":"Nho sinh nói Linh Miểu Viên nguyên vốn tồn tại giữa Linh giới và Nhân giới, vì vậy muốn đi vào phải lợi dụng khe hở không gian. Chương này chỉ nhắc Linh giới qua quan hệ vị trí với Linh Miểu Viên, chưa mô tả trực tiếp cảnh vật hay thế lực tại đó.","theLucLienQuan":[],"nguon":["@c0834","@c1056"]},{"id":"duoc-vien-tan-hai","name":"Dược viên tàn hài","cn":"","capDo":"khac","parentId":"linh-mieu-vien","blurb":"Tàn tích dược viên thượng cổ trong không gian lạ, đã lâu không người lui tới. Nơi này chứa nhiều linh dược cổ có dược tính hơn vạn năm và là nguồn nguyên liệu then chốt cho Giáng Vân Đan, Tuyết Phách Hoàn.","detail":"Hàn Lập cùng Đại Diễn Thần Quân khảo sát dược viên tàn hài và phát hiện nhiều linh dược quý hiếm như Uyển Mộng Quả. Phần lớn linh thảo ở đây có linh tính cực cổ, giúp Hàn Lập nhận ra cơ duyên luyện thượng cổ linh đan, nhưng một số loại không thể di thực khiến kế hoạch luyện Giáng Vân Đan bị giới hạn.","theLucLienQuan":[],"nguon":["@c0853"]},{"id":"khong-gian-la","name":"Không gian lạ","cn":"","aliases":["Không gian này"],"capDo":"gioi-nho","parentId":null,"blurb":"Không gian bị phong bế nơi Hàn Lập đang mắc kẹt sau biến cố trong Linh Miểu Viên. Nơi này không có nhật nguyệt tinh thần, bốn phía không gian chi bích chưa lộ sơ hở, mặt đất và bầu trời đều có cấm chế.","detail":"Sau khi thu hoạch dược viên, vấn đề cấp bách của Hàn Lập là rời khỏi không gian này để trở về nhân giới. Hắn đã dò bốn phía không gian chi bích nhưng không phát hiện điểm bất ổn, tiểu bình cũng mất hiệu dụng vì nơi này không có nhật nguyệt tinh thần; lòng đất có cấm chế không đầy đủ, còn trên không là vùng vân vụ nguy hiểm.","theLucLienQuan":[],"nguon":["@c0853"]},{"id":"khoi-van-vu-menh-mong-ben-tren","name":"Khối vân vụ mênh mông bên trên","cn":"","capDo":"khac","parentId":"khong-gian-la","blurb":"Vùng vân vụ trên cao trong không gian lạ, gắn với cấm chế nguy hiểm từng diệt sát Ma hồn. Đây là hướng dò xét cuối cùng Hàn Lập chọn sau khi bốn phía và lòng đất đều không có lối ra.","detail":"Khối vân vụ mênh mông bên trên khiến Hàn Lập dè chừng vì cấm chế tại đó vừa đánh chết Ma hồn trước mắt hắn. Tuy vậy, vì những hướng khác đều không phát hiện sơ hở, Hàn Lập quyết định mạo hiểm bay lên kiểm tra, suy đoán ngân sắc hỏa diễm có thể chỉ khắc chế cổ ma chứ chưa chắc gây hại cho nhân loại tu sĩ.","theLucLienQuan":[],"nguon":["@c0853"]},{"id":"tan-tich-linh-mieu-vien","name":"Tàn tích Linh Miểu Viên","aliases":["Tàn hài Linh Miểu viên","Tàn tích","Tàn hài Linh Miểu viên","Tàn hài không gian Linh Miểu viên"],"capDo":"gioi-nho","parentId":null,"blurb":"Đây là tàn hài không gian nơi Hàn Lập và Ngân Nguyệt đang bị kẹt. Bên trong có cấm chế bạc, vách không gian vàng xám bất ổn và một điểm yếu không gian có thể trở thành lối thoát về sau.","detail":"Tàn tích Linh Miểu Viên là một không gian gần như phong bế, vốn đã ở bên bờ hủy diệt theo lời Đại Diễn Thần Quân. Cấm chế trong này dường như nhắm vào cổ ma, còn bản thân không gian lại tồn tại những điểm yếu chạy loạn trong toàn bộ phạm vi. Nhờ linh khí dày đặc cùng linh dược sẵn có, nơi này vừa là hiểm cảnh giam giữ vừa trở thành nơi Hàn Lập tạm thời khổ tu và luyện đan.","theLucLienQuan":["Linh giới tu sĩ"],"nguon":["@c0854"]},{"id":"cam-che-mau-bac-tren-dinh-khong-gian","name":"Cấm chế màu bạc trên đỉnh không gian","capDo":"khac","parentId":"tan-tich-linh-mieu-vien","blurb":"Đây là lớp ngân sa nằm sau tầng mây ở đỉnh không gian của tàn tích Linh Miểu Viên. Hàn Lập thử nghiệm và xác nhận có thể xuyên qua, nhưng vẫn không dám chạm sâu vì e ngại ngân sắc hỏa diễm ẩn trong đó.","detail":"Lớp cấm chế bạc hiện ra như ngân sa bàng bạc phủ phía sau tầng mây. Quang cầu màu xanh và bản thân Hàn Lập đều xuyên qua được mà không trực tiếp kích hoạt biến cố, nhưng việc quan sát khiến hắn liên tưởng tới loại cấm chế cực kỳ cao minh, có thể do tu sĩ Linh giới để lại và có liên quan tới việc áp chế cổ ma.","theLucLienQuan":["Linh giới tu sĩ"],"nguon":["@c0854"]},{"id":"diem-yeu-khong-gian","name":"Điểm yếu không gian","capDo":"khac","parentId":"tan-tich-linh-mieu-vien","blurb":"Đây là điểm dị thường nhỏ như hạt gạo, hiện ra như một lam sắc quang diễm mờ nhạt trong không gian. Nó là hy vọng lớn nhất để Hàn Lập có thể về sau phá vách và thoát khỏi tàn tích Linh Miểu Viên.","detail":"Theo lời Đại Diễn Thần Quân, điểm yếu nhất của không gian không cố định ở bốn bức vách mà có thể trôi nổi trong toàn bộ tàn hài. Hàn Lập dùng thần thức cùng Minh Thanh Linh Nhãn mới phát hiện ra một điểm nhỏ như hạt gạo, có linh khí ba động cực yếu, từ đó xác định phương hướng thoát thân về sau sẽ dựa vào vị trí này.","theLucLienQuan":[],"nguon":["@c0854"]},{"id":"tru-chau","name":"Trữ Châu","cn":"","capDo":"chau","parentId":"dong-du-quoc","blurb":"Một châu nhỏ thuộc Đông Dụ quốc ở Thiên Nam, nằm kề Xương Châu có Trụy Ma Cốc. Nơi này linh khí đơn bạc, nhiều đất vàng núi hoang và ít tu sĩ cư trú.","detail":"Trữ Châu trái ngược với Xương Châu rừng rậm sơn lĩnh vô biên, vì địa thế khô cằn, ít cây cối sông suối và linh khí nghèo nàn. Một số tiểu gia tộc tu tiên chiếm các linh mạch thấp kém tại đây mà không bị thế lực lớn tranh đoạt.","theLucLienQuan":["Ba gia tộc Hoàng, Lý, Vương Linh Lân sơn"],"nguon":["@c0855"]},{"id":"linh-lan-son-linh","name":"Linh Lân sơn lĩnh","cn":"","capDo":"vuc","parentId":"tru-chau","blurb":"Dãy núi ở phía tây nam Trữ Châu, có vài khối linh mạch nhỏ. Linh Lân sơn của ba gia tộc Hoàng, Lý, Vương nằm trong khu vực này.","detail":"Linh Lân sơn lĩnh không có linh khí dồi dào, nhưng vẫn có vài mạch linh khí đủ để các tiểu gia tộc tu tiên nương náu. Khu Linh Lân sơn trong đó trở thành nơi ba gia tộc cùng cư trú vì có linh tuyền vô danh.","theLucLienQuan":["Ba gia tộc Hoàng, Lý, Vương Linh Lân sơn"],"nguon":["@c0855"]},{"id":"linh-lan-son","name":"Linh Lân sơn","cn":"","capDo":"khac","parentId":"linh-lan-son-linh","blurb":"Khu núi tại phía tây nam Trữ Châu, diện tích hơn trăm dặm nhưng linh mạch chỉ hơn mười dặm. Đây là nơi ba gia tộc Hoàng, Lý, Vương cư trú và cùng giữ linh tuyền.","detail":"Linh Lân sơn gồm chủ phong và hai ngọn núi nhỏ phụ cận, vừa đủ cho tu sĩ ba nhà miễn cưỡng đả tọa tu hành. Dù linh khí không mạnh, linh tuyền vô danh trên chủ phong khiến ba gia tộc gắn bó với nơi này.","theLucLienQuan":["Gia tộc họ Hoàng Linh Lân sơn","Gia tộc họ Lý Linh Lân sơn","Gia tộc họ Vương Linh Lân sơn"],"nguon":["@c0855"]},{"id":"chu-phong-linh-lan-son","name":"Chủ phong Linh Lân sơn","cn":"","capDo":"khac","parentId":"linh-lan-son","blurb":"Ngọn chủ phong của Linh Lân sơn, nơi có linh tuyền vô danh và vách núi đen phong kín ngọc trì. Ba gia tộc cử hành nghi thức mở linh tuyền tại đây.","detail":"Trước vách núi đen cao hơn trăm trượng trên chủ phong, đệ tử trẻ ba nhà xếp hàng chờ còn các tu sĩ cao giai vận hành pháp trận. Khi thạch bích mở ra, ngọc trì linh tuyền hiện ra và trở thành nơi Hàn Lập rơi xuống từ khe hở không gian.","theLucLienQuan":["Ba gia tộc Hoàng, Lý, Vương Linh Lân sơn"],"nguon":["@c0855"]},{"id":"lac-hon-son","name":"Lạc Hồn sơn","cn":"","aliases":[],"capDo":"khac","parentId":"phong-do-quoc","blurb":"Ngọn núi ở Phong Đô quốc nơi yêu ma bị Diệt ma đội truy tung và bao vây. Trận chiến tại đây khốc liệt tới mức cả núi bị san phẳng.","detail":"Khi bị truy tới Lạc Hồn sơn, yêu ma đã gần khôi phục nguyên khí tới tu vi Hóa Thần kỳ. Hai đại tu sĩ và một Mộ Lan thần sư cùng xuất thủ đối phó, các tu sĩ khác không thể chen vào, cuối cùng Lạc Hồn sơn bị san thành bình địa.","theLucLienQuan":["Diệt ma đội","Mộ Lan nhân"],"nguon":["@c0856"]},{"id":"nhan-gioi","name":"Nhân giới","cn":"","aliases":[],"capDo":"gioi-dien","parentId":null,"blurb":"Giới diện nơi yêu ma thoát khỏi Trụy Ma cốc gây họa sau khi không rời đi như nhiều tiền bối dự đoán. Nó ở lại, đánh lén cao giai tu sĩ và thôn phệ Nguyên Anh.","detail":"Trong lời kể về yêu ma, ban đầu có người cho rằng loại yêu ma này không thể tồn tại lâu dài tại Nhân giới. Thực tế nó vẫn lưu lại, gây đại kiếp cho Thiên Nam tu tiên giới.","theLucLienQuan":[],"nguon":["@c0856","@c1056"]},{"id":"dai-tuyen-qua","name":"Đại tuyền qua","cn":"","capDo":"khac","parentId":"vo-bien-hai","blurb":"Xoáy nước lớn cổ quái xuất hiện gần bờ Vô Biên Hải phía Khê Quốc sau khi yêu ma biến mất. Nó phun lượng lớn linh khí, tinh lọc vùng biển phụ cận và khiến bảy đảo linh mạch nổi lên.","detail":"Đại tuyền qua là dị biến lớn ở Vô Biên Hải, có linh khí cuồn cuộn phun ra và áp lực cực mạnh khi xuống sâu. Nhiều tu sĩ từng muốn dò xét nguồn gốc nhưng đều bị ép lui, ngay cả Chí Dương thượng nhân cũng chỉ xuống khoảng ba ngàn trượng rồi phải quay lên.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam","Thất gia tu tiên đại phái"],"nguon":["@c0857"]},{"id":"bay-hon-dao-nho-quanh-dai-tuyen-qua","name":"Bảy hòn đảo nhỏ quanh Đại tuyền qua","cn":"","capDo":"khac","parentId":"dai-tuyen-qua","blurb":"Bảy đảo nhỏ từ đáy biển trồi lên quanh Đại tuyền qua. Mỗi đảo đều có linh khí bức người và linh mạch đỉnh cấp, dẫn tới Đoạt đảo đại hội.","detail":"Các đảo này xuất hiện cùng dị biến Đại tuyền qua, trở thành địa bàn tranh đoạt của nhiều tông môn. Sau Đoạt đảo đại hội, bảy đại phái tu tiên giành quyền sở hữu chúng.","theLucLienQuan":["Thất gia tu tiên đại phái","Tam đại tu sĩ Thiên Nam"],"nguon":["@c0857"]},{"id":"dai-tan","name":"Đại Tấn","cn":"","capDo":"quoc-gia","parentId":"nhan-gioi","blurb":"Đại Tấn được Đại Diễn Thần Quân xem là nơi có hy vọng tìm mua tài liệu quý để luyện Khôi Lỗi. Hàn Lập cũng muốn tới đây để tìm cách xử lý tà khí Huyết ma kiếm.","detail":"Trong cuộc đối thoại sau khi rời Linh Lân sơn, Đại Diễn Thần Quân thúc Hàn Lập đi Đại Tấn nếu Thiên Nam không có đủ tài liệu. Hàn Lập đồng ý vì sát khí và tà khí trên người đang cản trở tiến giai Nguyên Anh Trung Kỳ.","theLucLienQuan":[],"nguon":["@c0857","@c0969"]},{"id":"ma-gioi","name":"Ma giới","cn":"","aliases":["thượng Cổ ma giới","Cổ ma giới"],"capDo":"gioi-dien","parentId":null,"blurb":"Không gian được Đại Diễn Thần Quân nhắc là nơi ma tu nhân giới có thể phi thăng sau khi tu ma công đến cực trí.","detail":"Ma giới là không gian gắn với Cổ ma, thánh tổ và các con đường ma hóa được Đại Diễn Thần Quân giải thích cho Hàn Lập. Theo lời ông, ma tu nhân loại phi thăng tới đây rồi thành Cổ ma vẫn có thể giữ nhân hình, còn một bộ phận yêu tộc nhân giới tu luyện ma công cũng có thể phi thăng tới Cổ ma giới.","theLucLienQuan":["Cổ ma","Yêu tộc"],"nguon":["@c0858"]},{"id":"van-linh-son","name":"Vạn Lĩnh Sơn","cn":"","aliases":[],"capDo":"vuc","parentId":"xuong-chau","blurb":"Vùng núi tại Xương Châu, nơi có cửa vào Trụy Ma cốc mà Hàn Lập quay lại sau khi thoát khỏi khe hở không gian.","detail":"Hàn Lập tiến vào Xương Châu rồi tới Vạn Lĩnh Sơn để trở lại khu vực cửa vào Trụy Ma cốc. Tại đây hắn dùng bí thuật và pháp quyết để cảm ứng Thiên Tuyệt ma thi, xác nhận ma thi vẫn ở trong cốc nhưng đang bị kẹt nên không thể ra ngoài gặp mặt.","theLucLienQuan":[],"nguon":["@c0858"]},{"id":"son-mon-lac-van-tong","name":"Sơn môn Lạc Vân Tông","cn":"","aliases":[],"capDo":"khac","parentId":"van-mong-son","blurb":"Khu vực gần Lạc Vân Tông nơi Hàn Lập gặp đệ tử tuần sơn sau hai tháng trở về Vân Mộng Sơn.","detail":"Khi Hàn Lập về tới gần Vân Mộng Sơn, hắn gặp đệ tử tuần sơn ở khu vực sơn môn Lạc Vân Tông. Các đệ tử nhận ra vị tổ sư trưởng lão trở về, lập tức dùng Truyền Âm Phù báo tin, khiến toàn tông ra nghênh đón.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0858"]},{"id":"nhac-duong-cung","name":"Nhạc Dương cung","cn":"","aliases":[],"capDo":"khac","parentId":"dai-tan","blurb":"Một địa điểm tu luyện ở Đại Tấn, được Đại Diễn Thần Quân nhắc như manh mối tìm Hạo Dương Điểu.","detail":"Đại Diễn Thần Quân từng gặp một nữ tu trẻ ở Nhạc Dương cung khi du lịch Đại Tấn; nữ tu này có nuôi Hạo Dương Điểu. Vì lông Hạo Dương Điểu là tài liệu hiếm để luyện Tam Diễm Phiến, Nhạc Dương cung trở thành một manh mối quan trọng nếu Hàn Lập tới Đại Tấn tìm tài liệu.","theLucLienQuan":["Nhạc Dương cung"],"nguon":["@c0858"]},{"id":"tu-mau-phong","name":"Tử Mâu Phong","capDo":"khac","parentId":"son-mon-lac-van-tong","blurb":"Tử Mâu Phong là nơi đặt động phủ của Hàn Lập tại Lạc Vân Tông. Sau hơn hai mươi năm hắn mất tích, nơi này vẫn được giữ nguyên và Mộ Phái Linh tiếp tục ở đó tu luyện.","detail":"Sau khi rời mật thất phong băng Nam Cung Uyển, Hàn Lập trở về Tử Mâu Phong. Trình sư huynh và Lữ Lạc cho biết động phủ của hắn vẫn được giữ nguyên, còn Mộ Phái Linh vẫn ở trong Tử Mâu Phong và được hai người chiếu cố.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0859"]},{"id":"duoc-vien","name":"Dược viên","cn":"","capDo":"khac","parentId":"dong-phu-cua-han-lap","blurb":"Khu trồng linh dược trong động phủ của Hàn Lập. Chương này nơi đây còn giữ Huyền Thiên Tiên Đằng và Cửu Khúc Linh Sâm nguyên vẹn.","detail":"Sau hơn hai mươi năm Hàn Lập vắng mặt, dược viên vẫn không tổn hao. Huyền Thiên Tiên Đằng chỉ còn là tàn căn, còn Cửu Khúc Linh Sâm đã thông linh nhưng tạm chưa được dùng vì chưa có phương thuốc cổ phù hợp.","theLucLienQuan":[],"nguon":["@c0860"]},{"id":"trung-that","name":"Trùng thất","cn":"","capDo":"khac","parentId":"dong-phu-cua-han-lap","blurb":"Khu nuôi linh trùng trong động phủ của Hàn Lập. Hàn Lập dùng nơi này để bố trí Phệ Kim Trùng và Lục Dực Sương Công.","detail":"Sau khi trở về động phủ, Hàn Lập đưa Phệ Kim Trùng chờ tiến hóa vào trùng thất, rồi thả hơn hai mươi ấu trùng Lục Dực Sương Công vào trùng thất riêng để tiếp tục bồi dưỡng.","theLucLienQuan":[],"nguon":["@c0860"]},{"id":"cuc-tay","name":"Cực Tây","cn":"","capDo":"vuc","parentId":null,"blurb":"Vùng Hàn Lập từng đi qua cùng Mộ Phái Linh. Ấu trùng Lục Dực Sương Công nở không lâu trên đường đi vùng này.","detail":"Trong hồi tưởng của Hàn Lập, Lục Dực Sương Công nở trên đường đi Cực Tây. Sau đó do bị kẹt trong khe hở không gian khiến bình nhỏ không tái sinh lục dịch, đám linh trùng này vẫn chưa tiến cấp.","theLucLienQuan":[],"nguon":["@c0860","@c0969"]},{"id":"mat-that","name":"Mật thất","cn":"","capDo":"khac","parentId":"dong-phu-cua-han-lap","blurb":"Nơi Hàn Lập đi vào sau khi quyết định luyện hóa nốt Kiền Lam Băng Diễm. Nếu còn thời gian, hắn cũng sẽ dùng tài liệu mới nhận để luyện thượng cổ Nguyên Anh khôi lỗi.","detail":"Sau khi bàn với Ngân Nguyệt và Đại Diễn Thần Quân về phi kiếm, Cổ ma, Hư Thiên Đỉnh, Thất Diễm Phiến và khôi lỗi, Hàn Lập đi vào mật thất để tiếp tục tu luyện. Trọng tâm trước mắt của hắn là luyện hóa tia Kiền Lam Băng Diễm cuối cùng.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0862"]},{"id":"bach-xao-vien-dia-diem","name":"Bách Xảo Viện","cn":"","capDo":"khac","parentId":"van-mong-son","blurb":"Bách Xảo Viện là địa điểm chính của chương, nơi nhóm Hàn Lập tới dự lễ nhận chủ Càn Khôn Tháp. Bên trong có sân rộng, đài đá cao như tháp, vách núi nhiều động phủ và đại sảnh tiếp khách.","detail":"Nhóm Lạc Vân Tông được Phó lão giả dẫn qua cấm chế đại trận để vào Bách Xảo Viện. Không gian bên trong gồm khu sân rộng, đài đá cao, vách núi có nhiều động phủ và cửa động dẫn vào đại sảnh nơi các trưởng lão bàn về Càn Khôn Tháp, Kim lão quái và việc đoàn Cổ Kiếm Môn tới dự lễ.","theLucLienQuan":["Bách Xảo Viện","Lạc Vân Tông","Cổ Kiếm Môn"],"nguon":["@c0863"]},{"id":"phe-hoa-tri","name":"Phế Hỏa Trì","cn":"","capDo":"khac","parentId":"bach-xao-vien-dia-diem","blurb":"Phế Hỏa Trì nằm dưới ngọn núi của Bách Xảo Viện. Nơi này hỗ trợ luyện khí và có lợi cho tu sĩ tu luyện công pháp hỏa thuộc tính.","detail":"Trình sư huynh giải thích dưới núi Bách Xảo Viện có Phế Hỏa Trì, nhờ vậy viện đặt các luyện khí thất trên vách núi đá và cho cao giai đệ tử mở động phủ trong lòng núi để tận dụng điều kiện nơi đây.","theLucLienQuan":["Bách Xảo Viện"],"nguon":["@c0863"]},{"id":"vach-nui-dong-phu-bach-xao-vien","name":"Vách núi và động phủ Bách Xảo Viện","cn":"","capDo":"khac","parentId":"bach-xao-vien-dia-diem","blurb":"Khu vách núi và động phủ trong lòng núi là nơi đặt luyện khí thất và động phủ cao giai của Bách Xảo Viện. Nhóm Hàn Lập bay lên khoảng một ngàn trượng để tới cửa động lớn.","detail":"Nhờ Phế Hỏa Trì dưới núi, Bách Xảo Viện bố trí luyện khí thất trên vách núi đá, còn đệ tử bậc cao được mở động phủ trong lòng núi. Nhóm Hàn Lập theo các trưởng lão bay lên cửa động lớn trên cao để vào khu tiếp khách.","theLucLienQuan":["Bách Xảo Viện"],"nguon":["@c0863"]},{"id":"dai-sanh-bach-xao-vien","name":"Đại sảnh Bách Xảo Viện","cn":"","capDo":"khac","parentId":"bach-xao-vien-dia-diem","blurb":"Đại sảnh Bách Xảo Viện là nơi nhóm Lạc Vân Tông ngồi bàn chuyện Càn Khôn Tháp và Kim lão quái. Nơi này rộng khoảng trăm trượng, vách khảm tinh khối phát kim quang.","detail":"Trong đại sảnh, Phùng trưởng lão và Đinh trưởng lão tiếp Hàn Lập, Trình sư huynh và Lữ Lạc. Các cuộc trò chuyện tại đây xoay quanh Càn Khôn Tháp, cơ duyên Trụy Ma Cốc, danh vọng của Hàn Lập, khả năng Kim lão quái muốn gặp hắn và việc đoàn Cổ Kiếm Môn đã tới.","theLucLienQuan":["Bách Xảo Viện","Lạc Vân Tông","Cổ Kiếm Môn"],"nguon":["@c0863"]},{"id":"son-dong-bach-xao-vien","name":"Sơn động Bách Xảo Viện","cn":"","capDo":"khac","parentId":"bach-xao-vien-dia-diem","blurb":"Sơn động Bách Xảo Viện là nơi các tu sĩ Nguyên Anh của tam tông ngồi trò chuyện trước khi đi xem lễ. Tại đây diễn ra cuộc dò xét tu vi Hàn Lập và việc dâng Hỏa Lưu quả đãi khách.","detail":"Trong sơn động, Kim lão quái chú ý tu vi của Hàn Lập, Trình sư huynh bảo vệ thân phận trưởng lão Lạc Vân Tông của Hàn Lập, Phùng trưởng lão dâng Hỏa Lưu quả để làm dịu không khí, và Minh Hĩnh được giới thiệu cùng công pháp, pháp bảo.","theLucLienQuan":["Bách Xảo Viện","Lạc Vân Tông","Cổ Kiếm Môn"],"nguon":["@c0864"]},{"id":"dai-cao-nghi-le-bach-xao-vien","name":"Đài cao nghi lễ Bách Xảo Viện","cn":"","capDo":"khac","parentId":"bach-xao-vien-dia-diem","blurb":"Đài cao nghi lễ Bách Xảo Viện là nơi diễn ra nghi thức nhận chủ Càn Khôn Tháp. Khu vực này có đệ tử Trúc Cơ, tu sĩ Kết Đan, đỉnh đỏ và Ngọc sư đệ tế bái.","detail":"Đoàn tu sĩ được Liệt Hỏa lão quái mời đến đài cao để xem lễ. Tại đây, Phó lão giả bẩm báo Ngọc sư đệ đã tế bái hơn nửa canh giờ; sau đó đỉnh đỏ rung chuyển, phát linh quang và sóng nhiệt, báo hiệu nghi thức bước vào giai đoạn mở đỉnh.","theLucLienQuan":["Bách Xảo Viện"],"nguon":["@c0864"]},{"id":"van-son-phuong-thi","name":"Vân Sơn phường thị","cn":"","capDo":"khac","parentId":null,"blurb":"Vân Sơn phường thị là nơi được nói có người rao bán ấu trứng Hỏa Anh thú. Tin này khiến Hỏa Long Đồng Tử của Cổ Kiếm Môn rời tông nhiều tháng.","detail":"Địa danh được Minh Hĩnh nhắc khi giải thích lý do Hỏa Long sư huynh vắng mặt trong buổi xem lễ tại Bách Xảo Viện. Việc có ấu trứng Hỏa Anh thú rao bán ở đây đủ khiến một tu sĩ Cổ Kiếm Môn đi xem nhiều tháng.","theLucLienQuan":["Cổ Kiếm Môn"],"nguon":["@c0864"]},{"id":"that-linh-dao","name":"Thất Linh đảo","cn":"","capDo":"khac","parentId":"vo-bien-hai","blurb":"Cụm bảy đảo nhỏ bên cạnh vô danh đại tuyền qua ở Vô Biên Hải, nơi ba đại tu sĩ hẹn Hàn Lập tới sau ba tháng.","detail":"Thất Linh đảo là nơi Chí Dương Thượng nhân, Ngụy Vô Nhai và Hợp Hoan lão ma sẽ cùng có mặt để giải thích việc trọng đại cần mượn Ích Tà Thần Lôi của Hàn Lập. Chí Dương cho biết nửa năm sau ba người còn liên danh mời các tu sĩ Nguyên Anh Trung Kỳ ở Thiên Nam hội tụ tại đây.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam"],"nguon":["@c0866"]},{"id":"khe-quoc","name":"Khê quốc","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia nơi Lạc Vân Tông được lão giả họ Trình gọi là đệ nhất tu tiên tông môn sau biến cố Vân Mộng Sơn.","detail":"Trên đường về Lạc Vân Tông, lão giả họ Trình nói việc bổn tông trở thành đệ nhất tu tiên tông môn Khê quốc là tâm nguyện nhiều đời đại trưởng lão và nay đã thành hiện thực trong tay ông.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0867"]},{"id":"dong-suoi-lon-moi-xuat-hien","name":"Dòng suối lớn mới xuất hiện","cn":"","capDo":"khac","parentId":null,"blurb":"Dòng suối mới xuất hiện gần khu vực Thất Linh đảo, phun ra nhiều linh khí.","detail":"Dòng suối này được Hàn Lập nghi có liên quan đến lời mời của Chí Dương thượng nhân và nhu cầu mượn Ích Tà Thần Lôi. Trình sư huynh cho biết đệ tử Lạc Vân Tông trinh sát chỉ thấy nơi đây tuôn ra nhiều linh khí, gắn với linh mạch hiếm trên Thất Linh đảo, chưa phát hiện dị thường khác.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0868"]},{"id":"that-linh-hai","name":"Thất Linh Hải","cn":"","capDo":"vuc","parentId":"vo-bien-hai","blurb":"Thất Linh Hải là vùng biển thuộc Vô Biên Hải phía bắc Khê Quốc, nơi Hàn Lập đến theo lời hẹn với Chí Dương thượng nhân.","detail":"Trong chương 869, Hàn Lập bay ra Vô Biên Hải phía bắc Khê Quốc và nhận thấy vùng biển này có nước biển trong hơn, tôm cá nhỏ xuất hiện, linh khí nồng đậm hơn, đồng thời có nguồn linh khí lớn và bảy điểm linh ba động gần đó. Khu vực đang bị Hợp Hoan Tông phong tỏa.","theLucLienQuan":["Hợp Hoan Tông","Lạc Vân Tông"],"nguon":["@c0869"]},{"id":"linh-quy-dao","name":"Linh Quy đảo","cn":"","capDo":"khac","parentId":"that-linh-dao","blurb":"Linh Quy đảo là một trong bảy đảo nhỏ quanh Đại tuyền qua, hiện do Thái Chân môn chiếm cứ. Đảo có hình dáng giống linh quy và có tiểu linh mạch dài khoảng mười dặm.","detail":"Linh Quy đảo nằm gần Linh Phượng đảo trong cụm Thất Linh đảo ở Vô Biên Hải. Chí Dương Thượng nhân mở động phủ mới tại đây để tiếp Hàn Lập, trên đảo tập trung các tu sĩ tu vi cao và là địa bàn của Thái Chân môn trong lần bàn việc Đại tuyền qua.","theLucLienQuan":["Thái Chân môn"],"nguon":["@c0870"]},{"id":"linh-phuong-dao","name":"Linh Phượng đảo","cn":"","capDo":"khac","parentId":"that-linh-dao","blurb":"Linh Phượng đảo là một trong các đảo thuộc Thất Linh đảo, nằm cạnh Linh Quy đảo. Đảo này do Hợp Hoan Tông chiếm cứ trong bố cục quanh Đại tuyền qua.","detail":"Cung trang phụ nhân giới thiệu Linh Phượng đảo là địa bàn của Hợp Hoan Tông khi dẫn Hàn Lập tới Linh Quy đảo. Hai đảo cùng nằm gần khu vực Đại tuyền qua, nơi linh khí dao động cực mạnh.","theLucLienQuan":["Hợp Hoan Tông"],"nguon":["@c0870"]},{"id":"dai-tan-tu-tien-gioi","name":"Đại Tấn tu tiên giới","cn":"","capDo":"quoc-gia","parentId":"dai-tan","blurb":"Đại Tấn tu tiên giới là nơi liên quan đến tư liệu về Thượng cổ Phong ấn pháp trận. Đây cũng là nguồn gốc cổ đại của Chân Cực môn và nhánh Thái Chân môn tại Thiên Nam.","detail":"Ngụy Vô Nhai và Chí Dương Thượng nhân nói tư liệu giải quyết kiếp nạn Đại tuyền qua có liên quan Đại Tấn. Chí Dương tiết lộ Thái Chân môn thời cổ là một nhánh của Chân Cực môn, một trong ba đại đạo môn tại Đại Tấn tu tiên giới.","theLucLienQuan":["Chân Cực môn","Thái Chân môn"],"nguon":["@c0870"]},{"id":"ma-khi-chi-uyen","name":"Ma Khí Chi Uyên","cn":"","capDo":"khac","parentId":"dai-tuyen-qua","blurb":"Vực ma khí đen đặc nằm dưới quang mạc trấn áp ở đáy lốc xoáy linh khí. Nơi này sâu rộng khó biết, ma khí dày nặng đến mức Chí Dương thượng nhân từng vào khoảng trăm trượng đã phải lui.","detail":"Ma Khí Chi Uyên là vùng ma khí thâm uyên phía dưới quang mạc trắng sữa. Hàn Lập dùng Ích Tà Thần Lôi thăm dò gần hai trăm trượng, thấy ma khí liên tục xông tới và bị kim sắc điện hồ đánh tan, nhưng mức tiêu hao thần lôi khiến việc xâm nhập sâu hơn trở thành rủi ro lớn.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam"],"nguon":["@c0872"]},{"id":"loc-xoay-linh-khi","name":"Lốc xoáy linh khí","cn":"","capDo":"khac","parentId":"dai-tuyen-qua","blurb":"Khu vực trắng mênh mông có linh khí đè nặng, sâu hơn vạn trượng và chứa các lốc xoáy ẩn. Thần thức tại đây bị phản ngược, buộc Hàn Lập và Chí Dương thượng nhân phải chậm rãi hạ xuống.","detail":"Trong lốc xoáy linh khí, Hàn Lập dùng Lam Quang Thuẫn, phi kiếm và Minh Thanh Linh Nhãn để hộ thân, còn Chí Dương thượng nhân dùng phi kiếm trắng phá linh khí. Khu vực này dẫn xuống quang mạc trấn ma và Ma Khí Chi Uyên bên dưới.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam"],"nguon":["@c0872"]},{"id":"quang-mac-trang-sua-tran-ma","name":"Quang mạc trắng sữa trấn ma","cn":"","capDo":"khac","parentId":"dai-tuyen-qua","blurb":"Tầng màn sáng dày ở đáy lốc xoáy linh khí, ngăn ma khí đen đặc phía dưới tràn lên. Nó không cản kiếm khí hay người tiến vào, cho thấy công năng chủ yếu là trấn áp ma khí.","detail":"Hàn Lập kiểm tra quang mạc trắng sữa và phát hiện cấm chế có thể ngăn ma khí nhưng không ngăn kiếm khí. Sau lớp quang mạc này là Ma Khí Chi Uyên, nơi ma khí dày đặc nhúc nhích như vật sống.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam"],"nguon":["@c0872"]},{"id":"khue-quoc","name":"Khuê Quốc","cn":"","capDo":"quoc-gia","parentId":"thien-nam","blurb":"Khu vực được Chí Dương thượng nhân nhắc tới khi đánh giá Hàn Lập không có dã tâm tranh bá. Chính Đạo Minh có nội tuyến tại đây theo dõi tình hình liên quan đến Hàn Lập.","detail":"Theo Chí Dương thượng nhân, với thần thông hiện tại Hàn Lập đủ khả năng khống chế Khuê Quốc nếu muốn, nhưng tin tức nội tuyến cho thấy hắn không có dấu hiệu theo đuổi việc này. Khuê Quốc vì thế trở thành căn cứ lập luận rằng Hàn Lập là khổ tu không ham quyền thế.","theLucLienQuan":["Chính Đạo Minh","Lạc Vân Tông"],"nguon":["@c0872"]},{"id":"quy-linh-dao","name":"Quy Linh Đảo","cn":"","capDo":"khac","parentId":"that-linh-hai","blurb":"Quy Linh Đảo là nơi nhóm Hàn Lập trở về sau cuộc bàn bạc về phong ấn. Tại đây Hàn Lập nghỉ qua đêm rồi đến đại sảnh nhận ngọc giản vị trí đặt trận bàn.","detail":"Sau khi thống nhất theo lời Hợp Hoan lão ma, nhóm Hàn Lập trở về Quy Linh Đảo. Hàn Lập xin một gian mật thất nghỉ qua đêm, sáng hôm sau nhận truyền âm của Chí Dương thượng nhân và đến đại sảnh bàn việc bố trí trận bàn.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam","Lạc Vân Tông"],"nguon":["@c0873"]},{"id":"dong-phu-cua-chi-duong-thuong-nhan","name":"Động phủ của Chí Dương thượng nhân","cn":"","capDo":"khac","parentId":"quy-linh-dao","blurb":"Động phủ của Chí Dương thượng nhân là nơi Hàn Lập và ba đại tu sĩ bàn điều kiện xuống ma khí. Tại đây Hàn Lập nhận trận bàn cùng các bảo vật hộ thân.","detail":"Trong động phủ, Hàn Lập xem ngọc giản vị trí trận bàn, tranh luận về mức nguy hiểm của ma khí sâu và yêu cầu mượn chí bảo tru ma ích tà. Sau đó ba đại tu sĩ giao trận bàn bạch ngọc cùng bốn món bảo vật trước khi cùng rời đi.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam"],"nguon":["@c0873"]},{"id":"dai-du-son","name":"Đại du sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Đại du sơn là hướng Hàn Lập và ba đại tu sĩ bay tới sau khi nhận trận bàn và chí bảo trừ ma. Địa điểm này nằm trên lộ trình tới vùng xoáy nước nơi phong ấn cần sửa chữa.","detail":"Sau khi hoàn tất việc giao bảo vật tại động phủ của Chí Dương thượng nhân, Hàn Lập cùng ba đại tu sĩ bay về hướng Đại du sơn để tiếp tục nhiệm vụ liên quan phong ấn ma khí.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam"],"nguon":["@c0873"]},{"id":"day-xoay-nuoc","name":"Đáy xoáy nước","cn":"","capDo":"khac","parentId":"dai-tuyen-qua","blurb":"Đáy xoáy nước là nơi Hàn Lập một mình xuất hiện sau vài canh giờ để chuẩn bị xuống ma khí. Tại đây có quang mạc và tầng ma khí bên dưới cần xâm nhập để bố trí trận bàn.","detail":"Sau khi rời động phủ của Chí Dương thượng nhân, Hàn Lập thuận lợi tới đáy xoáy nước. Hắn dùng Ích Tà Thần Lôi tạo điện võng ngoài màn hào quang, chuẩn bị tiến vào ma khí sâu để đặt trận bàn sửa phong ấn.","theLucLienQuan":["Lạc Vân Tông","Tam đại tu sĩ Thiên Nam"],"nguon":["@c0873"]},{"id":"tham-uyen-ma-khi","name":"Thâm Uyên ma khí","cn":"","capDo":"khac","parentId":"dai-tuyen-qua","blurb":"Vùng thâm uyên tối đen dưới mặt biển, tràn đầy ma khí và càng xuống sâu càng hao pháp lực. Hàn Lập đi xuống khoảng ba nghìn trượng để tìm trận nhãn.","detail":"Thâm Uyên ma khí là khu vực dưới mặt biển nơi Hàn Lập nhảy xuống dưới sự che chở của kim cô và Ích Tà Thần Lôi. Độ sâu và ma khí dày đặc khiến việc qua lại tiêu hao pháp lực lớn, đồng thời che phủ vị trí tế đàn thượng cổ và trận nhãn bên dưới.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam"],"nguon":["@c0874"]},{"id":"te-dan-co-duoi-day-tham-uyen","name":"Tế đàn cổ dưới đáy thâm uyên","cn":"","capDo":"khac","parentId":"tham-uyen-ma-khi","blurb":"Đài hình vuông rộng lớn nằm dưới đáy thâm uyên ma khí. Nơi này có hoa văn cổ xưa, trung tâm đặt bia đá vỡ và là vị trí trận nhãn.","detail":"Ban đầu Hàn Lập tưởng mặt bằng bên dưới là cự thạch, nhưng sau khi dùng kim mãng quét sạch ma khí, hắn nhận ra đó là một tế đàn hoặc đài vuông rất cổ. Các đồ án trên thạch bích và dấu vết thượng cổ cho thấy nơi đây nhiều khả năng do tu sĩ thượng cổ tạo ra.","theLucLienQuan":[],"nguon":["@c0874"]},{"id":"trung-tam-te-dan","name":"Trung tâm tế đàn","cn":"","capDo":"khac","parentId":"te-dan-co-duoi-day-tham-uyen","blurb":"Vị trí đặt bia đá vỡ ở giữa tế đàn cổ. Hàn Lập đào hố cạnh gốc bia để chôn trận bàn và khôi phục trận nhãn.","detail":"Trung tâm tế đàn có bia đá bị chấn thành nhiều đoạn, vẫn phát bạch quang và còn ký hiệu sót lại. Hàn Lập xác định đây là chỗ trọng yếu của trận nhãn, đặt trận bàn tinh xảo xuống cạnh bia đá và thấy cột sáng trắng sữa phát lên bình thường.","theLucLienQuan":[],"nguon":["@c0874"]},{"id":"khu-vuc-ma-khi-duoi-dai-vung-xoay","name":"Khu vực ma khí dưới đài/vũng xoáy","cn":"","capDo":"khac","parentId":"dai-tuyen-qua","blurb":"Khu vực ngập ma khí dưới đài và vũng xoáy, nơi Hàn Lập cùng Ngân Nguyệt tìm Ma Tủy Toản. Hàn Lập cũng dùng ma khí tinh thuần tại đây để tu bổ Âm La phiến.","detail":"Đây là nơi Hàn Lập xuống dưới để bố trí trận bàn, tìm Ma Tủy Toản và thử tu bổ Âm La phiến bằng ma khí tinh thuần. Sau khi hoàn tất, hắn phá linh khí phía trên để bay ra khỏi vũng xoáy.","theLucLienQuan":["Tam đại tu sĩ Thiên Nam"],"nguon":["@c0875"]},{"id":"bai-da-duoi-ma-khi","name":"Bãi đá","cn":"","capDo":"khac","parentId":"khu-vuc-ma-khi-duoi-dai-vung-xoay","blurb":"Bãi đá nằm trong khu vực ma khí, nơi Ngân Nguyệt chui vào tìm kiếm. Nàng từ đây trở ra và mang về ba khối Ma Tủy Toản.","detail":"Ngân Nguyệt trong hình dạng tiểu hồ trắng được Ích Tà Thần Lôi bảo hộ rồi chui vào bãi đá tìm Ma Tủy Toản. Sau một thời gian, nàng bắn ra khỏi bãi đá và phun ra ba khối màu đen trong suốt.","theLucLienQuan":[],"nguon":["@c0875"]},{"id":"mat-that-cua-han-lap","name":"Mật thất của Hàn Lập","cn":"","capDo":"khac","parentId":"son-mon-lac-van-tong","blurb":"Nơi Hàn Lập vào bế quan sau khi trở về Lạc Vân Tông. Mục tiêu của lần bế quan là tăng pháp lực và hoàn toàn tu thành đệ nhị Nguyên Anh.","detail":"Sau khi báo chuyện bản vẽ linh đảo và xem xét tình huống Nam Cung Uyển, Hàn Lập vào mật thất bắt đầu bế quan nhiều năm. Chương đặt nơi này làm điểm khởi đầu cho giai đoạn tu luyện đệ nhị Nguyên Anh của hắn.","theLucLienQuan":["Lạc Vân Tông"],"nguon":["@c0875"]},{"id":"phia-nam-thien-lan-thao-nguyen","name":"Phía nam Thiên Lan thảo nguyên","cn":"","capDo":"vuc","parentId":"thien-lan-thao-nguyen","blurb":"Phía nam Thiên Lan thảo nguyên là khu vực đội xe Thương Lộ Bộ đang đi qua khi chương mở đầu. Đây là một phần đại thảo nguyên dưới quyền người Đột Ngột sau cuộc chiến với Mộ Lan.","detail":"Đội xe hơn ba mươi người của Anh Lộ chậm rãi di chuyển qua vùng phía nam Thiên Lan thảo nguyên trên đường tới thánh điện. Khu vực này gắn với bối cảnh người Đột Ngột từng chỉ chiếm nửa nam thảo nguyên trước khi mở rộng ra toàn bộ đại thảo nguyên.","theLucLienQuan":["Người Đột Ngột","Thương Lộ Bộ"],"nguon":["@c0877"]},{"id":"thien-lan-thanh-dien-gan-nhat","name":"Thiên Lan thánh điện gần nhất","cn":"","capDo":"khac","parentId":"thien-lan-thao-nguyen","blurb":"Thiên Lan thánh điện gần nhất là điểm đến của đội xe Thương Lộ Bộ trong kỳ khai linh nhật. Từ bộ lạc của Anh Lộ đến nơi này phải đi khoảng ba tháng, nên đội đã xuất phát từ bốn tháng trước.","detail":"Đây là thánh điện mà Thương Lộ Bộ dự định tới để dâng cống phẩm và đưa người có linh căn khai linh. Đối với một bộ lạc nhỏ không có tiên sư riêng, hành trình đến thánh điện vừa quan trọng vừa nguy hiểm.","theLucLienQuan":["Thiên Lan thánh điện","Thương Lộ Bộ","Người Đột Ngột"],"nguon":["@c0877"]},{"id":"thanh-dien","name":"Thánh điện","cn":"","capDo":"khac","parentId":"thien-lan-thao-nguyen","blurb":"Nơi đội xe Thương Lộ bộ đang hướng đến để triều cống và cũng là mục tiêu Hàn Lập muốn tới. Tại đây có khai linh nhật hai mươi năm một lần, khiến Anh Lộ đoán Hàn Lập sẽ không bỏ qua.","detail":"Thánh điện là điểm đến chung của Hàn Lập và Thương Lộ bộ trong chương này. Anh Lộ cho biết bộ lạc đang trên đường tới đó triều cống, đồng thời nhắc khai linh nhật hai mươi năm một lần, nên ông dùng việc cùng đường làm cơ sở mời Hàn Lập hộ tống đội xe.","theLucLienQuan":["Thương Lộ bộ","Thiên Lan thánh điện"],"nguon":["@c0878"]},{"id":"noi-nghi-chan-tam-cua-thien-lan-thanh-dien","name":"Nơi nghỉ chân tạm của Thiên Lan thánh điện","cn":"","capDo":"khac","parentId":"thien-lan-thao-nguyen","blurb":"Trạm dừng tạm do Thiên Lan thánh điện dùng pháp lực dựng nhanh cho các bộ lạc đường xa tụ tập trước Khai linh nhật.","detail":"Đây là nơi nghỉ chân an toàn mà đoàn Thương Lộ bộ đang tiến tới sau nhiều ngày đi đường bình an. Nơi này được Thiên Lan thánh điện dựng tạm cho các bộ lạc đường xa trước Khai linh nhật và sẽ bị dỡ bỏ sau khi sự kiện kết thúc.","theLucLienQuan":["Thiên Lan thánh điện","Thương Lộ bộ tộc","Đột Ngột nhân"],"nguon":["@c0879"]},{"id":"hap-coc","name":"Hạp cốc","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực hạp cốc mà đoàn xe Thương Lộ bộ đi qua trên đường tới nơi nghỉ chân.","detail":"Đoàn xe Thương Lộ bộ đi qua hạp cốc và tìm được một bầy dê hoang, giúp hành trình bớt thiếu thốn trong thời gian Hàn Lập ẩn trong xe.","theLucLienQuan":["Thương Lộ Bộ"],"nguon":["@c0880"]},{"id":"mat-that-kin","name":"Mật thất kín","cn":"","capDo":"khac","parentId":null,"blurb":"Mật thất nơi bốn lão giả Thiên Lan lập pháp trận cứu chữa Nguyên Anh Quế tiên sư.","detail":"Trong mật thất kín, bốn lão giả tóc bạc dùng pháp kỳ xanh biếc, pháp trận lâm thời và trận bàn bát tròn màu ngọc xanh để giúp Nguyên Anh Quế tiên sư hồi phục. Đây cũng là nơi họ bàn về thực lực Hàn Lập và chứng kiến Quế tiên sư bị phản chấn khi Phệ Kim Trùng trưởng thành bị diệt nguyên thần.","theLucLienQuan":["Thiên Lan","Người Đột Ngột"],"nguon":["@c0881"]},{"id":"xe-ngua-tai-dia-phuong-xa-la","name":"Xe ngựa tại địa phương xa lạ","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Hàn Lập ngồi làm phép suốt nửa tháng để xử lý Phệ Kim Trùng trưởng thành.","detail":"Trên xe ngựa tại một địa phương xa lạ, Hàn Lập ngày đêm làm phép trong nửa tháng, rút nguyên thần Phệ Kim Trùng trưởng thành vào Âm La phiên rồi thử luyện xác trùng thành yêu thi. Người bên ngoài xe ngựa không quấy nhiễu hắn trong quá trình này.","theLucLienQuan":["Thương Lộ Bộ"],"nguon":["@c0881"]},{"id":"tram-dung-chan-do-thanh-dien-chi-dinh","name":"Trạm dừng chân do thánh điện chỉ định","cn":"","capDo":"khac","parentId":"dai-thao-nguyen","blurb":"Trạm dừng chân do thánh điện chỉ định là điểm nghỉ dành cho các đoàn tiến cống trên đại thảo nguyên. Đoàn của Anh Lộ dự tính còn khoảng hai ngày đường là tới nơi và có thể nghỉ ngơi hồi phục hai ngày.","detail":"Anh Lộ cho biết đoàn xe sắp tới trạm dừng chân do thánh điện chỉ định. Đây là điểm nghỉ trước khi các đoàn phải đi tiếp qua địa bàn của một đại bộ lạc, nên ông dự tính có thể dùng nơi này để nghỉ ngơi và tìm thêm tiểu bộ lạc cùng liên hợp.","theLucLienQuan":["Thiên Lan thánh điện","Thương Lộ bộ lạc","Tố Hồng Lang bộ lạc"],"nguon":["@c0882"]},{"id":"dai-thao-nguyen","name":"Đại thảo nguyên","cn":"","capDo":"vuc","parentId":null,"blurb":"Đại thảo nguyên là khu vực các đoàn tiến cống đang di chuyển và là nơi Viên Thứu xuất hiện. Chương này nêu Viên Thứu là nhị cấp yêu cầm trên đại thảo nguyên nhưng hiếm khi hiện thân.","detail":"Trên tuyến đường qua đại thảo nguyên, đoàn xe Thương Lộ và Tố Hồng Lang gặp ba con Viên Thứu. Khu vực này có trạm dừng chân do thánh điện chỉ định và đoạn đường về sau phải đi qua địa bàn của một đại bộ lạc.","theLucLienQuan":["Thiên Lan thánh điện","Thương Lộ bộ lạc","Tố Hồng Lang bộ lạc"],"nguon":["@c0882"]},{"id":"tru-dia-cua-thanh-dien","name":"Trú địa của thánh điện","cn":"","capDo":"khac","parentId":"thien-lan-thao-nguyen","blurb":"Nơi tập kết do Thiên Lan thánh điện chỉ định trên thảo nguyên.","detail":"Trú địa có tường đá-gỗ, nhiều lều và nhà gỗ, thạch điện, thạch trụ pháp trận bảo vệ, cấm chế cấm không và khu nghỉ dành cho tiên sư. Các bộ lạc nhỏ phải trú ở khu xa thánh điện hơn.","theLucLienQuan":["Thiên Lan thánh điện","Bộ lạc của Anh Lộ"],"nguon":["@c0884"]},{"id":"thach-dien-hai-tang-trong-tru-dia","name":"Thạch điện hai tầng trong trú địa","cn":"","capDo":"khac","parentId":"tru-dia-cua-thanh-dien","blurb":"Kiến trúc cao nhất trong trú địa, nơi thường có tu tiên giả ra vào.","detail":"Anh Lộ nói thạch điện là nơi nghỉ miễn phí dành cho tiên sư. Hàn Lập đi đến cửa nhưng cân nhắc nguy cơ gặp tu sĩ Đột Ngột cao cấp nên không vào.","theLucLienQuan":["Thiên Lan thánh điện"],"nguon":["@c0884"]},{"id":"bai-loan-thach-cach-tru-dia-nam-sau-muoi-dam","name":"Bãi loạn thạch cách trú địa năm sáu mươi dặm","cn":"","capDo":"khac","parentId":"thien-lan-thao-nguyen","blurb":"Khu bãi đá nơi Hàn Lập dừng lại sau khi rời trú địa.","detail":"Hàn Lập chọn một cự thạch tại bãi loạn thạch, khoét thành không gian trú thân rồi bố trí trận pháp ẩn hình quanh đó để tạm thời ẩn náu và nghiên cứu khẩu quyết.","theLucLienQuan":["Hàn Lập"],"nguon":["@c0884"]},{"id":"manh-thao-nguyen-nho-voi-vai-dam-rung","name":"Mảnh thảo nguyên nhỏ với vài đám rừng","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực thảo nguyên có vài đám rừng nhỏ, nơi Phong Nhạc bị lão giả mắt ưng truy sát. Hàn Lập độn tới đây và can thiệp vào cuộc truy sát.","detail":"Tại một bãi đất trống trong rừng nhỏ giữa mảnh thảo nguyên, Phong Nhạc bị hắc sắc huyết ô bao quanh và dựa vào thất sắc quang tráo chống lại hồng sắc phi kiếm của lão giả mắt ưng. Hàn Lập tới nơi, dùng Nguyên anh thứ hai diệt lão giả rồi kiểm tra tình trạng trúng độc của Phong Nhạc.","theLucLienQuan":[],"nguon":["@c0885"]},{"id":"quan-tru-phu","name":"Quan Trữ phủ","cn":"","capDo":"khac","parentId":"lieu-chau","blurb":"Quan Trữ phủ là địa bàn ở Liêu châu, nơi có bốn tu tiên thế gia gồm Khổng gia, Trương gia, Kim gia và Phùng gia.","detail":"Phong Nhạc nói Phùng gia là tiểu thế lực tu tiên ở Quan Trữ phủ thuộc Liêu châu. Cục diện địa phương gồm tứ đại tu tiên thế gia, nhưng Phùng gia đã suy bại sau khi ba nhà còn lại âm thầm xuống tay.","theLucLienQuan":["Phùng gia","Khổng gia","Trương gia","Kim gia"],"nguon":["@c0887"]},{"id":"lieu-chau","name":"Liêu châu","cn":"","capDo":"chau","parentId":"dai-tan","blurb":"Liêu châu là châu của Đại Tấn, nơi Quan Trữ phủ và Phùng gia tọa lạc. Thiên Quang tự cũng từng ở đây trước khi rời về bổn tông.","detail":"Trong lời Phong Nhạc, Phùng gia ở Quan Trữ phủ thuộc Liêu châu. Thiên Quang tự từng liên quan tới vùng này, sau mấy trăm năm đã rời Liêu châu về bổn tông Kim La môn.","theLucLienQuan":["Phùng gia","Thiên Quang tự"],"nguon":["@c0887","@c0897","@c0899"]},{"id":"mat-quat-phung-gia","name":"Mật quật Phùng gia","cn":"","capDo":"khac","parentId":"quan-tru-phu","blurb":"Mật quật Phùng gia là mật địa gia tộc cần chìa khóa bạc để mở. Phong Nhạc nói trong đó cất giữ pháp khí duy nhất hơn ngàn năm và Phật tông công pháp của Phùng gia.","detail":"Phong Nhạc đem chìa khóa mở mật quật làm vật thế nợ đổi Hạo nguyên đan với Hàn Lập. Mật quật được nói chứa vật có giá trị vượt xa mấy vạn linh thạch, gồm pháp khí duy nhất truyền hơn ngàn năm và Phật tông công pháp mà Hàn Lập đang quan tâm.","theLucLienQuan":["Phùng gia"],"nguon":["@c0887"]},{"id":"noi-nghi-chan-tren-thao-nguyen","name":"Nơi nghỉ chân trên thảo nguyên","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi nghỉ chân trên thảo nguyên là điểm tập kết lều vải, đội xe bộ lạc nhỏ và tu tiên giả hộ tống. Tại đây, Ưng tiền bối cùng hai tu sĩ Đột Ngột quan sát đoàn xe và dùng thần thức dò xét.","detail":"Sau khi Hàn Lập trở lại, các đội xe từ nhiều bộ lạc liên hợp để lên đường. Cùng lúc, nhóm tu sĩ Đột Ngột tại lầu đá dùng nơi này làm điểm kiểm tra, tìm dấu vết ngoại nhân giữa các đoàn xe.","theLucLienQuan":["Người Đột Ngột","Bộ lạc Thương Lộ"],"nguon":["@c0888"]},{"id":"thien-thuy-ha","name":"Thiên Thuỷ Hà","cn":"","aliases":[],"capDo":"khac","parentId":"thien-lam-thao-nguyen","blurb":"Thiên Thuỷ Hà là con sông lớn nhất ở Thiên Lam Thảo Nguyên theo ký ức của Hàn Lập. Nhánh nhỏ nơi đoàn xe dừng lại nối tới dòng chính cách hơn một trăm dặm.","detail":"Khi hỏi Anh San về con sông trước mắt, Hàn Lập biết đó là một nhánh nhỏ của Thiên Thuỷ Hà. Hắn nhớ Thiên Thuỷ Hà là sông lớn ở Thiên Lam Thảo Nguyên và còn liên hệ nó với Thuấn Giang ở Đại Tấn theo quan hệ thượng lưu, hạ lưu.","theLucLienQuan":["Đột Ngột"],"nguon":["@c0889"]},{"id":"nhanh-nho-cua-thien-thuy-ha","name":"Nhánh nhỏ của Thiên Thuỷ Hà","cn":"","aliases":[],"capDo":"khac","parentId":"thien-thuy-ha","blurb":"Nhánh nhỏ của Thiên Thuỷ Hà là nơi đoàn xe dừng nghỉ, lấy nước và nấu cơm. Đây cũng là chỗ Hàn Lập phát hiện dị vật bay tới từ phía bên kia sông.","detail":"Đoàn xe dừng lại bên nhánh sông này để bổ sung nước uống và nghỉ ngơi. Hàn Lập rời xe lần đầu trong nhiều ngày, nói chuyện với Anh San, hỏi về Thiên Thuỷ Hà và phát hiện một vật lạ bay tới từ phía bên kia sông.","theLucLienQuan":["Đột Ngột","Bộ lạc Hoả Lang"],"nguon":["@c0889"]},{"id":"thien-lam-thao-nguyen","name":"Thiên Lam Thảo Nguyên","cn":"","aliases":[],"capDo":"vuc","parentId":null,"blurb":"Thiên Lam Thảo Nguyên là vùng thảo nguyên nơi Thiên Thuỷ Hà chảy qua. Hàn Lập nhớ đây là nơi có con sông lớn nhất mà Anh San nhắc tới.","detail":"Qua lời Anh San và ký ức của Hàn Lập, Thiên Thuỷ Hà nằm trong Thiên Lam Thảo Nguyên. Chương này đoàn xe đang di chuyển trong khu vực này và dừng bên một nhánh nhỏ của con sông.","theLucLienQuan":["Đột Ngột"],"nguon":["@c0889","@c1050"]},{"id":"thuan-giang","name":"Thuấn Giang","cn":"","aliases":[],"capDo":"khac","parentId":"dai-tan","blurb":"Thuấn Giang là con sông ở Đại Tấn mà Hàn Lập liên hệ với Thiên Thuỷ Hà. Hai con sông được nhắc có quan hệ thượng lưu và hạ lưu.","detail":"Khi nghe tên Thiên Thuỷ Hà, Hàn Lập nhớ tới Thuấn Giang tại Đại Tấn và nhận ra giữa hai dòng sông có quan hệ thượng lưu, hạ lưu. Ý nghĩ này khiến hắn mơ hồ nảy ra một suy tính về đường thủy.","theLucLienQuan":[],"nguon":["@c0889"]},{"id":"bac-han-son","name":"Bắc Hàn sơn","cn":"","aliases":[],"capDo":"khac","parentId":null,"blurb":"Địa danh được Cố thống lĩnh nhắc tới khi nói về nhiệm vụ Giang Kiếm Anh mang Tuyết Tinh châu đi mời Bắc Huyền lão nhân.","detail":"Bắc Hàn sơn là nơi gắn với Bắc Huyền lão nhân trong lời Cố thống lĩnh. Cửu Tiên cung nói Giang Kiếm Anh được giao mang Tuyết Tinh châu tới đây để mời người, nhưng Giang Kiếm Anh phản bác rằng phía sau nhiệm vụ là âm mưu huyết tế.","theLucLienQuan":["Cửu Tiên cung"],"nguon":["@c0890"]},{"id":"vung-giap-gioi-dai-tan-va-thao-nguyen","name":"Vùng giáp giới Đại Tấn và thảo nguyên","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực tiếp giáp giữa Đại Tấn và Thiên Lan thảo nguyên.","detail":"Thiên Lan thánh điện phái nhiều tu sĩ tới vùng này dò xét để đề phòng người Âm La tông đến tiếp ứng Hàn Lập.","theLucLienQuan":["Thiên Lan thánh điện","Âm La tông"],"nguon":["@c0892"]},{"id":"cam-dia-trong-thien-lan-thanh-dien","name":"Cấm địa trong Thiên Lan thánh điện","cn":"","capDo":"khac","parentId":"thien-lan-thanh-dien","blurb":"Khu vực phòng ngự nghiêm mật bên trong Thiên Lan thánh điện.","detail":"Sau nghi thức khai linh, hơn trăm cao giai tiên sư Đột Ngột nhân tập hợp tại cấm địa này để tiến hành nghi thức triệu hoán phân thân thánh thú.","theLucLienQuan":["Thiên Lan thánh điện","Đột Ngột nhân"],"nguon":["@c0892"]},{"id":"quang-truong-cu-hinh-tran-do","name":"Quảng trường cự hình trận đồ","cn":"","capDo":"khac","parentId":"cam-dia-trong-thien-lan-thanh-dien","blurb":"Quảng trường rộng gần ngàn trượng trong cấm địa thánh điện.","detail":"Giữa quảng trường có cự hình trận đồ, trận nhãn đặt tế đàn màu xám trắng, là nơi diễn ra nghi thức triệu hoán phân thân thánh thú.","theLucLienQuan":["Thiên Lan thánh điện"],"nguon":["@c0892"]},{"id":"duong-song-hep-cach-do-bon-nam-tram-dam","name":"Đường sông hẹp cách đó bốn năm trăm dặm","cn":"","capDo":"khac","parentId":"thien-thuy-ha","blurb":"Đoạn đường sông nơi Hàn Lập lao ra khỏi nước và bắt đầu dùng Huyết ảnh độn bỏ chạy.","detail":"Từ đoạn đường sông hẹp cách vị trí truy tung bốn năm trăm dặm, Hàn Lập hóa thành huyết ảnh vọt khỏi mặt nước khi nhận ra nguy cơ bị truy bắt.","theLucLienQuan":["Thiên Lan thánh điện"],"nguon":["@c0893"]},{"id":"thao-nguyen","name":"Thảo nguyên","cn":"","capDo":"vuc","parentId":null,"blurb":"Thảo nguyên là địa bàn hoạt động của Đột Ngột tộc trong chương này. Đây là nơi Hàn Lập giao chiến với Thiên Lan thánh nữ và nơi Cổ Ma bị truy kích trước khi chạy về hướng Đại Tấn.","detail":"Sau biến cố ở thảo nguyên, Hàn Lập thoát khỏi Thiên Lan thánh nữ, Cổ Ma cũng được nói là chạy ngang qua thảo nguyên đến Đại Tấn. Ba đại nhân vật Đột Ngột hội hợp và bàn việc truy tìm Hàn Lập sang Đại Tấn.","theLucLienQuan":["Đột Ngột"],"nguon":["@c0897"]},{"id":"tren-thuyen-tao-gia","name":"Trên thuyền Tào gia","cn":"","capDo":"khac","parentId":"thuan-giang","blurb":"Thuyền Tào gia là không gian chính của chương, nơi Hàn Lập tỉnh lại sau khi được cứu khỏi khối băng trên Thuấn Giang. Tại đây hắn gặp Hà Văn, được Tào Mộng Dung mời ở lại và bố trí cấm chế trong phòng để tĩnh tọa.","detail":"Con thuyền chở gia quyến huyện úy họ Tào đi sau khi chủ nhà đã vội đi nhậm chức trước. Trên thuyền có Tào Mộng Dung, Hà Văn, Chu sư gia, Vương quản gia, tiêu sư, tôi tớ và nhiều dấu hiệu cho thấy đoàn người không chỉ là gia quyến phàm tục bình thường.","theLucLienQuan":["Tào gia của huyện úy họ Tào"],"nguon":["@c0899"]},{"id":"lieu-chau-ngu-nguyen-phu","name":"Liêu Châu Ngũ Nguyên phủ","cn":"","capDo":"khac","parentId":"lieu-chau","blurb":"Ngũ Nguyên phủ thuộc Liêu Châu là khu vực mở đầu chương. Bên dưới phủ có một tòa thành nhỏ an bình, phía tây là ngọn núi nhỏ nơi các bên hẹn gặp.","detail":"Khu vực Ngũ Nguyên phủ được nhắc trong bối cảnh Tào Mộng Dung cùng hai nữ tu Huyền Ngọc phái và người Tê Linh Tông tụ họp. Địa điểm cụ thể của cuộc gặp là ngọn núi nhỏ ở phía tây phủ.","theLucLienQuan":["Huyền Ngọc phái","Tê Linh Tông","Quan phủ Ngũ Nguyên phủ"],"nguon":["@c0900"]},{"id":"ngon-nui-nho-phia-tay-ngu-nguyen-phu","name":"Ngọn núi nhỏ phía tây Ngũ Nguyên phủ","cn":"","capDo":"khac","parentId":"lieu-chau-ngu-nguyen-phu","blurb":"Ngọn núi nhỏ phía tây Ngũ Nguyên phủ là nơi Tào Mộng Dung hẹn hai sư tỷ và phía Tê Linh Tông. Trên đỉnh có nhà tranh và thạch đình đơn sơ.","detail":"Tào Mộng Dung cùng Hàn Lập ngồi trong thạch đình trên đỉnh núi trước khi Lỗ sư tỷ và nữ tử trẻ tuổi Huyền Ngọc phái tới. Sau đó Ngô Hiểu Vũ và Mã Ngọc Lâm bay lên bằng phi hành pháp khí, biến nơi này thành điểm mở màn cuộc luận bàn.","theLucLienQuan":["Huyền Ngọc phái","Tê Linh Tông"],"nguon":["@c0900"]},{"id":"giang-lang-phu","name":"Giang Lăng phủ","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm Hàn Lập định tới để mở Phùng gia mật quật.","detail":"Sau khi xác định cần công pháp Phật môn giải trừ sát khí, Hàn Lập quyết định đến Giang Lăng phủ, nơi gắn với Phùng gia mật quật mà hắn có thể mở bằng chìa khóa đã có.","theLucLienQuan":["Phùng gia"],"nguon":["@c0901"]},{"id":"tru-phu","name":"Trữ phủ","cn":"","capDo":"khac","parentId":"lieu-chau","blurb":"Địa giới Hàn Lập tới sau hơn mười ngày phi hành từ vùng trước đó.","detail":"Trữ phủ thuộc Liêu châu, không xa Ngũ Nguyên phủ phía tây; Hàn Lập đi vào địa giới này rồi tìm đến một trấn nhỏ tên Chuẩn Vân trấn.","theLucLienQuan":[],"nguon":["@c0901"]},{"id":"chuan-van-tran","name":"Chuẩn Vân trấn","cn":"","capDo":"thanh","parentId":"tru-phu","blurb":"Trấn nhỏ hoang sơ thuộc sở hữu ba nhà Khổng, Triệu, Đổng từ năm sáu năm trước.","detail":"Chuẩn Vân trấn có đường xá ít, nhà cửa phần nhiều bằng bùn vàng và gỗ, cư dân lại không quá kinh ngạc khi thấy người tu tiên vì nơi này đã thuộc sở hữu Giang Trữ tam đại gia nhiều năm.","theLucLienQuan":["Giang Trữ tam đại gia","Khổng gia","Triệu gia","Đổng gia"],"nguon":["@c0901"]},{"id":"tuyet-lang-son","name":"Tuyết Lăng sơn","cn":"","aliases":["Tuyết Lĩnh sơn","Tuyết Lăng sơn mạch"],"capDo":"khac","parentId":"tru-phu","blurb":"Nơi diễn ra Đại hội Tham Vương do Giang Trữ tam đại gia tổ chức.","detail":"Hai đệ tử Khổng gia cho biết Đại hội Tham Vương đã bắt đầu hơn một ngày tại Tuyết Lăng sơn và khuyên Hàn Lập nên tới sớm nếu muốn tham gia.","theLucLienQuan":["Giang Trữ tam đại gia","Khổng gia","Triệu gia","Đổng gia"],"nguon":["@c0901"]},{"id":"trang-vien-tren-dinh-nui","name":"Trang viện trên đỉnh núi","cn":"","capDo":"khac","parentId":"tuyet-lang-son","blurb":"Trang viện trên đỉnh núi là khu kiến trúc mới dựng để tổ chức hội giao dịch ở Tuyết Lăng sơn. Nơi đây có khu tiếp đãi, sân lớn, trướng bồng pháp khí và điện đường cho tu sĩ ra vào giao dịch.","detail":"Hàn Lập được lam bào tu sĩ dẫn vào trang viện và thấy khoảng năm sáu trăm tu sĩ tập trung. Quy mô nơi này gồm khu cho Trúc Cơ, lầu các cho Kết Đan, quầy hàng ngoài sân, trướng bồng bạch quang và hai điện đường hai bên.","theLucLienQuan":["Tam đại thế gia Giang Trữ"],"nguon":["@c0902"]},{"id":"mat-that-sau-hai-muoi-truong-duoi-mat-dat","name":"Mật thất sâu hai mươi trượng dưới mặt đất","cn":"","capDo":"khac","parentId":"trang-vien-tren-dinh-nui","blurb":"Mật thất sâu hai mươi trượng dưới mặt đất là nơi đặt quan tài đen của hoàng bào nam tử. Nó nằm tách biệt bên dưới khu hội giao dịch trên mặt đất.","detail":"Khi Hàn Lập phát hiện khí tức Nguyên Anh có thi khí, dưới mật thất này hoàng bào nam tử trong quan tài đen bị kinh động. Hắn từ trong quan ngồi dậy, dò xét toàn núi rồi lại nằm xuống.","theLucLienQuan":[],"nguon":["@c0902"]},{"id":"gian-truong-bong-giua-san","name":"Gian trướng bồng giữa sân","cn":"","capDo":"khac","parentId":"trang-vien-tren-dinh-nui","blurb":"Gian trướng bồng giữa sân là khu pháp khí dạng trướng bồng lớn trong hội giao dịch. Nó phát bạch quang và có tu sĩ ra vào.","detail":"Hàn Lập chú ý tới gian trướng bồng này khi quan sát hội giao dịch, đoán nơi đây có thể là khu các tông môn hoặc thế lực bày bán vật phẩm, nên định tới xem xét.","theLucLienQuan":["Tam đại thế gia Giang Trữ"],"nguon":["@c0902"]},{"id":"thuong-co-cu-mo","name":"Thượng cổ cự mộ","cn":"","aliases":["Cổ mộ của Huyễn vương"],"capDo":"khac","parentId":"tuyet-lang-son","blurb":"Thượng cổ cự mộ là di mộ của Huyễn vương nằm sâu trong Tuyết Lăng sơn mạch theo lời Kim Nguyên. Nơi này có chủ mộ thất, vật chôn theo, hành thi và quan tài chứa dị vật màu vàng, sau đó biến mất khỏi địa điểm cũ.","detail":"Ba năm trước, Kim Nguyên cùng hảo hữu và vài chí giao vào tòa mộ nghi là cổ tu cự mộ thời thượng cổ. Trong chủ mộ thất, thây khô chôn cùng sống lại thành hành thi, nhiều người tử nạn, quan tài phát sinh động tĩnh như chủ mộ muốn hồi sinh; về sau Kim Nguyên dẫn cao giai tu sĩ quay lại thì cổ mộ đã biến mất dù ký hiệu lối vào còn đó.","theLucLienQuan":[],"nguon":["@c0904"]},{"id":"chu-mo-that","name":"Chủ mộ thất","cn":"","aliases":[],"capDo":"khac","parentId":"thuong-co-cu-mo","blurb":"Chủ mộ thất là buồng mộ chính trong thượng cổ cự mộ, nơi nhóm Kim Nguyên thấy nhiều tài liệu quý hiếm và pháp khí trước khi bị hành thi tấn công.","detail":"Trong chủ mộ thất, nhiều thây khô chôn cùng đột nhiên sống lại thành hành thi đao thương bất nhập, pháp khí và công pháp khó làm chúng bị thương; đây cũng là nơi có quan tài phát sinh động tĩnh như Huyễn Diệp vương muốn hồi sinh.","theLucLienQuan":[],"nguon":["@c0904"]},{"id":"hoang-son","name":"Hoang sơn","cn":"","aliases":[],"capDo":"khac","parentId":null,"blurb":"Hoang sơn là loại địa vực Kim Nguyên thường tìm đến để tìm cổ tu động phủ hoặc linh địa di chỉ sau khi tu vi có chút thành tựu.","detail":"Kim Nguyên nói mình thường vào hoang sơn tìm kiếm cổ tu động phủ và linh địa di chỉ, nhưng loại cơ duyên này khó gặp và thu hoạch không nhiều.","theLucLienQuan":[],"nguon":["@c0904"]},{"id":"co-tu-dong-phu-linh-dia-di-chi","name":"Cổ tu động phủ / linh địa di chỉ","cn":"","aliases":[],"capDo":"khac","parentId":null,"blurb":"Cổ tu động phủ và linh địa di chỉ là mục tiêu tìm kiếm lâu dài của Kim Nguyên trong quá trình làm tán tu.","detail":"Kim Nguyên hy vọng nhờ tìm được động phủ thượng cổ tu sĩ hoặc linh địa di chỉ mà đổi vận tu luyện, nhưng bản thân ông nói cơ hội như vậy rất khó gặp.","theLucLienQuan":[],"nguon":["@c0904"]},{"id":"thach-oc","name":"Thạch ốc","cn":"","capDo":"khac","parentId":null,"blurb":"Thạch ốc là nơi Hàn Lập tiếp Kim Nguyên trong chương 905. Sau khi Kim Nguyên rời khỏi đại môn, Hàn Lập lập tức thu vẻ tươi cười và kiểm tra vật trong hộp ngọc.","detail":"Địa điểm này làm nền cho cảnh Hàn Lập nghi ngờ lời mời dò cổ mộ của Kim Nguyên và thả Đề Hồn thú ra kiểm tra bọt khí vàng. Tại đây Đại Diễn Thần Quân nhận ra kim cương xá lợi và Hàn Lập dùng thần niệm chi bích chặn đoàn lục quang.","theLucLienQuan":[],"nguon":["@c0905"]},{"id":"mo-that-cach-xa-may-nghin-dam","name":"Mộ thất cách xa mấy nghìn dặm","cn":"","aliases":["Mộ thất Tam Thi"],"capDo":"khac","parentId":"thuong-co-cu-mo","blurb":"Mộ thất cách xa mấy nghìn dặm là nơi có ba quan tài đá, bích họa thượng cổ và lư đồng đốt lục hỏa. Tại đây Vương nhi, Đại vương và Ái phi phát hiện biến cố mất phân thần cùng kim cương tráo.","detail":"Mộ thất lớn dị thường, rộng hơn trăm trượng, trong đó có ba quan tài đá xếp thành thế nổi bật. Bóng người trong quan tài trái nổi giận vì mất phân thần, còn trung niên nam tử trong quan tài giữa và nữ tử trong quan tài nhỏ nhất đối thoại, hé lộ lai lịch kim cương tráo và Minh hà thiên thi quyết.","theLucLienQuan":[],"nguon":["@c0905"]},{"id":"chu-that-cua-vuong-nhi","name":"Chủ thất của Vương Nhi","cn":"","capDo":"khac","parentId":"thuong-co-cu-mo","blurb":"Nơi Vương Nhi từng hấp thu nguyệt hoa chi lực và luyện hóa Kim cương tráo khi phần lớn cấm chế chưa mở.","detail":"Chủ thất này nằm trong khu cổ mộ liên quan đến Vương Nhi. Tại đây, nàng từng dời phân huyệt lên mặt đất để mượn nguyệt hoa chi lực luyện hóa bảo vật, chuẩn bị nghi thức nhận chủ, rồi gặp nhóm tu sĩ xông vào do cấm chế chưa được mở đầy đủ.","theLucLienQuan":[],"nguon":["@c0906"]},{"id":"giang-ninh-phu","name":"Giang Ninh phủ","cn":"","capDo":"khac","parentId":null,"blurb":"Địa bàn nơi đại vương muốn khống chế toàn bộ các đại thế gia để thu tinh hồn tu sĩ.","detail":"Giang Ninh phủ là trọng điểm trong kế hoạch quy mô lớn của đại vương. Hắn muốn nắm chặt các đại thế gia tại đây; Qua tướng quân đã hóa thân thao túng một thế gia tu sĩ và còn liên hợp các thế gia khác tiêu diệt một gia tộc truyền thừa Phật tông để che giấu âm mưu.","theLucLienQuan":["Thế gia tu sĩ ở Giang Ninh phủ","Gia tộc truyền thừa Phật tông bị tiêu diệt"],"nguon":["@c0906"]},{"id":"phuong-tiem-son","name":"Phương Tiêm sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Địa danh gắn với Thiên Phong chân quân và Phương Tiêm sơn song ma.","detail":"Phương Tiêm sơn là nơi gắn với Thiên Phong chân quân, người được đại vương nói là đã đề xuất biện pháp thu nguyên thần quy mô lớn. Nữ tử nghi ngờ Phương Tiêm sơn song ma có mưu đồ khác, nhất là khả năng dụ đại vương rời khỏi mộ thất.","theLucLienQuan":["Phương Tiêm sơn song ma"],"nguon":["@c0906"]},{"id":"van-yeu-coc","name":"Vạn Yêu cốc","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm có cốc chủ là vạn năm thi hùng và Vạn yêu phiên trấn giữ.","detail":"Vạn Yêu cốc được nhắc như một nơi khiến nhân loại tu sĩ kiêng dè. Đại vương cho rằng trong cốc có Vạn yêu phiên dựng thẳng, nên cả các đại tông môn chính đạo và ma đạo cũng không dám tùy tiện tiến vào.","theLucLienQuan":["Vạn Yêu cốc"],"nguon":["@c0906"]},{"id":"thien-co-oc","name":"Thiên cơ ốc","cn":"","capDo":"khac","parentId":null,"blurb":"Thiên cơ ốc là nơi Hàn Lập ở đầu chương khi xử lý Đề Hồn thú và Kim Cương tráo. Sau đó hắn rời ra ngoài, thu nhỏ thạch ốc và trả lại cho trung niên nữ tu.","detail":"Không gian này có thể thu nhỏ thành thạch ốc, được Hàn Lập dùng tạm trước khi trở lại quảng trường. Tại đây hắn nhận thấy Đề Hồn thú chưa thôn phệ xong Kim Cương tráo nên thu cả hai vào túi linh thú.","theLucLienQuan":[],"nguon":["@c0907"]},{"id":"quang-truong-tai-khu-dau-gia","name":"Quảng trường tại khu đấu giá","cn":"","capDo":"khac","parentId":null,"blurb":"Quảng trường là nơi Hàn Lập quay lại sau khi trả Thiên cơ ốc. Lúc này số tu sĩ trên quảng trường đã giảm vì nhiều người sang thạch điện tham gia đấu giá.","detail":"Từ quảng trường, Hàn Lập quan sát thấy dòng người đi vào một thạch điện phía đối diện để dự đấu giá hội, rồi hắn cũng đi tới đó sau khi rời Thiên cơ ốc.","theLucLienQuan":["Đấu giá hội tại thạch điện"],"nguon":["@c0907"]},{"id":"thach-dien-dau-gia","name":"Thạch điện đấu giá","cn":"","capDo":"khac","parentId":"quang-truong-tai-khu-dau-gia","blurb":"Thạch điện đấu giá là đại điện đối diện quảng trường, nơi diễn ra phiên đấu giá Hàn Lập tham gia. Nơi này có cửa thu phí, thông đạo, đại sảnh chính và thiên môn dẫn tới hậu đường.","detail":"Hàn Lập nộp ba khối linh thạch tại cửa thạch điện, nhận ngọc bàn số hai trăm bốn mươi ba rồi đi qua thông đạo vào đại sảnh chính. Sau khi mua được Hỏa dong tinh, hắn theo thiên môn vào hậu đường để nhận hàng.","theLucLienQuan":["Đấu giá hội tại thạch điện"],"nguon":["@c0907"]},{"id":"dai-sanh-chinh-dau-gia-hoi","name":"Đại sảnh chính đấu giá hội","cn":"","capDo":"khac","parentId":"thach-dien-dau-gia","blurb":"Đại sảnh chính đấu giá hội là nơi người dự ngồi theo ngọc bàn đánh số và xem chủ trì bán vật phẩm. Hàn Lập quan sát giá cả Đại Tấn và phát hiện Hỏa dong tinh tại đây.","detail":"Trong đại sảnh, lam bào trung niên nhân chủ trì đấu giá phượng vĩ hoa, nhiều pháp khí linh dược và ba khối Hỏa dong tinh. Hàn Lập ngồi xuống, được hai nữ tu cạnh bên giải thích về ôn thạch rồi tham gia đấu giá Hỏa dong tinh.","theLucLienQuan":["Đấu giá hội tại thạch điện"],"nguon":["@c0907"]},{"id":"thien-mon-hau-duong-dau-gia-hoi","name":"Thiên môn hậu đường đấu giá hội","cn":"","capDo":"khac","parentId":"thach-dien-dau-gia","blurb":"Thiên môn hậu đường đấu giá hội là lối bên cạnh đại điện dành cho người trúng giá vào giao nhận vật phẩm. Hàn Lập được dẫn qua đây sau khi thắng Hỏa dong tinh.","detail":"Tại thiên môn đã có bạch bào tu sĩ Luyện Khí kỳ chờ sẵn để dẫn Hàn Lập vòng qua vài lượt tới phòng nhỏ phía sau. Trong hậu đường, thị nữ dâng trà và lão già đầu hói Trúc Cơ kỳ đem hộp ngọc chứa Hỏa dong tinh tới.","theLucLienQuan":["Đấu giá hội tại thạch điện"],"nguon":["@c0907"]},{"id":"loan-tinh-hai","name":"Loạn Tinh hải","cn":"","capDo":"vuc","parentId":null,"blurb":"Loạn Tinh hải được Hàn Lập dùng làm địa vực so sánh khi đánh giá tài nguyên Đại Tấn. Hắn nhận ra có nhiều vật quý hiếm ở Đại Tấn mà cả Loạn Tinh hải cũng chưa từng thấy.","detail":"Trong lúc quan sát đấu giá hội, Hàn Lập so sánh Đại Tấn với Thiên Nam và Loạn Tinh hải. Nhận định này cho thấy Đại Tấn có nguồn tài liệu, dược thảo phong phú khác biệt với các vùng hắn từng biết.","theLucLienQuan":[],"nguon":["@c0907"]},{"id":"phong-dau-gia","name":"Phòng đấu giá","cn":"","capDo":"khac","parentId":"thach-dien-dau-gia","blurb":"Không gian đấu giá nơi Hàn Lập quay lại sau khi mua hỏa dong tinh.","detail":"Sau giao dịch hỏa dong tinh, Hàn Lập trở lại chỗ ngồi trong phòng đấu giá, quan sát tinh thạch và tiếp tục theo dõi hội một lúc. Vì bị lời Đại Diễn Thần Quân làm tâm cảnh trầm xuống, hắn mất hứng thú với các vật phẩm sau đó rồi rời khỏi hội trường.","theLucLienQuan":["Đấu giá hội tại thạch điện"],"nguon":["@c0908"]},{"id":"quang-truong-giao-dich-hoi","name":"Quảng trường giao dịch hội","cn":"","capDo":"khac","parentId":"quang-truong-tai-khu-dau-gia","blurb":"Khu vực bên ngoài hội trường đấu giá, nơi Hàn Lập rời ra sau khi tâm cảnh trầm xuống.","detail":"Tại quảng trường giao dịch hội, Hàn Lập đi về góc ít người, dùng thần thức kiểm tra xung quanh rồi tiếp cận chấp sự Khổng gia đang đứng gần một gian lầu.","theLucLienQuan":["Khổng gia","Đấu giá hội tại thạch điện"],"nguon":["@c0908"]},{"id":"gian-lau-cua-khong-gia","name":"Gian lầu của Khổng gia","cn":"","capDo":"khac","parentId":"quang-truong-giao-dich-hoi","blurb":"Gian lầu nơi ngoại đường chấp sự Khổng gia đứng chờ người trong giao dịch hội.","detail":"Hàn Lập kiểm tra khu vực quanh gian lầu, thấy không có cấm chế lợi hại, rồi dùng hỏa dong tinh khiến chấp sự Khổng gia bị lam mang đóng băng. Sau đó hắn cuốn người này vào quang điểm và vô thanh vô tức tiến vào lầu.","theLucLienQuan":["Khổng gia"],"nguon":["@c0908"]},{"id":"tuyet-giang-tieu-thanh","name":"Tuyết Giang tiểu thành","cn":"","capDo":"thanh","parentId":null,"blurb":"Tiểu thành ngoài hơn trăm dặm từ Chuẩn Vân trấn, lớn hơn Chuẩn Vân trấn ba bốn lần.","detail":"Hàn Lập đến Tuyết Giang tiểu thành sau khi thẩm vấn Khổng Đấu. Trong thành chỉ có tu sĩ cấp thấp, người mạnh nhất là một tu sĩ Kết Đan trong trạch viện phía tây nam, không phát hiện được thần thức dò xét của Hàn Lập.","theLucLienQuan":["Khổng gia","Phùng gia"],"nguon":["@c0909"]},{"id":"duyet-lai-khach-diem","name":"Duyệt Lai khách điếm","cn":"","capDo":"khac","parentId":"tuyet-giang-tieu-thanh","blurb":"Khách điếm tại Tuyết Giang có dấu hiệu ấm trà dưới chiêu bài, là điểm liên lạc liên quan Phùng gia.","detail":"Hàn Lập nhận ra Duyệt Lai khách điếm nhờ chiêu bài và dấu hiệu ấm trà bên dưới, rồi lẻn vào trong đêm để gặp lão bản. Tại đây hắn dùng chìa khóa bạc để lấy đầu mối mật thất Phùng gia.","theLucLienQuan":["Phùng gia"],"nguon":["@c0909"]},{"id":"hau-vien-duyet-lai-khach-diem","name":"Hậu viện Duyệt Lai khách điếm","cn":"","capDo":"khac","parentId":"duyet-lai-khach-diem","blurb":"Hậu viện nơi lão bản Duyệt Lai đào viên gạch xanh có cấm chế.","detail":"Lão bản Duyệt Lai dẫn Hàn Lập ra hậu viện, đào ở góc tường lấy viên gạch xanh và nói mật thất được phong ấn tại đó, mặt trên có cấm chế.","theLucLienQuan":["Phùng gia"],"nguon":["@c0909"]},{"id":"trach-vien-tay-nam-tuyet-giang-thanh","name":"Trạch viên tây nam Tuyết Giang thành","cn":"","capDo":"khac","parentId":"tuyet-giang-tieu-thanh","blurb":"Trạch viện phía tây nam Tuyết Giang thành có tu sĩ Kết Đan mạnh nhất trong thành.","detail":"Khi Hàn Lập thả thần thức dò xét Tuyết Giang, nơi này là chỗ có tu sĩ tu vi cao nhất trong thành, nhưng người đó không phát hiện được thần thức của hắn.","theLucLienQuan":[],"nguon":["@c0909"]},{"id":"hoang-son-vo-danh-gan-tuyet-giang","name":"Hoang sơn vô danh gần Tuyết Giang","cn":"","capDo":"khac","parentId":null,"blurb":"Ngọn hoang sơn gần Tuyết Giang nơi Hàn Lập dừng lại sau khi rời thành.","detail":"Sau khi rời Duyệt Lai khách điếm và bay khỏi Tuyết Giang tiểu thành, Hàn Lập đáp xuống một hoang sơn vô danh gần đó để lấy viên gạch xanh ra xem tiếp.","theLucLienQuan":[],"nguon":["@c0909"]},{"id":"mo-that-trong-tuyet-lang-son-mach","name":"Mộ thất trong Tuyết Lăng sơn mạch","cn":"","capDo":"khac","parentId":"tuyet-lang-son","blurb":"Mộ thất nằm trong Tuyết Lăng sơn mạch, có nhiều thạch quan và là nơi Đại vương cùng thuộc hạ xuất hiện. Từ đây, Đại vương phái người truy sát Hàn Lập và chuẩn bị rời mộ thất nhân ngày âm khí bạo phát.","detail":"Không gian mộ thất có các thạch quan chứa Đại vương, ái phi và những tồn tại khác. Chương 910 cho thấy đây là cứ điểm của một nhóm bí ẩn: Đại vương ra lệnh cho hai nhân ảnh lục sắc giết Hàn Lập, đồng thời bảo người ở lại dựng cấm chế sau khi hắn rời khỏi mộ thất.","theLucLienQuan":["Mộ thất Tuyết Lăng sơn của Đại vương"],"nguon":["@c0910"]},{"id":"co-mo-cua-huyen-vuong","name":"Cổ mộ","cn":"","capDo":"khac","parentId":null,"blurb":"Khu cổ mộ nơi Huyễn Vương có uy thế rất mạnh và là trung tâm kế hoạch vây sát của nhiều phe.","detail":"Trong cổ mộ, Huyễn Vương được nói có thần thông không kém tu sĩ Nguyên Anh hậu kỳ. Phe mai phục phải dụ lão ma rời mộ thất mới có cơ hội xuống tay.","theLucLienQuan":["Huyễn Vương","Hai thế gia còn lại","Tông môn đứng sau hai thế gia"],"nguon":["@c0911"]},{"id":"mo-that-cua-huyen-vuong","name":"Mộ thất","cn":"","capDo":"khac","parentId":"co-mo-cua-huyen-vuong","blurb":"Nơi Huyễn Vương thường ở và không dễ rời đi.","detail":"Thiên Phong chân quân cho biết phải bày bẫy mới khiến Huyễn Vương rời mộ thất, từ đó tạo cơ hội cho các phe phục kích.","theLucLienQuan":["Huyễn Vương"],"nguon":["@c0911"]},{"id":"lang-mo-cua-huyen-vuong","name":"Lăng mộ","cn":"","capDo":"khac","parentId":"co-mo-cua-huyen-vuong","blurb":"Khu lăng mộ chứa bảo vật, thiên thi châu và mấy ngàn thi binh mà phe mai phục muốn đoạt.","detail":"Sau khi Huyễn Vương bị trừ, phe mai phục dự tính chia bảo vật trong lăng mộ. Chủ nhân thanh âm chói tai đặc biệt muốn mấy ngàn thi binh để dựng thế lực tại Vô động sơn.","theLucLienQuan":["Huyễn Vương"],"nguon":["@c0911"]},{"id":"vo-dong-son","name":"Vô động sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực mà chủ nhân thanh âm chói tai muốn dùng thi binh để lập thế lực.","detail":"Chủ nhân thanh âm chói tai nói chỉ cần mấy ngàn thi binh trong lăng mộ là có thể trở thành một thế lực tại Vô động sơn.","theLucLienQuan":["Chủ nhân thanh âm chói tai"],"nguon":["@c0911"]},{"id":"cua-da-sau-thac-nuoc","name":"Cửa đá sau thác nước","cn":"","capDo":"khac","parentId":"mat-quat-phung-gia","blurb":"Lối vào mật quật Phùng gia được mở bằng chìa khóa bạc.","detail":"Hàn Lập tìm lỗ nhỏ trên cửa đá, tra chìa khóa bạc vào và dùng thanh ti kích hoạt, khiến cửa đá phát linh quang rồi nâng lên để lộ động khẩu.","theLucLienQuan":["Phùng gia"],"nguon":["@c0911"]},{"id":"dai-sanh-mat-quat","name":"Đại sảnh mật quật","cn":"","capDo":"khac","parentId":"mat-quat-phung-gia","blurb":"Đại sảnh bí mật trong mật quật Phùng gia, nơi đặt kho tàng và các rương bạc.","detail":"Đại sảnh rộng khoảng hai mươi trượng, xây bằng ôn thạch, có hai hàng giá gỗ chứa pháp khí, pháp bảo, hơn trăm ngọc giản và ba rương bạc đựng linh thạch, tài liệu cùng phù triện.","theLucLienQuan":["Phùng gia"],"nguon":["@c0911"]},{"id":"son-mach","name":"Sơn mạch","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực Hàn Lập phải cấp tốc rời khỏi sau khi chia tay Huyễn Diệp vương. Hắn liên tục đổi hướng và độn xa ngàn dặm để tránh nguy cơ pháp lực bị phong tỏa.","detail":"Sau khi nhận Thiên Thi Châu và rời khỏi Huyễn Diệp vương, Hàn Lập không dám chậm trễ, cấp tốc thoát khỏi sơn mạch trước khi pháp lực bị phong tỏa. Đây là vùng gần cổ mộ và cũng là nơi hắn muốn rời càng xa càng tốt trước khi gặp nhóm người đang chờ.","theLucLienQuan":["Huyễn Diệp vương"],"nguon":["@c0917"]},{"id":"nui-nho-vang-ve","name":"Núi nhỏ vắng vẻ","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Hàn Lập hạ xuống sau hai ngày rời xa sơn mạch. Hắn mở động phủ tạm dưới chân núi và bày trận che giấu.","detail":"Sau khi độn xa khỏi sơn mạch, Hàn Lập chọn một núi nhỏ vắng vẻ, mở động phủ đơn giản dưới chân núi rồi dùng khí cụ bày trận che kín. Đây là nơi hắn tạm thời xử lý việc tu luyện, bảo vật và bàn kế hoạch với Đại Diễn Thần Quân.","theLucLienQuan":[],"nguon":["@c0917"]},{"id":"nam-chau","name":"Nam Châu","cn":"","capDo":"chau","parentId":null,"blurb":"Địa bàn có phú thương do Phùng gia âm thầm bồi dưỡng và hơn mười cửa hàng nổi danh. Hàn Lập dự tính dùng đường lui này làm bình phong để bái nhập đại tông môn.","detail":"Nam Châu là nơi Phùng gia từng chuẩn bị đường lui thông qua một phú thương không lộ quan hệ thân phận công khai. Hàn Lập dự tính mượn người này che chắn thân phận để trà trộn vào một đại tông môn có linh mạch tốt, nhằm âm thầm tu luyện Minh Vương Quyết.","theLucLienQuan":["Phùng gia","Đại tông môn Nam Châu"],"nguon":["@c0917"]},{"id":"quan-giap-ranh-bac-bo-va-trung-bo-dai-tan","name":"Quận giáp ranh Bắc bộ và Trung bộ Đại Tấn","cn":"","capDo":"vuc","parentId":"dai-tan","blurb":"Đây là một quận nhỏ nhưng giàu có của Đại Tấn, nằm ở nơi giáp ranh Bắc bộ và Trung bộ. Vùng này nhiều đồng bằng sông hồ, sản vật phong phú, có linh sơn đại xuyên và phong khí Phật Đạo, học viện thịnh hành.","detail":"Quận được giới thiệu là diện tích không lớn nhưng mức giàu có thuộc nhóm đầu, phàm nhân thường thấy bóng dáng tiên nhân ăn mặc như tăng nhân hoặc đạo sĩ, khiến phong trào tín Phật phụng Đạo lan rộng. Nền học viện ở đây cũng phát triển, mở đường cho con em nghèo tiến thân.","theLucLienQuan":["Học viện Đại Tấn tại quận này"],"nguon":["@c0919"]},{"id":"thai-xuong-phu","name":"Thái Xương phủ","cn":"","aliases":["Thái Xương thành"],"capDo":"thanh","parentId":"quan-giap-ranh-bac-bo-va-trung-bo-dai-tan","blurb":"Thái Xương phủ là phủ thành có danh khí lớn trong quận. Nơi đây tập trung quan quý, phú hào, cự thương và mấy nhà công hầu cư trú.","detail":"Cam gia đặt phủ đệ ở bờ Tây Thái Xương thành. Hàn Lập khi đến đây dùng thần thức dò xét và phát hiện trong thành có không ít tu tiên giả, phân bố có quy luật ở vài địa điểm.","theLucLienQuan":["Cam gia"],"nguon":["@c0919"]},{"id":"cam-phu","name":"Cam phủ","cn":"","capDo":"khac","parentId":"thai-xuong-phu","blurb":"Cam phủ là cự trạch của Cam gia ở bờ Tây Thái Xương thành. Đại môn đen bóng treo bảng Cam Phủ là nơi Hàn Lập tìm đến để gặp Cam Trì.","detail":"Tại Cam phủ, Hàn Lập được hạ nhân giữ cửa truyền báo, được Cam Dụ mời vào khách sảnh, rồi sau đó gặp Cam Trì và đi vào thư phòng để xác nhận tuyến liên lạc bí mật.","theLucLienQuan":["Cam gia"],"nguon":["@c0919"]},{"id":"bach-lo-thu-vien","name":"Bạch Lộ thư viện","cn":"","capDo":"khac","parentId":"huyen-van-phong","blurb":"Bạch Lộ thư viện nằm ngoài thành Thái Xương, dựng trên Huyễn Vân phong thuộc Ngọc Điền Sơn. Nơi này có lầu các quy mô lớn, đủ chứa hơn nghìn người.","detail":"Bạch Lộ thư viện bề ngoài chỉ là thư viện bậc trung, nhưng tọa lạc trên linh sơn nổi danh của phủ Thái Xương. Kiến trúc trải từ sườn núi tới đỉnh Huyễn Vân phong, xung quanh có rừng trúc, tường đỏ mái trắng và cửa phụ dẫn vào trong viện.","theLucLienQuan":["Bạch Lộ thư viện"],"nguon":["@c0920"]},{"id":"thanh-thai-xuong","name":"Thành Thái Xương","cn":"","capDo":"thanh","parentId":"thai-xuong-phu","blurb":"Thành Thái Xương là đại thành gần Bạch Lộ thư viện. Hàn Lập từng xuất hiện ở Cam phủ trong khu vực này trước khi lên Ngọc Điền Sơn.","detail":"Bạch Lộ thư viện nằm ngoài thành Thái Xương, còn Cam phủ là nơi Hàn Lập xuất hiện một tháng trước khi thông qua Cam Trì tìm đường vào thư viện.","theLucLienQuan":["Cam gia","Bạch Lộ thư viện"],"nguon":["@c0920"]},{"id":"ngoc-dien-son","name":"Ngọc Điền Sơn","cn":"","capDo":"vuc","parentId":"thai-xuong-phu","blurb":"Ngọc Điền Sơn là dãy linh sơn nổi danh của phủ Thái Xương, có hơn mười ngọn núi và khí xuân quanh năm. Hàn Lập đánh giá linh mạch nơi này tốt hơn các linh mạch gần thành Thái Xương khác.","detail":"Ngọc Điền Sơn có nhiều kỳ hoa dị thảo, một số linh dược quý hiếm chỉ trồng được tại đây và được xếp đứng đầu mười ba linh sơn của Nươm quận. Bạch Lộ thư viện tọa lạc trên Huyễn Vân phong thuộc dãy núi này.","theLucLienQuan":["Bạch Lộ thư viện","Bảo Linh tự"],"nguon":["@c0920"]},{"id":"huyen-van-phong","name":"Huyễn Vân phong","cn":"","capDo":"khac","parentId":"ngoc-dien-son","blurb":"Huyễn Vân phong là ngọn núi thuộc Ngọc Điền Sơn, nơi Bạch Lộ thư viện tọa lạc. Hàn Lập và Nghiêm Nghiêu lên núi từ chân phong tới rừng trúc và cửa phụ thư viện.","detail":"Bạch Lộ thư viện được xây trên Huyễn Vân phong, từ sườn núi kéo tới đỉnh núi. Tuyến đường vào viện có rừng trúc xanh um, đường đá trắng và cửa phụ dùng để thông bẩm khách đến.","theLucLienQuan":["Bạch Lộ thư viện"],"nguon":["@c0920"]},{"id":"hoang-thanh-quan","name":"Hoàng Thanh quan","cn":"","capDo":"khac","parentId":"ngoc-dien-son","blurb":"Hoàng Thanh quan là đạo quán trên một ngọn núi khác trong dãy Ngọc Điền sơn. Hàn Lập chỉ từng nghe tên nơi này trước khi Hoa Liên tiên cô đề nghị đưa hắn sang đó.","detail":"Đạo quán này nằm trong khu vực Ngọc Điền Sơn, cùng vùng với Bạch Lộ thư viện. Trong chương, Hàn Lập biết lơ mơ đây là một đạo quán trên ngọn núi khác nhưng chưa hiểu rõ nội tình, đặc biệt không biết nơi này là nữ quan có cả tu sĩ tại gia và nam tử môn nhân sống ngoài quan.","theLucLienQuan":["Hoàng Thanh quan"],"nguon":["@c0921","@c0946"]},{"id":"mat-that-chua-tai-lieu-tap-nham","name":"Mật thất chứa tài liệu tạp nham","cn":"","aliases":[],"capDo":"khac","parentId":"luyen-khi-dien","blurb":"Mật thất chứa tài liệu tạp nham là nơi Hoa Liên tiên cô đưa Hàn Lập tới gặp Vi lão. Đây là bối cảnh ban đầu của việc giao Hàn Lập làm trợ thủ luyện bảo.","detail":"Trong mật thất có nhiều tài liệu tạp nham, Vi lão đang ở đó khi Hoa Liên tiên cô dẫn Hàn Lập tới. Tại đây, Hoa Liên tiên cô giới thiệu Vi lão và nói rõ nhu cầu trợ thủ cho việc luyện chế trọng bảo.","theLucLienQuan":["Tam Hoàng quan","Hoàng Thanh quan","Luyện Khí điện"],"nguon":["@c0923"]},{"id":"luyen-khi-dien","name":"Luyện Khí điện","cn":"","aliases":[],"capDo":"khac","parentId":"hoang-thanh-quan","blurb":"Luyện Khí điện là biệt viện nằm giữa ngọn núi của Hoàng Thanh quan. Đây là nơi Vi lão phụ trách luyện khí và Hàn Lập bắt đầu làm trợ thủ.","detail":"Luyện Khí điện gồm địa hỏa đại điện, vài luyện khí các và các động phủ dựa vào núi cho đệ tử sinh sống. Nơi này tiếp nhận nam nữ đệ tử trong quan tới thuê hoặc nhờ luyện khí, đồng thời là nơi Hàn Lập học luyện khí thuật từ Vi lão.","theLucLienQuan":["Hoàng Thanh quan","Tam Hoàng quan"],"nguon":["@c0923"]},{"id":"dia-hoa-dai-dien","name":"Địa hỏa đại điện","cn":"","aliases":[],"capDo":"khac","parentId":"luyen-khi-dien","blurb":"Địa hỏa đại điện là khu vực trọng yếu trong Luyện Khí điện. Vi lão về sau thường ở trong mật thất tại đây để luyện chế vật bí mật.","detail":"Địa hỏa đại điện thuộc bố cục của Luyện Khí điện, gắn với việc luyện khí bằng địa hỏa. Trong giai đoạn sau, Vi lão thường xuyên bận rộn trong mật thất của khu vực này để luyện chế thứ chưa lộ rõ.","theLucLienQuan":["Luyện Khí điện","Hoàng Thanh quan"],"nguon":["@c0923"]},{"id":"dong-quat-mat-that-cua-han-lap","name":"Động quật mật thất của Hàn Lập","cn":"","aliases":["Động quật của Hàn Lập","Mật thất của Hàn Lập"],"capDo":"khac","parentId":"luyen-khi-dien","blurb":"Động quật mật thất của Hàn Lập là nơi hắn tu luyện Minh Vương Quyết ở cuối chương. Tại đây thân thể hắn xuất hiện kim quang, tơ máu, gân xanh và dị vật chạy dưới da.","detail":"Sau thời gian sinh hoạt trong Luyện Khí điện, Hàn Lập dùng động quật mật thất làm nơi tu luyện. Cuối chương, hắn vận công trong tư thế kỳ dị, chịu đau đớn cho tới khi kim quang thu lại và thân thể khôi phục bình thường.","theLucLienQuan":["Luyện Khí điện","Hoàng Thanh quan"],"nguon":["@c0923"]},{"id":"dai-mon-luyen-khi-dien","name":"Đại môn Luyện Khí điện","cn":"","capDo":"khac","parentId":"luyen-khi-dien","blurb":"Đại môn Luyện Khí điện là lối nhóm Lục Tú quận chúa và các tu sĩ trẻ đi vào. Tiếng động từ hướng này khiến Hàn Lập chú ý khi đang ở Địa Hỏa đại điện.","detail":"Địa điểm này đánh dấu thời điểm đoàn Lục Tú quận chúa xuất hiện tại Luyện Khí điện, mở đầu cho việc nhờ tinh luyện Huyết ty ngân.","theLucLienQuan":["Luyện Khí điện","Hoàng Thanh quan"],"nguon":["@c0924"]},{"id":"mat-that-duoi-dat","name":"Mật thất dưới đất","cn":"","capDo":"khac","parentId":"luyen-khi-dien","blurb":"Mật thất dưới đất là nơi Vi lão và hai trợ thủ đang bế quan làm việc. Vì đang luyện chế trọng bảo ở đây, ông dặn đệ tử không được quấy nhiễu nếu không có việc trọng đại.","detail":"Nơi này khiến yêu cầu mời Vi đại sư tinh luyện Huyết ty ngân không thể thực hiện ngay, buộc Lục Tú quận chúa chuyển sang để Hàn Lập thử.","theLucLienQuan":["Luyện Khí điện","Hoàng Thanh quan"],"nguon":["@c0924"]},{"id":"trong-quan","name":"Trong quận","cn":"","capDo":"khac","parentId":null,"blurb":"Trong quận là phạm vi danh tiếng của Tứ quán chủ Hoàng Thanh quan được nhắc tới. Ông được nói là nổi danh hiển hách trong khu vực này.","detail":"Địa danh chưa được nêu tên cụ thể, chỉ dùng để chỉ phạm vi ảnh hưởng và uy danh của Tứ quán chủ Hoàng Thanh quan.","theLucLienQuan":["Hoàng Thanh quan"],"nguon":["@c0924"]},{"id":"vuong-phu-cua-luc-tu-quan-chua","name":"Vương phủ của Lục Tú quận chúa","cn":"","capDo":"khac","parentId":null,"blurb":"Vương phủ là nơi Lục Tú quận chúa nói mình ở, qua đó hé lộ xuất thân quyền quý của nàng. Nàng dù ở vương phủ vẫn từng nghe đại danh Vi đại sư.","detail":"Vương phủ chưa được mô tả trực tiếp, nhưng là bối cảnh xã hội gắn với thân phận quận chúa của Lục Tú.","theLucLienQuan":["Vương phủ của Lục Tú quận chúa"],"nguon":["@c0924"]},{"id":"hoa-dien","name":"Hỏa điện","cn":"","capDo":"khac","parentId":"luyen-khi-dien","blurb":"Hỏa điện là công trình trọng yếu nhất của Luyện Khí điện. Nơi này chia ba tầng và dùng địa hỏa phục vụ đề luyện tài liệu, luyện chế linh khí.","detail":"Hỏa điện có thượng tầng cất giữ tài liệu, trung tầng nối thông địa hỏa để đề luyện tài liệu và luyện linh khí bậc thấp, hạ tầng có Địa Hỏa trì dùng cho linh khí bậc cao. Hàn Lập đưa Lục Tú quận chúa vào mật thất luyện khí ở khu trung tầng tại đây.","theLucLienQuan":["Luyện Khí điện"],"nguon":["@c0925"]},{"id":"trung-tang-hoa-dien","name":"Trung tầng Hỏa điện","cn":"","capDo":"khac","parentId":"hoa-dien","blurb":"Trung tầng Hỏa điện là khu nối thông địa hỏa, dùng để đề luyện tài liệu và luyện chế linh khí bậc thấp. Mật thất luyện khí thường dùng của Hàn Lập nằm tại đây.","detail":"Hàn Lập dẫn Lục Tú quận chúa đến gian mật thất ở trung tầng Hỏa điện. Khu này có điều kiện hỏa lực thích hợp cho việc xử lý tài liệu luyện khí.","theLucLienQuan":["Luyện Khí điện"],"nguon":["@c0925"]},{"id":"ha-tang-hoa-dien","name":"Hạ tầng Hỏa điện","cn":"","capDo":"khac","parentId":"hoa-dien","blurb":"Hạ tầng Hỏa điện nằm sâu dưới đất và dùng Địa Hỏa trì phục vụ luyện chế linh khí bậc cao. Đây là tầng khai thác địa hỏa mạnh hơn trung tầng.","detail":"Hạ tầng nằm sâu hai ba mươi trượng dưới đất, có Địa Hỏa trì chứa địa hỏa chi tinh. Nơi này chuyên dùng cho luyện chế linh khí bậc cao.","theLucLienQuan":["Luyện Khí điện"],"nguon":["@c0925"]},{"id":"dia-hoa-tri","name":"Địa Hỏa trì","cn":"","capDo":"khac","parentId":"ha-tang-hoa-dien","blurb":"Địa Hỏa trì là ao địa hỏa ở hạ tầng Hỏa điện. Nơi này chứa một luồng địa hỏa chi tinh dùng cho luyện khí bậc cao.","detail":"Địa Hỏa trì được nhắc khi giới thiệu hạ tầng Hỏa điện, là nguồn hỏa lực quan trọng để luyện chế linh khí bậc cao.","theLucLienQuan":["Luyện Khí điện"],"nguon":["@c0925"]},{"id":"mat-that-luyen-khi-cua-han-lap","name":"Mật thất luyện khí của Hàn Lập","cn":"","capDo":"khac","parentId":"trung-tang-hoa-dien","blurb":"Mật thất luyện khí của Hàn Lập nằm ở trung tầng Hỏa điện. Gian mật thất này có đại đỉnh ở giữa và tám pháp khí hình hồ lô bố trí bốn phía.","detail":"Hàn Lập đưa Lục Tú quận chúa vào mật thất để luyện hóa huyết ty ngân. Trong mật thất có đại đỉnh và tám pháp khí hồ lô có thể phun lửa đỏ đậm phục vụ luyện khí.","theLucLienQuan":["Luyện Khí điện"],"nguon":["@c0925"]},{"id":"lau-cac-tren-dinh-nui","name":"Lầu các trên đỉnh núi","cn":"","capDo":"khac","parentId":null,"blurb":"Lầu các trên đỉnh núi là nơi đạo cô lớn tuổi họ Diệp và trung niên mỹ phụ Diệp gia bí mật bàn luận. Cuộc nói chuyện xoay quanh kế hoạch hơn bốn trăm năm của hoàng tộc Đại Tấn.","detail":"Tại lầu các này, hai người Diệp gia tranh luận về việc mưu đoạt hai món linh bảo, nguy cơ đối đầu các thế lực lớn và bí mật liên quan tu sĩ Hóa Thần kỳ.","theLucLienQuan":["Diệp gia hoàng tộc Đại Tấn"],"nguon":["@c0925"]},{"id":"dong-phu-trong-nui-cua-su-phu-luc-tu-quan-chua","name":"Động phủ trong núi của sư phụ Lục Tú quận chúa","cn":"","capDo":"khac","parentId":null,"blurb":"Động phủ trong núi của sư phụ Lục Tú quận chúa là nơi nàng nói trước đây vẫn theo sư phụ tu hành. Nơi này cho thấy nàng không sinh hoạt như quận chúa vương phủ thông thường.","detail":"Lục Tú quận chúa nhắc đến động phủ này khi giải thích với Hàn Lập rằng nàng từ nhỏ theo Ngọc di tu luyện, chứ không phải sống và tu hành trong vương phủ như hắn tưởng.","theLucLienQuan":[],"nguon":["@c0925"]},{"id":"kinh-thanh","name":"Kinh thành","cn":"","aliases":["Tấn kinh","Tấn thành","Kinh thành Đại Tấn","Kinh đô Đại Tấn"],"capDo":"thanh","parentId":"dai-tan","blurb":"Kinh thành là nơi vài thế lực lớn tăng số tu sĩ Kết Đan kỳ đóng giữ trong thời gian Diệp gia âm thầm triển khai kế hoạch lớn.","detail":"Mỹ phụ Diệp gia nói số tu sĩ Kết Đan kỳ của vài thế lực lớn đóng ở kinh thành bỗng tăng nhiều, khiến nội bộ hoàng tộc nhận định kế hoạch của họ có thể đã bị nghi ngờ nhưng chưa bị phát giác hoàn toàn.","theLucLienQuan":["Diệp gia","Vài thế lực lớn ở kinh thành"],"nguon":["@c0926"]},{"id":"tay-binh-son","name":"Tây Bỉnh sơn","cn":"","aliases":[],"capDo":"khac","parentId":"dai-tan","blurb":"Tây Bỉnh sơn là địa bàn gắn với Quỷ Vương được Diệp gia nhắc như ngoại viện sẵn lòng giúp hoàng tộc.","detail":"Trong cuộc bàn bạc của Diệp gia, Tây Bỉnh sơn xuất hiện qua danh xưng Tây Bỉnh sơn Quỷ Vương. Người này cùng phó cốc chủ hùng sư Vạn yêu cốc được nói là nguyện vì hoàng tộc ra mặt.","theLucLienQuan":["Diệp gia"],"nguon":["@c0926"]},{"id":"dai-tan-nam-bo","name":"Đại Tấn nam bộ","cn":"","capDo":"vuc","parentId":"dai-tan","blurb":"Khu vực phía nam Đại Tấn nơi hơn một năm sau xuất hiện ba người kỳ lạ liên tục tìm đoạt tài liệu quý.","detail":"Đại Tấn nam bộ trở thành tâm điểm chấn động của tu tiên giới khi liên tiếp xuất hiện các vụ thu mua, mất trộm và cưỡng ép giao dịch thiên tài địa bảo. Các hành động này khiến nhiều tông môn, thế gia phái người truy lùng thủ phạm.","theLucLienQuan":["Các tu tiên tông môn Đại Tấn nam bộ"],"nguon":["@c0927"]},{"id":"ich-chau","name":"Ích Châu","cn":"","capDo":"chau","parentId":"dai-tan-nam-bo","blurb":"Một châu ở Đại Tấn nam bộ, có phường thị Thái Hưng được nhắc đến trong chuỗi vụ thu gom tài liệu.","detail":"Ích Châu là địa bàn có phường thị Thái Hưng, nơi một người trẻ tuổi dùng giá cao mua một cửa hàng lâu năm rồi dò hỏi về khoáng thạch vô danh.","theLucLienQuan":[],"nguon":["@c0927"]},{"id":"thai-hung","name":"Thái Hưng","cn":"","capDo":"khac","parentId":"ich-chau","blurb":"Phường thị lớn nhất Ích Châu, nơi người trẻ tuổi mua cửa hàng để hỏi mua khoáng thạch vô danh.","detail":"Thái Hưng là phường thị lớn nhất Ích Châu. Tại đây, một người trẻ tuổi bỏ tám vạn linh thạch mua một cửa hàng gần trăm năm, sau đó gặp ai cũng hỏi về một khối khoáng thạch vô danh.","theLucLienQuan":[],"nguon":["@c0927"]},{"id":"phien-quan","name":"Phiền quận","cn":"","capDo":"khac","parentId":"dai-tan-nam-bo","blurb":"Khu vực có Phiền Xuyên giao dịch hội, nơi tu sĩ che mặt mua Hỏa tích mộc.","detail":"Phiền quận được nhắc trong chuỗi sự kiện thu gom tài liệu ở Đại Tấn nam bộ. Tại Phiền Xuyên giao dịch hội thuộc khu vực này, một tu sĩ che mặt dùng lượng lớn linh thạch mua ba khối Hỏa tích mộc.","theLucLienQuan":[],"nguon":["@c0927"]},{"id":"phien-xuyen-giao-dich-hoi","name":"Phiền Xuyên giao dịch hội","cn":"","capDo":"khac","parentId":"phien-quan","blurb":"Giao dịch hội nổi danh nơi ba khối Hỏa tích mộc được tu sĩ che mặt mua bằng mười lăm vạn linh thạch.","detail":"Phiền Xuyên giao dịch hội là địa điểm giao dịch nổi danh tại Phiền quận. Trong chuỗi vụ thu gom tài liệu, một tu sĩ che mặt xuất hiện tại đây và dùng mười lăm vạn linh thạch mua ba khối Hỏa tích mộc.","theLucLienQuan":[],"nguon":["@c0927"]},{"id":"phong-chau","name":"Phong Châu","cn":"","capDo":"chau","parentId":"dai-tan-nam-bo","blurb":"Châu có Khai Long Phủ, nơi Minh Kiếm tông xảy ra vụ mất trộm Linh giác Thiết Giác tê.","detail":"Phong Châu được nhắc đến qua vụ việc tại Khai Long Phủ. Minh Kiếm tông trong khu vực này phát sinh mất trộm, một Linh giác của Thiết Giác tê trong tông môn biến mất không rõ tung tích.","theLucLienQuan":["Minh Kiếm tông"],"nguon":["@c0927"]},{"id":"khai-long-phu","name":"Khai Long Phủ","cn":"","capDo":"khac","parentId":"phong-chau","blurb":"Địa điểm thuộc Phong Châu, nơi Minh Kiếm tông bị mất Linh giác Thiết Giác tê.","detail":"Khai Long Phủ là nơi có Minh Kiếm tông. Tại đây, trong chuỗi biến cố ở Đại Tấn nam bộ, tông môn này xảy ra vụ mất trộm tài liệu cất giữ trong nội bộ.","theLucLienQuan":["Minh Kiếm tông"],"nguon":["@c0927"]},{"id":"khuc-quan","name":"Khúc quận","cn":"","capDo":"khac","parentId":"dai-tan-nam-bo","blurb":"Quận có Tông Bình thế gia, nơi đại hán xấu xí Nguyên Anh trung kỳ ép đổi Ngũ Quang mộc.","detail":"Khúc quận là địa bàn của Tông Bình thế gia, được gọi là đệ nhất thế gia trong quận. Tại đây, đại hán xấu xí Nguyên Anh trung kỳ dùng thần thông áp chế hai trưởng lão Nguyên Anh, buộc gia chủ giao Ngũ Quang mộc.","theLucLienQuan":["Tông Bình thế gia"],"nguon":["@c0927"]},{"id":"lung-chau","name":"Lũng châu","cn":"","capDo":"chau","parentId":"dai-tan","blurb":"Đại châu biên giới phía tây Đại Tấn, địa hình nhiều núi cao, chướng khí, độc xà và độc trùng. Toàn châu gần như do Nhạc Dương Cung và Ma Mộc Tông cùng khống chế.","detail":"Lũng châu là vùng biên giới phía tây Đại Tấn, nổi bật bởi địa thế hiểm trở và môi trường độc hại. Cục diện tu tiên tại đây do hai thế lực mạnh là Nhạc Dương Cung và Ma Mộc Tông nắm giữ, các tông phái nhỏ bản xứ khó tạo uy hiếp và thường phải nương nhờ họ.","theLucLienQuan":["Nhạc Dương Cung","Ma Mộc Tông","Các tông phái nhỏ bản xứ Lũng châu"],"nguon":["@c0928","@c0932"]},{"id":"thien-nhac-son-mach","name":"Thiên Nhạc sơn mạch","cn":"","capDo":"vuc","parentId":"lung-chau","blurb":"Sơn mạch vùng Tây Xuyên, phương viên hơn mười vạn dặm. Đây là địa bàn đặt Nhạc Dương Cung và là khu vực Hàn Lập bí mật tìm nơi bố trí cạm bẫy.","detail":"Thiên Nhạc sơn mạch nằm tại Tây Xuyên thuộc Lũng châu, có quy mô rộng lớn. Nhạc Dương Cung đặt trung tâm tại Nam Thiên Phong trong sơn mạch, còn Hàn Lập tiếp cận rìa khu vực này để tìm cơ hội phục kích Hạo Dương Điểu nhỏ.","theLucLienQuan":["Nhạc Dương Cung"],"nguon":["@c0928"]},{"id":"tay-xuyen","name":"Tây Xuyên","cn":"","capDo":"vuc","parentId":"lung-chau","blurb":"Khu vực trong Lũng châu nơi có Thiên Nhạc sơn mạch. Nhạc Dương Cung tọa lạc tại đây.","detail":"Tây Xuyên được nhắc như vùng đặt Thiên Nhạc sơn mạch, địa bàn trọng yếu của Nhạc Dương Cung tại Lũng châu. Sự kiện Hàn Lập tiếp cận Nhạc Dương Cung diễn ra trong phạm vi khu vực này.","theLucLienQuan":["Nhạc Dương Cung"],"nguon":["@c0928"]},{"id":"nam-thien-phong","name":"Nam Thiên Phong","cn":"","capDo":"khac","parentId":"thien-nhac-son-mach","blurb":"Ngọn núi trung tâm Thiên Nhạc sơn mạch, nơi đặt Nhạc Dương Cung. Núi được bảo vệ bởi đại trận mười ba tầng cấm đoạn từ trong ra ngoài.","detail":"Nam Thiên Phong là trung tâm phòng ngự của Nhạc Dương Cung. Với mấy vạn đệ tử quanh vùng và đại trận nhiều tầng, nơi này được mô tả như khu vực phòng thủ kiên cố, khiến Hàn Lập không chọn xâm nhập trực diện.","theLucLienQuan":["Nhạc Dương Cung"],"nguon":["@c0928"]},{"id":"son-coc-rung-dao","name":"Sơn cốc rừng đào","cn":"","capDo":"khac","parentId":"thien-nhac-son-mach","blurb":"Sơn cốc hẻo lánh có rừng đào màu phấn hồng. Hàn Lập chọn nơi này làm trận địa đặt bẫy Hạo Dương Điểu nhỏ.","detail":"Sau hai ngày tìm kiếm quanh khu vực, Hàn Lập phát hiện sơn cốc rừng đào không có tu sĩ Nhạc Dương Cung ở gần. Hắn xác định nơi này thích hợp để bố trí trận pháp, bày nhiều lớp trận kỳ và ngồi nhập định chờ thời cơ.","theLucLienQuan":["Nhạc Dương Cung"],"nguon":["@c0928"]},{"id":"bo-bien-vung-dong-bo-dai-tan","name":"Bờ biển vùng đông bộ Đại Tấn","cn":"","capDo":"vuc","parentId":"dai-tan","blurb":"Khu vực ven biển phía đông Đại Tấn được nhắc có ác giao lên bờ cắn nuốt tu sĩ. Hàn Lập dự định tới đây sau Tấn Kinh để tìm vật liệu liên quan Xích Hỏa giao.","detail":"Bờ biển vùng đông bộ Đại Tấn là điểm đến dự kiến trong lộ trình tiếp theo của Hàn Lập. Vì có tin ác giao xuất hiện, hắn muốn thử tìm vật liệu thuộc tính hỏa để phục vụ việc luyện chế Tam Diễm Phiến.","theLucLienQuan":[],"nguon":["@c0928"]},{"id":"rung-dao-trong-son-coc-bi-an","name":"Rừng đào trong sơn cốc bí ẩn","cn":"","capDo":"khac","parentId":"thien-nhac-son-mach","blurb":"Rừng đào trong sơn cốc bí ẩn là nơi Hàn Lập bố trí mồi nhử bằng Nghê Thường thảo, san hô hồng và ảo trận. Cuối chương, cả hỏa cầu đỏ và khối sáng vàng đều lao về hướng nơi này.","detail":"Hàn Lập dùng rừng đào trong sơn cốc làm địa điểm dụ Hạo Dương điểu, đặt linh thảo trên san hô, dùng cấm chế chặn yêu thú cấp thấp và khởi động ảo trận ngoài cùng khi mục tiêu sắp tới. Đây trở thành điểm hội tụ của thú triều, Hạo Dương điểu và một luồng tồn tại lớn khác.","theLucLienQuan":["Hàn Lập","Nhạc Dương cung"],"nguon":["@c0929"]},{"id":"phia-bac-thien-nhac-son-mach","name":"Phía bắc Thiên Nhạc sơn mạch","cn":"","capDo":"khac","parentId":"thien-nhac-son-mach","blurb":"Phía bắc Thiên Nhạc sơn mạch là nơi các đệ tử cấp thấp Nhạc Dương cung cố ghì giữ linh cầm bị kích động. Khu vực này cho thấy phạm vi ảnh hưởng của Dụ yêu thảo lan rộng trong sơn mạch.","detail":"Tại phía bắc Thiên Nhạc sơn mạch, vài đệ tử cấp thấp Nhạc Dương cung dùng dây cương bạc giữ những con chim lạ đang muốn đổi hướng bay về cùng một phía.","theLucLienQuan":["Nhạc Dương cung"],"nguon":["@c0929"]},{"id":"hang-dong-bi-an-ben-ria-son-mach","name":"Hang động bí ẩn bên rìa sơn mạch","cn":"","capDo":"khac","parentId":"thien-nhac-son-mach","blurb":"Hang động bí ẩn bên rìa Thiên Nhạc sơn mạch là nơi Mã đạo hữu Ma Mộc tông ghì giữ nhện đen trưởng thành. Nơi này cũng bị ảnh hưởng bởi làn sóng náo loạn linh thú do Dụ yêu thảo gây ra.","detail":"Trong hang động bí ẩn ở rìa Thiên Nhạc sơn mạch, một tu sĩ che mặt mặc phục sức vàng xanh dùng bàn tay lục quang áp chế con nhện đen trưởng thành đang nổi giận.","theLucLienQuan":["Ma Mộc Tông"],"nguon":["@c0929"]},{"id":"dao-lam","name":"Đào lâm","cn":"","capDo":"khac","parentId":"son-coc-rung-dao","blurb":"Đào lâm là khu rừng đào đỏ rực trong sơn cốc nơi Hạo Dương điểu bị Hàn Lập chế trụ.","detail":"Trong khu rừng đào, Hạo Dương điểu bị lưới điện màu vàng trói trên không, sau đó nằm hôn mê dưới một gốc đào sau khi bị lấy lông đuôi. Đây cũng là hiện trường khiến người Nhạc Dương cung truy tới kiểm tra.","theLucLienQuan":["Nhạc Dương cung bí điện"],"nguon":["@c0930"]},{"id":"day-nui-tru-da-ngoai-tram-dam","name":"Dãy núi trụ đá ngoài trăm dặm","cn":"","capDo":"khac","parentId":"thien-nhac-son-mach","blurb":"Dãy núi trụ đá ngoài trăm dặm là nơi tử bào lão ẩu truy dấu tới sau biến cố Hạo Dương điểu.","detail":"Sau khi dùng thần thức dò tìm manh mối, tử bào lão ẩu rời sơn cốc và đuổi tới khu vực trụ đá ngoài trăm dặm. Tại đây bà gặp tu sĩ che mặt họ Mã của Ma Mộc tông và chất vấn hắn.","theLucLienQuan":["Nhạc Dương cung bí điện","Ma Mộc Tông"],"nguon":["@c0930"]},{"id":"hoang-le-son","name":"Hoàng Lê sơn","cn":"","capDo":"khac","parentId":"dai-tan","blurb":"Hoàng Lê sơn là phủ thành nơi Mã đạo hữu phát hiện Thổ Giáp Long trước khi truy đuổi đến Thiên Nhạc sơn mạch.","detail":"Mã đạo hữu nói ông phát hiện Thổ Giáp Long cấp bảy tại phủ thành Hoàng Lê sơn rồi truy đuổi suốt sáu ngày sáu đêm đến khu vực Thiên Nhạc sơn mạch. Địa danh này là điểm khởi đầu của tuyến truy bắt Thổ Giáp Long trong chương.","theLucLienQuan":["Ma Mộc Tông"],"nguon":["@c0931"]},{"id":"than-moc-nhai","name":"Thần Mộc nhai","cn":"","capDo":"khac","parentId":"lung-chau","blurb":"Thần Mộc nhai là địa bàn gắn với tông môn của Mã đạo hữu. Tôn lão ẩu nhắc nơi này khi cảnh cáo ông không nên lưu lại Thiên Nhạc sơn mạch.","detail":"Trong cuộc đối thoại với Mã đạo hữu, Tôn lão ẩu dùng Thần Mộc nhai để nhấn mạnh Thiên Nhạc sơn mạch không phải địa bàn của phe ông. Địa danh này cho thấy ranh giới thế lực giữa Nhạc Dương cung và Ma Mộc Tông tại Lũng châu.","theLucLienQuan":["Ma Mộc Tông"],"nguon":["@c0931"]},{"id":"thach-that-trong-bung-nui-vo-danh","name":"Thạch thất trong bụng núi vô danh","cn":"","capDo":"khac","parentId":"lung-chau","blurb":"Thạch thất trong bụng núi vô danh là nơi Hàn Lập tạm ẩn sau khi rời Thiên Nhạc sơn mạch. Tại đây hắn kiểm kê chiến lợi phẩm và bắt đầu xử lý Hỏa linh.","detail":"Hàn Lập mở một thạch thất trong bụng một ngọn núi vô danh để tạm thời trú ẩn. Trong thạch thất, hắn bàn với Đại Diễn Thần Quân về thu hoạch Hỏa linh, Thổ Giáp Long, Tấn kinh và đại hội đấu giá, rồi dùng anh hỏa luyện Hỏa linh.","theLucLienQuan":["Hàn Lập"],"nguon":["@c0931"]},{"id":"kim-giang-quan","name":"Kim giang quận","cn":"","capDo":"khac","parentId":"dai-tan","blurb":"Kim giang quận là khu vực phụ cận Tấn kinh nơi Hàn Lập giảm độn quang Ngự phong xa. Tại đây hắn thu liễm khí tức về mức Kết Đan để tránh gây chú ý.","detail":"Sau hơn một tháng phi độn, Hàn Lập tiến vào Kim giang quận gần Tấn kinh. Vì khu vực trung tâm Đại Tấn có thể có nhiều tu sĩ cao giai, hắn giảm tốc và che giấu phần lớn tu vi.","theLucLienQuan":["Quan phủ Đại Tấn quốc"],"nguon":["@c0932"]},{"id":"quan-dao-vao-tan-kinh","name":"Quan đạo vào Tấn kinh","cn":"","capDo":"khac","parentId":"kinh-thanh","blurb":"Quan đạo vào Tấn kinh là tuyến đường phàm tục Hàn Lập chọn sau khi mua xe ngựa. Trên đường này hắn gặp thương đội, tu sĩ cấp thấp cưỡi ngựa và đoàn kỵ binh giáp bạc.","detail":"Do quanh Tấn kinh có quy định ngầm cấm phi hành và đánh nhau, Hàn Lập đi bằng xe ngựa theo quan đạo. Tại đây hắn gặp đoàn kỵ binh giáp bạc mang cờ chữ Vương cùng xe bích ngọc có tu sĩ bên trong.","theLucLienQuan":["Đội kỵ binh giáp bạc dưới cờ chữ Vương","Quan phủ Đại Tấn quốc"],"nguon":["@c0932"]},{"id":"nga-ba-duong-co-rung-cay-va-hang-nuoc","name":"Ngã ba đường có rừng cây và hàng nước","cn":"","capDo":"khac","parentId":"quan-dao-vao-tan-kinh","blurb":"Ngã ba đường có rừng cây và hàng nước là điểm dừng chân trên đường vào Tấn kinh. Tại đây Hàn Lập được binh sĩ giáp bạc mời vào gặp Tào Mộng Dung.","detail":"Sau khi đi thêm khoảng mười dặm, Hàn Lập tới ngã ba có hàng nước và rừng cây bên cạnh. Đoàn kỵ binh giáp bạc nghỉ lại ở đây, xe bích ngọc đã trống và Tào Mộng Dung sai người mời Hàn Lập vào hàng trà.","theLucLienQuan":["Đội kỵ binh giáp bạc dưới cờ chữ Vương"],"nguon":["@c0932"]},{"id":"nam-cuong-dai-tan","name":"Nam Cương Đại Tấn","cn":"","capDo":"khac","parentId":"dai-tan","blurb":"Nam Cương Đại Tấn là địa bàn đóng quân của Trụ Nam tướng quân. Ông từ nơi này phụng mệnh về Tấn kinh có việc.","detail":"Tào Mộng Dung giới thiệu Trụ Nam tướng quân là bá phụ của Vương tiểu thư và đang đóng quân tại Nam Cương Đại Tấn. Chuyến đi của ông cùng đội kỵ binh giáp bạc là để phụng mệnh về kinh.","theLucLienQuan":["Quan phủ Đại Tấn quốc","Đội kỵ binh giáp bạc dưới cờ chữ Vương"],"nguon":["@c0932"]},{"id":"quan-tra-ven-duong","name":"Quán trà ven đường","cn":"","capDo":"khac","parentId":"dai-tan","blurb":"Quán trà ven đường là nơi Hàn Lập gặp Trụ Nam tướng quân, Vương tiểu thư và Tào Mộng Dung. Tại đây bổn mạng phi kiếm của Hàn Lập phát tiếng, khiến hắn vội bay đi.","detail":"Hàn Lập cùng Trụ Nam tướng quân, Vương tiểu thư và Tào Mộng Dung ngồi trò chuyện trong quán trà ven đường trước khi biến cố kiếm minh xảy ra. Sau khi Hàn Lập hóa thành ánh sáng bay đi, người quanh quán trà xôn xao vì chứng kiến tiên sư phi thiên.","theLucLienQuan":["Triều đình Đại Tấn","Phủ Trụ Nam tướng quân"],"nguon":["@c0933"]},{"id":"con-ngo-tien-son","name":"Côn Ngô tiên sơn","cn":"","capDo":"khac","parentId":"nhan-gioi","blurb":"Côn Ngô tiên sơn là địa danh truyền thuyết được Trụ Nam tướng quân hỏi Hàn Lập. Nó được nhắc như nơi trú ngụ của thiên thượng chân tiên trong cổ truyền.","detail":"Trong cuộc trò chuyện về cổ thư và truyền thuyết, Trụ Nam tướng quân hỏi Hàn Lập về Côn Ngô tiên sơn, nơi được truyền rằng từng có thiên thượng chân tiên trú ngụ. Câu hỏi bị cắt ngang bởi tiếng kiếm minh trong cơ thể Hàn Lập.","theLucLienQuan":[],"nguon":["@c0933"]},{"id":"tuu-lau-phung-gia-o-tan-kinh","name":"Tửu lâu Phùng gia ở Tấn kinh","cn":"","capDo":"khac","parentId":"kinh-thanh","blurb":"Tửu lâu Phùng gia ở Tấn kinh là nơi Hàn Lập dùng ngọc bội chữ Phùng để gặp Phùng Thuyên. Đây là đầu mối thế tục hắn chọn thay vì tìm Trụ Nam tướng quân.","detail":"Hàn Lập tới tửu lâu của Phùng gia trong Tấn kinh, đưa ngọc bội khắc chữ Phùng để chưởng quỹ nhận thân phận Đại công tử, rồi yêu cầu tìm nơi ở yên tĩnh, kín đáo, tránh người ngoài chú ý.","theLucLienQuan":["Phùng gia"],"nguon":["@c0934"]},{"id":"can-nha-heo-lanh-trong-tan-kinh","name":"Căn nhà hẻo lánh trong Tấn kinh","cn":"","capDo":"khac","parentId":"kinh-thanh","blurb":"Căn nhà hẻo lánh trong Tấn kinh là nơi Phùng Thuyên dẫn Hàn Lập tới với danh nghĩa chỗ ở tạm. Thực chất nơi này có cấm chế, hoàng vụ và tu sĩ mai phục.","detail":"Phùng Thuyên nói căn nhà thuộc người quen cũ đã đi xa nhiều năm, thích hợp làm nơi ở kín đáo cho Hàn Lập. Khi tới trước sân, Hàn Lập vạch trần ý định trốn vào cấm chế và sai đồng bọn bắt mình, khiến cuộc phục kích lộ rõ.","theLucLienQuan":["Phùng gia"],"nguon":["@c0934"]},{"id":"tuu-lau","name":"Tửu lâu","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Tửu lâu là nơi Hàn Lập nhận ra liễm thức thuật kém của lão gù và bắt đầu nghi ngờ Phùng chưởng quỹ có vấn đề. Hắn không ra tay ngay tại đó vì nơi này đông người.","detail":"Trong ký ức và suy xét của Hàn Lập, lão gù từng để lộ sơ hở tại tửu lâu do liễm thức thuật kém. Hàn Lập khi đó đã đoán Phùng chưởng quỹ có vấn đề nhưng không tiện ra tay ngay giữa nơi đông người.","theLucLienQuan":["Khổng gia","Phùng gia"],"nguon":["@c0935"]},{"id":"ngon-nui-to-chuc-tham-vuong-dai-hoi","name":"Ngọn núi tổ chức Tham vương đại hội","cn":"","capDo":"khac","parentId":"tuyet-lang-son","blurb":"Ngọn núi tổ chức Tham vương đại hội là nơi thành viên ba nhà bị quỷ trận của Huyễn vương vây khốn. Họ phải dựa vào đại trận trên núi để miễn cưỡng tự bảo vệ.","detail":"Sau biến cố lão tổ Khổng gia, Huyễn vương lập quỷ trận vây phạm vi hơn trăm dặm quanh ngọn núi tổ chức Tham vương đại hội. Thành viên ba nhà bị vây hơn một tháng, đến khi cao thủ Nguyên Anh ở phụ cận đánh lui tam thi mới thoát nạn.","theLucLienQuan":["Ba nhà quản lý Tham vương đại hội","Tam thi / phe Huyễn vương"],"nguon":["@c0935"]},{"id":"dao-quan-hoac-tu-mieu-o-tan-kinh","name":"Đạo quan hoặc tự miếu ở Tấn kinh","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Đạo quan hoặc tự miếu ở Tấn kinh là kiểu chỗ ở mới Hàn Lập cân nhắc thuê sau khi quyết định rời căn nhà hiện tại. Lựa chọn này nhằm tránh dây dưa với Phùng chưởng quỹ và tiếp tục nghe ngóng tình hình tu tiên.","detail":"Sau khi biết nơi ở hiện tại có liên hệ với Phùng chưởng quỹ, Hàn Lập cho rằng không thể ở lâu. Hắn dự tính tìm một đạo quan hoặc tự miếu để thuê, vừa kín đáo hơn vừa thuận tiện nghe ngóng tin tức tu tiên ở Tấn kinh.","theLucLienQuan":[],"nguon":["@c0935"]},{"id":"thu-vien-trong-tan-kinh","name":"Thư viện trong Tấn kinh","cn":"","capDo":"khac","parentId":"kinh-thanh","blurb":"Thư viện trong Tấn kinh nơi Hàn Lập phát hiện khí tức tu sĩ sau khi rời đạo quan. Tại đây hắn gặp lão nho áo trắng để hỏi tin phường thị và đại đấu giá hội.","detail":"Thư viện trong Tấn kinh là địa điểm có khí tức tu sĩ mà Hàn Lập phát hiện vào sáng hôm sau sau khi ở tạm đạo quan phàm nhân. Bên trong có lão nho áo trắng liên hệ Nho môn, người bị Hàn Lập dùng khí tức Nguyên Anh kỳ áp chế để cung cấp bản đồ phường thị và tin đấu giá.","theLucLienQuan":["Nho môn"],"nguon":["@c0936"]},{"id":"tay-tan-phuong-thi","name":"Tây Tấn phường thị","cn":"","capDo":"khac","parentId":"kinh-thanh","blurb":"Phường thị tu tiên nằm phía tây Tấn kinh, được pháp trận ẩn giấu. Đây là nơi có nhiều thương hào, hàng trăm tu sĩ qua lại và sắp tổ chức đại đấu giá hội tại Bảo Quang Điện.","detail":"Tây Tấn phường thị là khu phố tu tiên ẩn trong một khu đường phố hẻo lánh phía tây Tấn kinh, được che bởi pháp trận ẩn dấu cao minh. Hàn Lập thông qua cấm chế đi vào, thấy bên trong có mấy trăm tu sĩ, nhiều cửa hàng lớn và các thương hào như Thiên Cơ Các; đại đấu giá hội sau chín ngày cũng diễn ra tại đây.","theLucLienQuan":["Thiên Cơ Các","Các phường thị Đại Tấn liên hợp"],"nguon":["@c0936"]},{"id":"bao-quang-dien","name":"Bảo Quang Điện","cn":"","aliases":["Quang Bảo Điện"],"capDo":"khac","parentId":"tay-tan-phuong-thi","blurb":"Địa điểm trong Tây Tấn phường thị nơi đại đấu giá hội sẽ được tổ chức sau chín ngày. Chương ghi cả hai cách gọi Bảo Quang Điện và Quang Bảo Điện trong cùng ngữ cảnh đấu giá.","detail":"Bảo Quang Điện là nơi lão nho áo trắng cho biết đại đấu giá hội sẽ cử hành sau chín ngày tại Tây Tấn phường thị. Phiên đấu giá tại đây chia theo cấp Kết Đan và Nguyên Anh, thường kéo dài năm sáu ngày.","theLucLienQuan":["Các phường thị Đại Tấn liên hợp"],"nguon":["@c0936","@c0947"]},{"id":"thien-co-cac-tai-tay-tan-phuong-thi","name":"Thiên Cơ Các tại Tây Tấn phường thị","cn":"","capDo":"khac","parentId":"tay-tan-phuong-thi","blurb":"Tòa lầu ba tầng lớn trong Tây Tấn phường thị, nơi Hàn Lập vào hỏi mua tài liệu hiếm. Đây là điểm giao dịch tiết lộ tin về khối nhỏ Lôi Linh thạch.","detail":"Thiên Cơ Các tại Tây Tấn phường thị lớn hơn các thương hào xung quanh, tầng một có sai vặt Luyện Khí kỳ, tầng ba dùng tiếp đãi khách cao giai. Hàn Lập chọn nơi này vì cần một cửa hàng đủ thế lực để mua bán lượng lớn và chuẩn bị linh thạch cho đại đấu giá hội.","theLucLienQuan":["Thiên Cơ Các"],"nguon":["@c0936"]},{"id":"hai-ngoai","name":"Hải ngoại","cn":"","capDo":"vuc","parentId":null,"blurb":"Hải ngoại là lai lịch Hàn Lập đưa ra khi bị Phú tiền bối thăm dò thân phận. Hắn nói mình thường tu luyện trên một hòn đảo nhỏ ngoài hải ngoại và rất ít đặt chân vào Đại Tấn.","detail":"Trong cuộc trò chuyện tại Thiên Cơ các, Hàn Lập dùng thân phận tu sĩ hải ngoại để giải thích vì sao một Nguyên Anh trung kỳ như mình ít được biết tới ở Đại Tấn. Lời giải thích này khiến Phú tiền bối tin quá nửa và suy đoán hắn đến Tấn kinh vì hội đấu giá.","theLucLienQuan":[],"nguon":["@c0937"]},{"id":"giao-dich-hoi-duoi-long-dat","name":"Giao dịch hội dưới lòng đất","cn":"","capDo":"khac","parentId":"kinh-thanh","blurb":"Tuyến giao dịch Ám trong đấu giá hội Tấn Kinh mười năm một lần. Hội do ma đạo tà tông chủ trì, không công khai cho tu sĩ ngoài biết và có nhiều vật phẩm cấm cùng tài liệu quý hiếm.","detail":"Lão Phú truyền âm cho Hàn Lập biết giao dịch hội dưới lòng đất là nơi khó vào với tu sĩ hải ngoại tán tu, nhưng có khả năng tìm được tài liệu mà đấu giá công khai không có. Giao dịch ở đây thường dùng hình thức lấy vật đổi vật.","theLucLienQuan":["Ma đạo tà tông"],"nguon":["@c0938"]},{"id":"phuong-thi-chinh-dao-giao-dich-hoi-minh","name":"Phường thị chính đạo / giao dịch hội Minh","cn":"","capDo":"khac","parentId":"kinh-thanh","blurb":"Tuyến giao dịch công khai trong đấu giá hội Tấn Kinh. Hội do chính đạo duy trì và chủ yếu dành cho tu sĩ bình thường.","detail":"Trong lời lão Phú, đấu giá hội Tấn Kinh chia thành Nhất Minh và Nhất Ám; hội Minh là phường thị do chính đạo duy trì, mức độ công khai cao hơn hội dưới lòng đất.","theLucLienQuan":["Chính đạo"],"nguon":["@c0938"]},{"id":"gioi-tu-khong-gian-cua-thien-co-cac","name":"Giới tử không gian của Thiên Cơ các","cn":"","capDo":"khac","parentId":"thien-co-cac-tai-tay-tan-phuong-thi","blurb":"Không gian tư nhân đặc chế của Thiên Cơ các. Vương trưởng lão muốn dẫn Hàn Lập vào đây để xem Thiên Cơ phủ.","detail":"Giới tử không gian được tạo nhờ bí thuật luyện vết nứt không gian thành tư nhân không gian. Vương trưởng lão nói đây là bí thuật Đại Tấn mới nghiên cứu ra gần ngàn năm, nên Hàn Lập với thân phận hải ngoại không biết cũng là chuyện bình thường.","theLucLienQuan":["Thiên Cơ Các"],"nguon":["@c0938"]},{"id":"thien-nam-tu-tien-gioi","name":"Thiên Nam tu tiên giới","cn":"","capDo":"vuc","parentId":"thien-nam","blurb":"Khu vực tu tiên ở Thiên Nam, nơi Hàn Lập từng biết quan niệm rằng không gian bí thuật cao cấp khó xuất hiện tại nhân giới. Chương này được dùng làm đối chiếu với kiến thức về giới tử không gian của Đại Tấn.","detail":"Khi nghe Vương trưởng lão nói có thể luyện chế khe hở không gian thành giới tử không gian, Hàn Lập nhớ tới nhận thức phổ biến tại Thiên Nam rằng không gian bí thuật cao cấp rất khó xuất hiện ở nhân giới, còn túi trữ vật chỉ là ứng dụng không gian thông thường.","theLucLienQuan":[],"nguon":["@c0939"]},{"id":"tan-tay-phuong-thi","name":"Tấn Tây phường thị","cn":"","capDo":"khac","parentId":"dai-tan","blurb":"Tấn Tây phường thị là nơi Hàn Lập đối đầu nhóm Âm La Tông và Thiên Lan thánh nữ trong chương này. Phường thị có quy củ nghiêm cấm tu sĩ động thủ, được các thế lực Phật Đạo đứng sau bảo hộ.","detail":"Trong Tấn Tây phường thị, Hàn Lập dùng lệnh cấm đấu pháp và nguy cơ bị các thế lực hậu thuẫn truy sát để kiềm chế nhóm Cát Thiên Hào và Lâm Ngân Bình. Ô Ích cùng tăng nhân xấu xí xuất hiện tại đây để giữ quy củ, nhưng họ chỉ quản chuyện đấu pháp bên trong phường thị.","theLucLienQuan":["Tứ đại phật tông và tam đại đạo môn","Âm La Tông","Thiên Lan thánh điện","Chân Cực môn"],"nguon":["@c0941"]},{"id":"thach-dien-tan-tay-phuong-thi","name":"Thạch điện","cn":"","capDo":"khac","parentId":"tan-tay-phuong-thi","blurb":"Thạch điện là khu vực trong Tấn Tây phường thị nơi cao giai tu sĩ đối đầu. Khi nguy cơ giao chiến xuất hiện, các tu sĩ cấp thấp né tránh và một số lầu các mở cấm chế phòng hộ.","detail":"Tại thạch điện, khí thế đối đầu giữa Hàn Lập, Cát Thiên Hào và Lâm Ngân Bình khiến tu sĩ Trúc Cơ, Kết Đan xung quanh sợ bị vạ lây. Từ một lầu các trong khu vực này, Ô Ích và tăng nhân xấu xí bay ra can thiệp.","theLucLienQuan":["Tứ đại phật tông và tam đại đạo môn","Chân Cực môn"],"nguon":["@c0941"]},{"id":"khu-cho-tan-kinh","name":"Khu chợ","cn":"","capDo":"khac","parentId":"kinh-thanh","blurb":"Khu chợ tại Tấn kinh nơi Hàn Lập bị Thiên Lan thánh nữ và nhóm Âm La Tông nghi ngờ bao đồ. Tại đây hắn lấy trường đao kim sắc ra, đòi ngọc bội hồ điệp rồi rời đi.","detail":"Khu chợ là nơi diễn ra màn đối chất giữa Hàn Lập, Lâm Ngân Bình, Cát Thiên Hào và các tu sĩ đi cùng. Sau khi mở bao để lộ trường đao kim sắc, Hàn Lập lấy ngọc bội của Lâm Ngân Bình làm bồi thường và rời khỏi nơi này dưới thân phận Lệ Phi Vũ tán tu Hải ngoại.","theLucLienQuan":["Thiên Lan","Âm La Tông"],"nguon":["@c0942"]},{"id":"san-bo-hoang-trong-ngo-hem","name":"Sân bỏ hoang trong ngõ hẻm","cn":"","capDo":"khac","parentId":"kinh-thanh","blurb":"Nơi Hàn Lập cố ý dẫn kẻ bám theo tới sau khi rời khu chợ. Tại đây lão giả áo xanh khô gầy hiện thân và đề nghị giao dịch.","detail":"Sau khi hòa vào đường phố, Hàn Lập đổi hướng vào một ngõ hẻm và dừng lại tại sân bỏ hoang. Hắn vạch trần kẻ dùng quỷ ảnh độn theo dõi mình, buộc lão giả áo xanh hiện thân nói rõ mục đích giao dịch.","theLucLienQuan":[],"nguon":["@c0942"]},{"id":"tan-kinh","name":"Tấn Kinh","cn":"","capDo":"thanh","parentId":null,"blurb":"Tấn Kinh là nơi tiểu lão đầu uy hiếp Hàn Lập và cũng là bối cảnh của vụ diệt khẩu trong chương này. Thành đang có nhiều tu sĩ cấp cao tụ tập vì đấu giá đại hội.","detail":"Tiểu lão đầu dựa vào hoàn cảnh Tấn Kinh đông tu sĩ cấp cao để tự tin rằng Hàn Lập khó giết người rồi thoát thân. Sau khi Hàn Lập ra tay diệt khẩu và hủy dấu vết, nhóm Lâm Ngân Bình, Cát Thiên Hào cùng nam tu sĩ Kết Đan vẫn lần tới hiện trường trong khu vực này.","theLucLienQuan":["Âm La Tông","Thiên Lan"],"nguon":["@c0943"]},{"id":"dai-hoi-dau-gia","name":"Đại hội đấu giá","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Sự kiện tại Tấn Kinh mà Hàn Lập vẫn quyết tham dự để tìm tài liệu cần thiết. Cát Thiên Hào cũng đoán Hàn Lập sẽ đến đây nên dùng nó làm điểm dự liệu truy tìm.","detail":"Đại hội đấu giá là nơi Hàn Lập coi là con đường duy nhất để tìm tài liệu cần thiết cho việc luyện chế khôi lỗi. Phía Âm La Tông dự đoán hắn sẽ dự hội nên triệu tập lực lượng trong Tấn Kinh và chuẩn bị truy tìm, phục kích.","theLucLienQuan":["Âm La Tông","Thiên Lan Thánh Điện"],"nguon":["@c0944"]},{"id":"tay-bac-dai-tan","name":"Tây Bắc Đại Tấn","cn":"","capDo":"vuc","parentId":"dai-tan","blurb":"Khu vực ở phía tây bắc Đại Tấn, nơi đặt Bắc Dạ Tiểu Cực Cung theo lời Đại Diễn Thần Quân. Nơi này gắn với manh mối Hàn tuỷ.","detail":"Đại Diễn Thần Quân nói Hàn tuỷ chỉ nghe có tại Bắc Dạ Tiểu Cực Cung ở Tây Bắc Đại Tấn. Khu vực này vì vậy trở thành địa danh liên quan trực tiếp đến nguồn gốc Hàn tuỷ và Huyền Ngọc vạn năm.","theLucLienQuan":["Bắc Dạ Tiểu Cực Cung"],"nguon":["@c0944"]},{"id":"bac-minh-dao","name":"Bắc Minh Đảo","cn":"","aliases":["Bắc Minh Băng Đảo"],"capDo":"khac","parentId":"dai-tan","blurb":"Đảo băng ở Đại Tấn, địa bàn của Bắc Dạ Tiểu Cực Cung. Nơi đây có dấu hiệu bông tuyết trên bình Hàn tuỷ và thường bị yêu thú cấp cao công kích vì Hàn tuỷ.","detail":"Bắc Minh Đảo nằm trên hàn nhãn Thiên Nguyên Âm Mạch, khiến khí băng hàn bao phủ vạn dặm xung quanh. Nhờ địa thế này và các cấm đoạn đại trận thượng cổ, Tiểu Cực Cung nhiều lần chống được yêu thú cấp cao Đại Tấn tấn công.","theLucLienQuan":["Bắc Dạ Tiểu Cực Cung","Vạn Yêu Cốc"],"nguon":["@c0945"]},{"id":"thien-nguyen-am-mach","name":"Thiên Nguyên Âm Mạch","cn":"","aliases":[],"capDo":"khac","parentId":"bac-minh-dao","blurb":"Hàn nhãn dưới Bắc Minh Đảo, tạo nên khí băng hàn khắc nghiệt quanh khu vực. Đây là một trong các lợi thế phòng thủ của Bắc Dạ Tiểu Cực Cung.","detail":"Thiên Nguyên Âm Mạch khiến vạn dặm quanh Bắc Minh Đảo bị khí băng hàn bao trùm. Yêu thú không tu công pháp hàn thuộc tính khi xâm nhập phải hao tổn hơn phân nửa linh lực để chống lạnh, vì vậy khó phá Tiểu Cực Cung.","theLucLienQuan":["Bắc Dạ Tiểu Cực Cung"],"nguon":["@c0945"]},{"id":"dao-quan-noi-han-lap-tru-lai","name":"Đạo quán nơi Hàn Lập trú lại","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Đạo quán tại Tấn kinh nơi Hàn Lập tạm ở trong lúc chờ đại hội đấu giá. Tại đây hắn luyện lại Tuyết Tinh Châu bằng hàn tủy và anh hỏa.","detail":"Hàn Lập ở trong phòng của đạo quán một ngày một đêm. Lão quán chủ mơ hồ đoán được thân phận tu tiên của hắn nên tránh cho người khác quấy rầy, giúp hắn có thời gian thử Tử La Cực Hỏa và tái luyện Tuyết Tinh Châu.","theLucLienQuan":[],"nguon":["@c0946"]},{"id":"phu-de-nghiep-gia-o-goc-bac-kinh-thanh","name":"Phủ đệ Nghiệp gia ở góc bắc kinh thành","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Phủ đệ khí thế hùng vĩ của Nghiệp gia ở góc bắc Tấn kinh. Đây là nơi Hàn trưởng lão gặp Vân Dật và các trưởng lão Nghiệp gia bàn kế hoạch.","detail":"Trong phủ đệ Nghiệp gia, Hàn trưởng lão đứng ở thạch đình nhận tin từ Vân Dật về việc Âm La tông truy tìm Hàn Lập. Ở một lầu gác khác trong phủ, Vân Dật, nhị trưởng lão và phụ nhân họp kín để đánh giá Hàn trưởng lão, Hàn Lập và kế hoạch mua vật liệu ở đại hội đấu giá.","theLucLienQuan":["Nghiệp gia","Hoàng tộc Đại Tấn"],"nguon":["@c0946"]},{"id":"thach-dinh-trong-hoa-vien-phu-nghiep-gia","name":"Thạch đình trong hoa viên phủ Nghiệp gia","cn":"","capDo":"khac","parentId":"phu-de-nghiep-gia-o-goc-bac-kinh-thanh","blurb":"Thạch đình trong hoa viên phủ Nghiệp gia, nơi Hàn trưởng lão tiếp Vân Dật. Tại đây hắn nhận bạch ngọc giản chứa bức họa Hàn Lập.","detail":"Hàn trưởng lão đứng trong thạch đình ngắm hoa cỏ thì Vân Dật đến báo tin. Cuộc gặp tại đây mở ra việc Nghiệp gia phát hiện Âm La tông đang âm thầm truy tìm Hàn Lập.","theLucLienQuan":["Nghiệp gia"],"nguon":["@c0946"]},{"id":"lau-gac-vang-ve-trong-phu-nghiep-gia","name":"Lầu gác vắng vẻ trong phủ Nghiệp gia","cn":"","capDo":"khac","parentId":"phu-de-nghiep-gia-o-goc-bac-kinh-thanh","blurb":"Lầu gác trong phủ Nghiệp gia, nơi các trưởng lão họp kín sau cuộc gặp Hàn trưởng lão. Tại đây họ bàn việc đề phòng Hàn trưởng lão và chuẩn bị mua vật liệu cho kế hoạch đoạt bảo.","detail":"Vân Dật, nhị trưởng lão Nghiệp gia và phụ nhân xinh đẹp cùng bàn trong lầu gác này. Họ đánh giá Hàn trưởng lão vừa hữu dụng vừa nguy hiểm, nghi ngờ Hàn Lập có thể liên quan đến Nghiệp gia, và quyết định giữ bí mật việc mua vật liệu ở đại hội đấu giá.","theLucLienQuan":["Nghiệp gia"],"nguon":["@c0946"]},{"id":"cac-khu-cho-trong-kinh-thanh","name":"Các khu chợ trong kinh thành","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Các khu chợ trong Tấn kinh nơi tu sĩ Âm La tông âm thầm truy tìm Hàn Lập qua bức họa. Tin này được thám tử của Nghiệp gia truyền về.","detail":"Vân Dật cho biết thám tử Nghiệp gia phát hiện một số tu sĩ Âm La tông ở các khu chợ trong kinh thành đang lặng lẽ tìm một người qua bức họa. Đây là đầu mối khiến Nghiệp gia giao việc xử lý Hàn Lập cho Hàn trưởng lão.","theLucLienQuan":["Âm La tông","Nghiệp gia"],"nguon":["@c0946"]},{"id":"khu-cho-tay-tan","name":"Khu chợ Tây Tấn","cn":"","aliases":["Tây Tấn thị"],"capDo":"khac","parentId":"tan-kinh","blurb":"Khu chợ nơi đại hội đấu giá được tổ chức. Nơi này có cấm chế ra vào, tập trung nhiều tu sĩ cao giai và bị Âm La tông canh lối vào để dò người khả nghi.","detail":"Hàn Lập cải trang thành đại hán mặt đen rồi đến Khu chợ Tây Tấn. Càng gần khu chợ càng có nhiều khí tức cao giai, trong đó có không ít tu sĩ Nguyên Anh; lối vào còn có tu sĩ Âm La tông dùng thần thức quét xét người ra vào.","theLucLienQuan":["Âm La tông","Nghiệp gia"],"nguon":["@c0947"]},{"id":"cuu-tieu-dien","name":"Cửu Tiêu điện","cn":"","capDo":"khac","parentId":"khu-cho-tay-tan","blurb":"Đại điện đá trắng treo giữa không trung phía trên Bảo Quang điện. Nơi này được mượn khẩn cấp để tổ chức hội đấu giá cấp Nguyên Anh.","detail":"Do số tu sĩ tham gia đông hơn trước, đại hội đấu giá cấp Nguyên Anh được tổ chức tại Cửu Tiêu điện. Hàn Lập nộp linh thạch, nhận ngọc bài rồi bay vào điện; sau hai canh giờ có mấy trăm tu sĩ Nguyên Anh tiến vào và đại hội chính thức bắt đầu.","theLucLienQuan":["Thiên Cơ các"],"nguon":["@c0947"]},{"id":"hoang-cung","name":"Hoàng cung","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Nơi Huyền Thanh và Thất Diệu được nói đã đột nhập. Sự kiện này khiến Nghiệp gia lo ngại phong thanh kế hoạch đã truyền tới phía hoàng cung.","detail":"Trong cuộc bàn bạc của Nghiệp gia, mỹ phụ nhân nhắc việc Huyền Thanh và Thất Diệu đột nhập vào cung. Chi tiết này khiến Nghiệp gia phải tính đến cách ứng phó với Hoàng Thượng và các thế lực lớn.","theLucLienQuan":["Nghiệp gia","Thái Nhất môn","Thiên Ma tông"],"nguon":["@c0947"]},{"id":"dai-dien-dau-gia","name":"Đại điện đấu giá","cn":"","capDo":"khac","parentId":"phuong-thi","blurb":"Nơi diễn ra ngày đầu đấu giá hội với sự tham dự của nhiều tu sĩ Nguyên Anh Đại Tấn. Mặc kim và Cách hỏa sa đều được đưa ra tranh đoạt tại đây.","detail":"Hàn Lập ngồi trong góc đại điện để quan sát các tu sĩ cao giai và theo dõi vật phẩm đấu giá. Đại điện là nơi tu sĩ trung niên áo bào đen chủ trì bán Khương Hoàng tinh, Mặc kim và nhiều vật phẩm giá trị khác.","theLucLienQuan":["Phật tông","Âm La Tông","Nghiệp gia"],"nguon":["@c0948"]},{"id":"tay-bo-nam-cuong-dai-sa-mac","name":"Tây bộ Nam Cương đại sa mạc","cn":"","capDo":"vuc","parentId":"dai-tan","blurb":"Vùng đại sa mạc ở Tây bộ Nam Cương, được nêu là nơi xuất xứ của Khương Hoàng tinh. Loại tinh thạch này phải tìm dưới sâu trong sa mạc.","detail":"Khương Hoàng tinh được giới thiệu là tài liệu chỉ tìm được dưới một ngàn thước trong Tây bộ Nam Cương đại sa mạc. Địa danh này gắn với nguồn tài liệu luyện khí thổ thuộc tính.","theLucLienQuan":[],"nguon":["@c0948"]},{"id":"khu-nha-dan-tai-tan-kinh","name":"Khu nhà dân tại Tấn kinh","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Địa điểm gặp riêng giữa lão giả họ Cao và Ô quan lão giả sau ngày đầu đấu giá. Tại đây, Cách hỏa sa được giao cho Nghiệp gia và kế hoạch giao dịch ngầm về Mặc kim được nhắc tới.","detail":"Sau khi đấu giá kết thúc, lão giả họ Cao tới một khu nhà dân tại Tấn kinh để gặp Ô quan lão giả. Hai người bàn chuyện Mặc kim, giao Cách hỏa sa, thù lao, linh thạch và ngọc giản tình báo.","theLucLienQuan":["Nghiệp gia"],"nguon":["@c0948"]},{"id":"phong-giao-dich-ngam","name":"Phòng giao dịch ngầm","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Nơi Ô quan lão giả nói vài ngày sau còn có cơ hội trao đổi Mặc kim. Đây là điểm hẹn ngầm mà Nghiệp gia chuẩn bị tài liệu để tiếp tục giao dịch.","detail":"Sau khi Mặc kim tại đấu giá hội rơi vào tay Hàn Lập, Ô quan lão giả cho biết phòng giao dịch ngầm vài ngày sau vẫn có trao đổi loại tài liệu này. Họ Cao được giao thêm linh thạch và tình báo để lo liệu việc sau.","theLucLienQuan":["Nghiệp gia"],"nguon":["@c0948"]},{"id":"loi-vao-loi-ra-phuong-thi","name":"Lối vào/lối ra phường thị","cn":"","capDo":"khac","parentId":"phuong-thi","blurb":"Lối vào/lối ra phường thị là nơi nhóm Cát Thiên Hào và Lâm Ngân Bình chặn tìm Hàn Lập. Diệu Âm bảo kính được dùng tại đây để soi xét tu sĩ qua lại.","detail":"Khu vực này trở thành điểm canh giữ của Âm La tông sau đấu giá hội. Hàn Lập không đi qua đây mà rẽ tới Thiên Cơ các rồi dùng đường truyền tống rời phường thị.","theLucLienQuan":["Âm La tông","Thiên Lan"],"nguon":["@c0949"]},{"id":"thien-co-cac","name":"Thiên Cơ các","cn":"","capDo":"khac","parentId":"phuong-thi","blurb":"Thiên Cơ các là điểm Hàn Lập ghé sau đấu giá hội thay vì rời phường thị. Tại đây, hắn gặp Vương trưởng lão và lão giả họ Phú.","detail":"Nơi này giúp Hàn Lập tránh khỏi cuộc chặn bắt ở lối ra phường thị. Trong phòng khách quý, Hàn Lập cùng Vương trưởng lão và lão giả họ Phú trao đổi kinh nghiệm tu luyện gần nửa ngày.","theLucLienQuan":["Thiên Cơ các"],"nguon":["@c0949"]},{"id":"sau-linh-trai","name":"Sấu Linh trai","cn":"","capDo":"khac","parentId":"phuong-thi","blurb":"Sấu Linh trai là lầu các và hãng buôn gần Thiên Cơ các. Bên trong có truyền tống trận tạm thời đưa Hàn Lập tới gần giao dịch hội dưới đất.","detail":"Chủ nhân Sấu Linh trai là hảo hữu của lão giả họ Phú và là trận pháp đại sư danh tiếng. Truyền tống trận tại đây được phép bố trí trong thời gian ngắn, trở thành đường rời phường thị bí mật.","theLucLienQuan":["Sấu Linh trai"],"nguon":["@c0949"]},{"id":"giao-dich-hoi-duoi-dat","name":"Giao dịch hội dưới đất","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Giao dịch hội dưới đất là hội trao đổi vật phẩm dành cho tu sĩ Nguyên Anh vào ngày cuối. Muốn tham gia cần có quan hệ ma đạo hoặc người giới thiệu.","detail":"Hội này là đích đến của Hàn Lập, lão giả họ Phú, Cát Thiên Hào và Lâm Ngân Bình sau đấu giá hội. Nó nằm gần điểm đến của truyền tống trận tạm thời từ Sấu Linh trai.","theLucLienQuan":["Âm La tông","Sấu Linh trai"],"nguon":["@c0949"]},{"id":"son-dong-bi-mat","name":"Sơn động bí mật","cn":"","capDo":"khac","parentId":"phia-nam-tan-kinh","blurb":"Sơn động bí mật là nơi Hàn Lập và lão giả họ Phú xuất hiện sau khi dùng truyền tống trận từ Sấu Linh trai. Đây là điểm trung chuyển gần giao dịch hội dưới đất.","detail":"Sơn động nằm gần một ngọn núi vô danh phía nam Tấn kinh. Từ đây có thể mơ hồ thấy tường thành Tấn kinh, cho thấy vị trí không quá xa khu vực chính.","theLucLienQuan":["Sấu Linh trai"],"nguon":["@c0949"]},{"id":"phia-nam-tan-kinh","name":"Phía nam Tấn kinh","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Phía nam Tấn kinh là khu vực Hàn Lập và lão giả họ Phú được truyền tống tới sau khi rời phường thị. Nơi này có sơn động bí mật gần một ngọn núi vô danh.","detail":"Khu vực này đóng vai trò điểm chuyển tiếp từ phường thị tới giao dịch hội dưới đất. Vị trí đủ gần để nhìn thấy tường thành Tấn kinh từ xa.","theLucLienQuan":[],"nguon":["@c0949"]},{"id":"ngon-nui-vo-danh","name":"Ngọn núi vô danh","cn":"","capDo":"khac","parentId":"phia-nam-tan-kinh","blurb":"Ngọn núi vô danh nằm gần sơn động bí mật phía nam Tấn kinh. Đây là mốc địa hình quanh điểm truyền tống từ Sấu Linh trai.","detail":"Chương chỉ nêu ngọn núi như vị trí gần sơn động bí mật, nơi Hàn Lập và lão giả họ Phú xuất hiện sau truyền tống.","theLucLienQuan":[],"nguon":["@c0949"]},{"id":"hoang-thanh","name":"Hoàng thành","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Hướng một tu sĩ bí ẩn bay về sau khi hai người chia nhau hành động ngoài khu chợ.","detail":"Sau khi nhóm Âm La Tông rời khu chợ, hai tu sĩ bí ẩn xuất hiện và phân công hành sự; một người ẩn thân bám theo hướng Cát Thiên Hào, người còn lại hóa thành độn quang bay thẳng về Hoàng thành.","theLucLienQuan":[],"nguon":["@c0950"]},{"id":"nui-hoang-den-kit-cach-tan-kinh-ba-nghin-dam","name":"Núi hoang đen kịt cách Tấn kinh ba nghìn dặm","cn":"","capDo":"khac","parentId":"dai-tan","blurb":"Khu vực đặt lối vào giao dịch hội ngầm, nằm cách Tấn kinh khoảng ba nghìn dặm.","detail":"Lão giả họ Phú dẫn Hàn Lập rời Tấn kinh, bay khoảng ba nghìn dặm tới một vùng núi hoang đen kịt. Tại đây có lối vào giao dịch hội ngầm được che giấu bằng cấm chế, chỉ hiện ra khi dùng pháp khí thích hợp mở cửa.","theLucLienQuan":["Giao dịch hội ngầm"],"nguon":["@c0950"]},{"id":"khe-nui-hoang-da-giua-hai-ngon-nui","name":"Khe núi hoang dã giữa hai ngọn núi","cn":"","capDo":"khac","parentId":"nui-hoang-den-kit-cach-tan-kinh-ba-nghin-dam","blurb":"Vị trí cụ thể của cửa vào giao dịch hội ngầm, nằm giữa hai ngọn núi hoang.","detail":"Khe núi này đầy cỏ dại và bụi cây, bề ngoài khó nhận ra điểm đặc biệt. Lão giả họ Phú dùng vòng tròn pháp khí kích hoạt cấm chế trên vách đá, khiến vách đá biến mất và hiện ra cửa hang lớn dẫn vào nơi giao dịch hội ngầm.","theLucLienQuan":["Giao dịch hội ngầm"],"nguon":["@c0950"]},{"id":"dai-sanh-giao-dich-hoi","name":"Đại sảnh giao dịch hội","cn":"","capDo":"khac","parentId":null,"blurb":"Đại sảnh hơi tối nơi diễn ra giao dịch hội ẩn danh.","detail":"Đại sảnh có bốn năm trăm chỗ ngồi vây quanh khu đất trống hình tròn ở giữa, nơi đặt bàn bạch ngọc để bày vật đấu giá. Cả không gian nằm trong ảnh hưởng của trận pháp cổ quái, phối hợp với lá bùa đặc chế để che giấu thân phận người dự hội.","theLucLienQuan":["Giao dịch hội ẩn danh"],"nguon":["@c0951"]},{"id":"giao-hoan-hoi","name":"Giao hoán hội","capDo":"khac","parentId":null,"blurb":"Giao hoán hội là nơi Hàn Lập hoàn tất đổi Ngũ hành ngọc và Diệp gia đưa Bình Sơn Ấn ra làm trọng bảo cuối cùng. Đây là địa điểm tập trung nhiều tu sĩ tham gia trao đổi và đấu giá vật phẩm quý.","detail":"Trong chương này, giao hoán hội chuyển từ phần trao đổi vật phẩm sang bán đấu giá trọng bảo cuối. Người chủ trì công bố Bình Sơn Ấn sau khi hai trưởng lão Diệp gia xuất hiện công khai.","theLucLienQuan":["Diệp gia"],"nguon":["@c0954"]},{"id":"bao-kho-diep-gia","name":"Bảo khố Diệp gia","capDo":"khac","parentId":null,"blurb":"Bảo khố Diệp gia là nơi xuất phát của Bình Sơn Ấn được đưa ra tại giao hoán hội. Tin tức về vật từ bảo khố khiến các tu sĩ đặc biệt chú ý đến trọng bảo cuối.","detail":"Người chủ trì nói trước cho mọi người nhìn chân diện mục của vật lấy ra từ bảo khố, rồi mở hộp chứa Bình Sơn Ấn để công bố lai lịch và uy năng của nó.","theLucLienQuan":["Diệp gia"],"nguon":["@c0954"]},{"id":"khu-vuc-gan-dia-ha-giao-hoan-hoi","name":"Khu vực gần địa hạ giao hoán hội","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực gần địa hạ giao hoán hội là nơi Hàn Lập và Cổ ma đối đầu trong chương 956. Vị trí này khiến nhiều tu sĩ truy bảo liên tục kéo tới, buộc Hàn Lập phải ưu tiên rút lui.","detail":"Tại khu vực này, Ác hỏa đầu đà, ba tu sĩ Nguyên Anh sơ kỳ và sau đó thêm sáu bảy đạo độn quang lần lượt xuất hiện. Vì chiến trường không xa địa hạ giao hoán hội, Đại Diễn Thần Quân cảnh báo Hàn Lập không nên dây dưa lâu.","theLucLienQuan":["Giao hoán hội"],"nguon":["@c0956"]},{"id":"van-chau","name":"Vân châu","cn":"","capDo":"chau","parentId":"dai-tan","blurb":"Vân châu là đại châu duyên hải phía đông Đại Tấn. Nơi đây nhiều cảng, thành trấn và phường thị, thường có hải ngoại tu sĩ lui tới trao đổi tài nguyên tu luyện.","detail":"Vân châu nằm ở vùng duyên hải phía đông Đại Tấn, có hoạt động giao thương tu tiên nhộn nhịp nhờ hải ngoại tu sĩ đem yêu thú và tài liệu vào đổi tài nguyên. Khai Giang trấn và Bạch Trúc sơn của Thiên Phù môn nằm trong khu vực này.","theLucLienQuan":["Thiên Phù môn"],"nguon":["@c0957"]},{"id":"khai-giang-tran","name":"Khai Giang trấn","cn":"","capDo":"thanh","parentId":"van-chau","blurb":"Khai Giang trấn là trấn nhỏ cách bờ biển khoảng hai trăm dặm tại Vân châu. Gần trấn có ngọn núi đặt sơn môn Thiên Phù môn.","detail":"Khai Giang trấn nằm trong vùng duyên hải Vân châu, cách biển khoảng hai trăm dặm. Một ngọn núi nhỏ linh mạch yếu gần trấn là nơi Thiên Phù môn đặt sơn môn.","theLucLienQuan":["Thiên Phù môn"],"nguon":["@c0957"]},{"id":"bach-truc-son","name":"Bạch Trúc sơn","cn":"","aliases":["Bạch Tú sơn"],"capDo":"khac","parentId":"van-chau","blurb":"Bạch Trúc sơn là ngọn núi nhỏ linh mạch yếu gần Khai Giang trấn, nơi Thiên Phù môn đặt sơn môn. Trong chương cũng xuất hiện cách gọi Bạch Tú sơn cho địa điểm này.","detail":"Bạch Trúc sơn cao khoảng hai ba trăm trượng, linh mạch không mạnh, phù hợp với hiện trạng suy tàn của Thiên Phù môn. Hàn Lập bay tới đây bằng thanh hồng để xin gặp chưởng môn Thiên Phù môn.","theLucLienQuan":["Thiên Phù môn"],"nguon":["@c0957"]},{"id":"hoa-van-chau","name":"Hoa Vân châu","cn":"","capDo":"chau","parentId":"dai-tan","blurb":"Hoa Vân châu là nơi từng xuất hiện mấy ác giao. Việc này liên quan đến lý do Hàn Lập tìm đến Thiên Phù môn để học phương pháp luyện chế Hàng Linh phù.","detail":"Hàn Lập nghĩ nếu không vì mấy ác giao tại Hoa Vân châu và việc chưa học phương pháp luyện chế Hàng Linh phù, hắn sẽ không đến tiểu phái Thiên Phù môn. Chương này chưa mô tả thêm vị trí hay tình hình Hoa Vân châu.","theLucLienQuan":[],"nguon":["@c0957"]},{"id":"am-minh-chi-dia","name":"Âm Minh chi địa","cn":"","capDo":"khac","parentId":"quy-vu","blurb":"Âm Minh chi địa là hiểm địa trong Quỷ vụ, nơi không thể vận dụng pháp lực. Hàn Lập kể sơ chuyện nơi này cho Ôn lão giả khi giải thích việc Vân đạo hữu mất tích.","detail":"Khi Hàn Lập thuật lại chuyện Quỷ vụ, Âm Minh chi địa được nhắc như nơi nguy hiểm khiến Ôn lão giả kinh hãi. Các chi tiết liên quan bí mật của Hàn Lập được hắn lược bỏ.","theLucLienQuan":["Thiên Phù môn"],"nguon":["@c0958"]},{"id":"dai-dien-thien-phu-mon","name":"Đại điện Thiên Phù môn","cn":"","capDo":"khac","parentId":"thien-phu-mon","blurb":"Đại điện Thiên Phù môn là nơi Ôn lão giả, Nhạc Chân và các tu sĩ tiếp đãi Hàn Lập. Tại đây Hàn Lập giao cốt hạp chứa phương pháp luyện chế Hàng Linh phù.","detail":"Sau khi Hàn Lập rời đi, đại điện cũng là nơi nội bộ Thiên Phù môn bàn cách kết giao hắn để giải quyết vấn đề phường thị và áp lực từ các thế lực khác.","theLucLienQuan":["Thiên Phù môn"],"nguon":["@c0958"]},{"id":"tang-thu-cac-thien-phu-mon","name":"Tàng thư các Thiên Phù môn","cn":"","aliases":["Tàng kinh các Thiên Phù môn"],"capDo":"khac","parentId":"thien-phu-mon","blurb":"Tàng thư các Thiên Phù môn là lầu các ba tầng có cấm chế xanh nhạt, nơi cất giữ điển tịch chế phù. Hàn Lập tới đây xem sách và gặp Lý sư điệt.","detail":"Dương sư điệt đưa Hàn Lập tới Tàng thư các sau khi Hàn Lập đồng ý lưu lại vì hứng thú với điển tịch quan phù. Tại đây, cuộc gặp giữa Hàn Lập và Lý sư điệt bộc lộ dấu hiệu có ẩn tình.","theLucLienQuan":["Thiên Phù môn"],"nguon":["@c0958"]},{"id":"phuong-thi-dang-tranh-chap","name":"Phường thị đang tranh chấp","cn":"","capDo":"khac","parentId":"hoa-van-chau","blurb":"Phường thị đang tranh chấp là vấn đề trước mắt của Thiên Phù môn. Môn phái hy vọng nếu kết giao được Hàn Lập thì có thể dễ dàng hóa giải áp lực này.","detail":"Trong cuộc bàn bạc sau khi Hàn Lập rời đại điện, các tu sĩ Thiên Phù môn cho rằng uy danh một tu sĩ Nguyên Anh có thể khiến Linh Phong môn và Sát Dương tông phải kiêng dè, từ đó giải quyết chuyện phường thị.","theLucLienQuan":["Thiên Phù môn","Linh Phong môn","Sát Dương tông"],"nguon":["@c0958"]},{"id":"thien-phu-mon-tang-hai-tang-thu-lau","name":"Thiên Phù môn tầng hai tàng thư lầu","cn":"","capDo":"khac","parentId":"dai-dien-thien-phu-mon","blurb":"Tầng hai tàng thư lầu Thiên Phù môn là nơi Hàn Lập được Hướng Chi Lễ đưa lên xem điển tịch chế phù. Cuối chương, Hàn Lập dùng trận kỳ dựng cấm chế màu xanh nhạt bao phủ toàn tầng.","detail":"Không gian tầng hai không lớn, có nhiều giá sách và chứa các ngọc giản điển tịch chế phù của Thiên Phù môn. Sau khi Hướng Chi Lễ lui xuống, Hàn Lập cùng Đại Diễn Thần Quân bàn về thân phận thật của lão giả, rồi bày cấm chế phòng hộ trước khi dùng thần thức dò xét ngọc giản.","theLucLienQuan":["Thiên Phù môn"],"nguon":["@c0959"]},{"id":"lam-giang-phu","name":"Lâm Giang phủ","cn":"","capDo":"khac","parentId":"dai-tan","blurb":"Địa điểm Hàn Lập dự định tới, gần đây nổi lên tin ác giao xuất hiện.","detail":"Các tu sĩ đến Lâm Giang phủ gần đây phần lớn vì biến cố ác giao. Hàn Lập đặc biệt hỏi về hồng giao xuất hiện tại vùng ven biển nơi này.","theLucLienQuan":["Nam Hải môn"],"nguon":["@c0960"]},{"id":"quan-anh-dao","name":"Quần Anh đảo","cn":"","capDo":"khac","parentId":"lam-giang-phu","blurb":"Nơi Nam Hải môn mời cao giai tu sĩ tụ tập để chuẩn bị đại hội đồ giao.","detail":"Trước đàn ác giao ẩn ở hải đảo, tập kích tu sĩ lẻ và phàm nhân rồi trốn vào biển sâu, Nam Hải môn chọn Quần Anh đảo làm nơi tụ hội cao giai tu sĩ cho đại hội đồ giao.","theLucLienQuan":["Nam Hải môn"],"nguon":["@c0960"]},{"id":"hai-vuc-phu-can","name":"Hải vực phụ cận","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng biển nơi Nam Hải môn chia tổ tu sĩ truy quét ác giao. Khi nhân thủ săn giao suy giảm, nơi đây trở thành địa bàn bát cấp lam giao và đồng bọn tập kích các đội tu sĩ.","detail":"Đại hội đồ giao của Nam Hải môn đưa nhiều tổ tu sĩ ra hải vực phụ cận để tìm ác giao. Đám ác giao ẩn nấp lâu ngày, sau đó phản kích các tổ ít người rồi dùng thủy thuật lẩn xuống đáy biển.","theLucLienQuan":["Nam Hải môn"],"nguon":["@c0961"]},{"id":"hai-vuc-phia-tay-quynh-anh-dao","name":"Hải vực phía tây Quỳnh Anh đảo","cn":"","capDo":"khac","parentId":"quynh-anh-dao","blurb":"Khu vực đội tu sĩ được Nam Hải môn phái tới dò xét. Nơi này cách Quỳnh Anh đảo không xa và từng xảy ra vụ một tổ tu sĩ bị bát cấp lam giao đánh lén.","detail":"Hải vực phía tây Quỳnh Anh đảo là địa điểm chính của nhiệm vụ dò xét trong chương. Đội tu sĩ do đại hán Nguyên Anh kỳ dẫn đầu tới đây kiểm tra lại, nhưng bị đàn ác giao từ nhiều hướng phản vây, dẫn tới trận Hàn Lập đối đầu Xích Hỏa Giao.","theLucLienQuan":["Nam Hải môn","Đàn ác giao hải vực Quỳnh Anh đảo"],"nguon":["@c0962"]},{"id":"quynh-anh-dao","name":"Quỳnh Anh đảo","cn":"","capDo":"khac","parentId":"quan-anh-dao","blurb":"Đảo mốc dùng để xác định khu vực tìm kiếm của đội tu sĩ. Hải vực phía tây đảo này là nơi xảy ra cuộc phản vây của đàn ác giao.","detail":"Quỳnh Anh đảo được nhắc như mốc địa lý cho nhiệm vụ dò xét của đội tu sĩ. Khu vực tìm kiếm nằm ở hải vực phía tây đảo, cách đảo không xa.","theLucLienQuan":["Nam Hải môn"],"nguon":["@c0962"]},{"id":"linh-dao-khong-nguoi","name":"Linh đảo không người","cn":"","capDo":"khac","parentId":"dai-hai","blurb":"Linh đảo không người là mục tiêu Hàn Lập muốn tìm sau khi rời chiến trường ác giao. Hắn định chọn nơi này để bắt đầu luyện chế khôi lỗi của Đại Diễn thần quân.","detail":"Sau khi bay xa chiến trường hơn trăm dặm, Hàn Lập không quay lại cuộc vây tiễu ác giao mà tiếp tục đi sâu vào đại hải. Mục tiêu của hắn là tìm một linh đảo không người để luyện chế khôi lỗi cho Đại Diễn thần quân.","theLucLienQuan":[],"nguon":["@c0963"]},{"id":"dao-nho-vo-danh-trong-hai-vuc","name":"Đảo nhỏ vô danh trong hải vực","cn":"","capDo":"khac","parentId":null,"blurb":"Đảo nhỏ hẻo lánh giữa hải vực, nơi Hàn Lập chọn làm chỗ bí mật luyện chế khôi lỗi. Đảo có linh mạch nhỏ nhưng không bị thế lực nào chiếm giữ.","detail":"Hàn Lập dựa theo bản đồ hải vực bay nửa tháng mới tới đảo nhỏ vô danh này. Đảo rộng khoảng bốn mươi dặm vuông, nằm xa tuyến thông thương, có linh mạch nhỏ dài bảy tám dặm nên không đáng để gia tộc mạnh chiếm giữ nhưng đủ thích hợp cho hắn tạm lập động phủ.","theLucLienQuan":[],"nguon":["@c0964"]},{"id":"linh-mach-nho-tren-dao","name":"Linh mạch nhỏ trên đảo","cn":"","capDo":"khac","parentId":"dao-nho-vo-danh-trong-hai-vuc","blurb":"Linh mạch nhỏ dài khoảng bảy tám dặm trên đảo vô danh. Nó không đủ giá trị với thế lực lớn nhưng phù hợp để Hàn Lập đặt động phủ tạm thời.","detail":"Linh mạch nằm trên đảo nhỏ vô danh trong hải vực. Chính vì linh mạch nhỏ, vị trí lại hẻo lánh, đảo không bị các gia tộc tu tiên chiếm giữ, tạo điều kiện để Hàn Lập bí mật luyện khôi lỗi.","theLucLienQuan":[],"nguon":["@c0964"]},{"id":"ngon-nui-nho-dat-thien-co-phu","name":"Ngọn núi nhỏ đặt Thiên Cơ Phủ","cn":"","capDo":"khac","parentId":"dao-nho-vo-danh-trong-hai-vuc","blurb":"Ngọn núi trên đảo vô danh được Hàn Lập khoét hang đặt Thiên Cơ Phủ. Bên ngoài được ảo trận và sương mù che phủ trong phạm vi mười dặm.","detail":"Hàn Lập dùng phi kiếm mở hang trong lòng núi, đặt Thiên Cơ Phủ vào trong, khởi động cấm chế rồi bố trí ảo trận che phủ toàn bộ ngọn núi nhỏ để tránh người ngoài nhòm ngó.","theLucLienQuan":[],"nguon":["@c0964"]},{"id":"mat-that-trung-tam-dong-phu","name":"Mật thất trung tâm động phủ","cn":"","capDo":"khac","parentId":"ngon-nui-nho-dat-thien-co-phu","blurb":"Mật thất trong Thiên Cơ Phủ nơi Hàn Lập bắt đầu công đoạn luyện khôi lỗi. Đây cũng là nơi Đại Diễn Thần Quân giao ngọc giản và tiết lộ phương án dùng tinh hồn bản thân.","detail":"Trong mật thất, Hàn Lập mang lượng lớn tài liệu luyện chế vào, đặt ống trúc chứa Đại Diễn Thần Quân trước mặt, đọc bạch sắc ngọc giản và bàn bạc các điểm then chốt của khôi lỗi cấp cao.","theLucLienQuan":[],"nguon":["@c0964"]},{"id":"kho-truc-dao","name":"Khô trúc đảo","cn":"","capDo":"khac","parentId":"vung-bien-vo-danh-cua-dai-tan","blurb":"Tiểu đảo trong vùng biển vô danh của Đại Tấn, quanh năm bị sương mù lam bao phủ. Đây là nơi ở của Khô trúc lão nhân và được vạn mộc đại trận bảo vệ.","detail":"Khô trúc đảo là địa bàn của Khô trúc lão nhân, một tu sĩ Nguyên Anh trung kỳ nổi danh hải ngoại. Đảo có thiên tang thần thụ làm trận nhãn cho vạn mộc đại trận, khiến nơi này uy chấn vùng biển nhiều vạn năm; chương kết bằng việc một ác khách xuất hiện tại đây.","theLucLienQuan":["Khô trúc lão nhân","Hải ngoại tam tiên"],"nguon":["@c0965"]},{"id":"vung-bien-vo-danh-cua-dai-tan","name":"Vùng biển vô danh của Đại Tấn","cn":"","capDo":"vuc","parentId":"dai-tan","blurb":"Vùng biển hải ngoại thuộc Đại Tấn, nơi Khô trúc đảo tọa lạc. Khu vực này được dùng làm bối cảnh giới thiệu uy danh của Khô trúc lão nhân.","detail":"Vùng biển vô danh của Đại Tấn là nơi có Khô trúc đảo, địa bàn của Khô trúc lão nhân. Đây là không gian hải ngoại tách khỏi các tranh đoạt thường thấy của tu tiên giới đất liền.","theLucLienQuan":["Hải ngoại tam tiên"],"nguon":["@c0965"]},{"id":"nghenh-phuong-cac","name":"Nghênh Phượng Các","cn":"","capDo":"khac","parentId":"kho-truc-dao","blurb":"Nghênh Phượng Các là nơi Khô Trúc lão nhân chỉ định để tiếp đãi Hàn Lập và khôi lỗi trung niên khi hai người được mời vào Khô trúc đảo.","detail":"Sau khi nhận Truyền Âm Phù, Khô Trúc lão nhân truyền giọng cho đệ tử dẫn hai vị khách Nguyên Anh kỳ đến Nghênh Phượng Các, còn mình sẽ lập tức xuất quan gặp mặt.","theLucLienQuan":["Khô trúc đảo"],"nguon":["@c0966"]},{"id":"moc-dien-tren-dinh-nui","name":"Mộc điện trên đỉnh núi","cn":"","capDo":"khac","parentId":"kho-truc-dao","blurb":"Đại điện bằng gỗ nằm trên đỉnh núi nhỏ trong khu trung tâm Khô Trúc đảo. Đây là nơi Hàn Lập gặp Khô Trúc lão nhân và bàn giao dịch Ô phong linh.","detail":"Sau khi cảnh vật trên Khô Trúc đảo biến đổi, lão giả dẫn Hàn Lập và khôi lỗi lên đỉnh núi tới một mộc điện lớn. Bên ngoài điện có bốn mộc linh vệ canh giữ, bên trong có đại sảnh và thiên điện, được dùng làm nơi Khô Trúc tiếp khách.","theLucLienQuan":["Khô Trúc đảo"],"nguon":["@c0967"]},{"id":"hoang-dao-vo-danh","name":"Hoang đảo vô danh","cn":"","capDo":"khac","parentId":null,"blurb":"Hoang đảo vô danh là nơi Hàn Lập đưa khôi lỗi chứa tinh hồn Đại Diễn Thần Quân tới. Tại đây hắn chứng kiến Đại Diễn Thần Quân tọa hóa, sau đó bố trí Thiên cơ phủ để hàng phục Thổ giáp long.","detail":"Vài ngày sau, Hàn Lập xuất hiện trên một hoang đảo vô danh khác. Nơi này trở thành địa điểm Đại Diễn Thần Quân giao di nguyện và Đại diễn bảo kinh trước khi tiêu tán, rồi Hàn Lập dùng làm nơi tạm trú để xử lý Thổ giáp long cấp bảy.","theLucLienQuan":[],"nguon":["@c0969"]},{"id":"dong-phuc-thien-trung","name":"Động phúc thiên trung","cn":"","capDo":"khac","parentId":null,"blurb":"Động phúc thiên trung là nơi Đại Diễn Thần Quân cất ngọc giản chứa Đại diễn bảo kinh. Địa đồ tới nơi này được lão để trong ống trúc.","detail":"Đại Diễn Thần Quân nói ngọc giản ghi Đại diễn bảo kinh được lưu tại động phúc thiên trung, còn địa đồ nằm trong ống trúc. Đây là điểm giữ y bát khôi lỗi thuật của lão.","theLucLienQuan":["Thiên trúc giáo"],"nguon":["@c0969"]},{"id":"nam-cuong","name":"Nam Cương","cn":"","capDo":"vuc","parentId":"dai-tan","blurb":"Nam Cương là khu vực Hàn Lập dự định đi tới sau hoang đảo. Nơi này vừa có Ngân xà sơn thích hợp luyện linh liêu, vừa là điểm hẹn với lão giả họ Phú của Cửu U tông.","detail":"Hàn Lập chọn Nam Cương vì tại đây có Ngân xà sơn với núi lửa phun quanh năm và hỏa mạch nổi danh. Việc tới nơi này cũng thuận tiện cho ước hẹn giữa hắn và lão giả họ Phú của Cửu U tông.","theLucLienQuan":["Cửu U tông"],"nguon":["@c0969","@c0970"]},{"id":"ngan-xa-son","name":"Ngân xà sơn","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Ngân xà sơn là ngọn núi ở Nam Cương có núi lửa phun quanh năm. Hàn Lập chọn nơi này làm điểm đến để luyện linh liêu cho Tam Diễm Phiến.","detail":"Do phế hỏa mạch Bách Xảo Viện không còn khả năng sử dụng, Hàn Lập chuyển hướng tới Ngân xà sơn. Nơi này có hỏa mạch nổi danh trong Đại Tấn, phù hợp với nhu cầu luyện linh liêu bằng chân hỏa.","theLucLienQuan":[],"nguon":["@c0969","@c0974"]},{"id":"phe-hoa-mach-bach-xao-vien","name":"Phế hỏa mạch Bách Xảo Viện","cn":"","capDo":"khac","parentId":"dai-tan","blurb":"Phế hỏa mạch Bách Xảo Viện từng được Hàn Lập để ý cho việc luyện linh liêu. Sau biến cố ở Đại Tấn, hắn cho rằng không còn khả năng mượn nơi này.","detail":"Khi cân nhắc địa hỏa để luyện linh liêu Tam Diễm Phiến, Hàn Lập nhớ tới phế hỏa mạch của Bách Xảo Viện nhưng loại bỏ vì tình hình hiện tại không cho phép mượn dùng.","theLucLienQuan":["Bách Xảo Viện"],"nguon":["@c0969"]},{"id":"trieu-van-phu","name":"Triều Vân Phủ","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Triều Vân Phủ nằm ở phía tây Nam Cương. Song Hạt Sơn, địa điểm Hàn Lập tìm tới để gặp Phú lão giả, thuộc phạm vi phủ này.","detail":"Chương xác định vị trí Song Hạt Sơn nằm trong Triều Vân Phủ ở tây bộ Nam Cương. Đây là lớp địa danh trung gian giữa Nam Cương và Song Hạt Sơn.","theLucLienQuan":["Các tông môn Nam Cương"],"nguon":["@c0970"]},{"id":"song-hat-son","name":"Song Hạt Sơn","cn":"","capDo":"khac","parentId":"trieu-van-phu","blurb":"Song Hạt Sơn là sơn mạch rộng mấy trăm dặm thuộc Triều Vân Phủ, quanh năm chướng khí bao phủ. Nơi đây có độc thảo, Thiết Vĩ Hạt, Hồng tuyến Độc Hạt và là địa điểm Phú lão giả hẹn Hàn Lập.","detail":"Khi Hàn Lập tới, Song Hạt Sơn đang vào kỳ chướng khí bộc phát hằng năm nên nhiều tu sĩ cấp thấp tụ tập bắt độc trùng. Địa thế độc khí dày đặc cũng thích hợp cho tu sĩ thi triển côn trùng thuật, nhất là các thủ đoạn liên quan linh trùng.","theLucLienQuan":["Các tông môn Nam Cương"],"nguon":["@c0970"]},{"id":"dinh-nui-cao-nhat-trong-song-hat-son","name":"Đỉnh núi cao nhất trong Song Hạt Sơn","cn":"","capDo":"khac","parentId":"song-hat-son","blurb":"Đỉnh núi cao nhất trong Song Hạt Sơn được Hàn Lập suy đoán là nơi gặp Phú lão giả vì lời hẹn ban đầu không nêu vị trí cụ thể. Cuối chương, hắn lên đỉnh này giữa mưa sấm và đuổi nhóm tu sĩ địa phương đi.","detail":"Trên đỉnh núi có bảy tám tu sĩ địa phương tụ tập trong cơn mưa sấm. Hàn Lập phóng linh áp và thanh hà quét họ rời đi, sau đó đứng dưới mây đen và sấm chớp dày đặc, chuẩn bị tận dụng thiên tượng.","theLucLienQuan":["Các tông môn Nam Cương"],"nguon":["@c0970"]},{"id":"bac-da-tieu-cuc-cung","name":"Bắc Dạ Tiểu Cực Cung","cn":"","capDo":"khac","parentId":"bac-minh-dao","blurb":"Bắc Dạ Tiểu Cực Cung là tông môn hẻo lánh mà Bạch Dao Di giữ chức ngoại sự trưởng lão.","detail":"Bạch Dao Di xác nhận mình là ngoại sự trưởng lão Tiểu Cực cung. Hàn Lập từng nghe danh nơi này và đặc biệt cảnh giác vì hàn tủy liên quan trấn cung chi bảo của cung đang ở trên người hắn.","theLucLienQuan":["Bắc Dạ Tiểu Cực Cung"],"nguon":["@c0971"]},{"id":"ngon-nui-noi-cho-chuong-khi-tan","name":"Ngọn núi nơi chờ chướng khí tan","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Ngọn núi nơi nhóm Hàn Lập, Bạch Dao Di và đại hán họ Nguyên chờ lão giả họ Phú sau khi chướng khí tan dần. Đây là điểm hội họp trước khi kế hoạch Bồi Anh đan được tiết lộ.","detail":"Sau gần nửa tháng chờ chướng khí tan phân nửa, lão giả họ Phú và Thường Chỉ Phương bay tới ngọn núi này để gặp ba khách mời. Tại đây, lão giả họ Phú lập cấm chế u hỏa rồi nói rõ kế hoạch tìm Âm Chi Mã huyết nhục để luyện Bồi Anh đan.","theLucLienQuan":["Cửu U tông","Độc Thánh môn"],"nguon":["@c0972"]},{"id":"giao-dich-hoi-ngam-tai-tan-kinh","name":"Giao dịch hội ngầm tại Tấn kinh","cn":"","capDo":"khac","parentId":"tan-kinh","blurb":"Giao dịch hội ngầm tại Tấn kinh được nhắc trong các tin đồn về Ác hỏa đầu đà và quỷ yêu hai đầu bốn tay. Đây là nơi liên quan đến chuỗi biến cố khiến danh tiếng thực lực của Hàn Lập bị chú ý.","detail":"Trong lời lão giả họ Phú và đại hán họ Nguyên, giao dịch hội ngầm tại Tấn kinh là nơi Ác hỏa đầu đà bị đánh chết sau đó và cũng gắn với tin quỷ yêu hai đầu bốn tay xuất hiện, thích cắn nuốt Nguyên Anh tu sĩ. Hàn Lập phủ nhận mình giết Ác hỏa đầu đà và nói việc quỷ yêu xảy ra sau khi hắn rời đi.","theLucLienQuan":[],"nguon":["@c0972"]},{"id":"am-duong-quat","name":"Âm dương quật","cn":"","aliases":["Âm Phong quật","Âm dương quật"],"capDo":"khac","parentId":"van-doc-coc","blurb":"Âm dương quật là một trong bảy đại tuyệt địa được công nhận của Đại Tấn. Nơi này nằm trong Vạn độc cốc và là chỗ sào huyệt Âm chi mã được phát hiện.","detail":"Âm dương quật sâu dưới đất mấy ngàn trượng, có nhiều thông đạo và huyệt động như mê cung. Âm phong trong động có thể khiến Nguyên Anh hồn phi phách tán, thần thức bị cản trở, lại có nhiều quỷ vật sinh ra từ huyền âm chi địa và lời đồn về Quỷ vương cực lợi hại.","theLucLienQuan":["Cửu U tông"],"nguon":["@c0973"]},{"id":"van-doc-coc","name":"Vạn độc cốc","cn":"","aliases":[],"capDo":"khac","parentId":"nam-cuong","blurb":"Vạn độc cốc là khu vực chứa Âm dương quật. Lão giả họ Phú phát hiện sào huyệt Âm chi mã ở nơi này.","detail":"Trong kế hoạch của lão giả họ Phú, Vạn độc cốc là địa điểm then chốt vì Âm chi mã trú gần Âm dương quật tại đây, khiến việc bắt giữ trở nên cực kỳ nguy hiểm.","theLucLienQuan":[],"nguon":["@c0973"]},{"id":"khe-nut-luyen-bao-o-ngan-xa-son","name":"Khe nứt luyện bảo ở Ngân xà sơn","cn":"","capDo":"khac","parentId":"ngan-xa-son","blurb":"Khe nứt luyện bảo là nơi Hàn Lập dùng kim sắc tiểu kiếm mở ra giữa vùng hỏa mạch Ngân xà sơn. Sau khi hắn phóng linh áp Nguyên Anh, phạm vi mười dặm quanh đó thành cấm địa.","detail":"Khe nứt dài hơn hai mươi trượng được mở bằng bảy tám khẩu kim sắc tiểu kiếm. Trong quá trình Hàn Lập luyện bảo, nơi này phát ra tiếng sấm rồi tiếng minh thanh như phượng gáy, khiến tu sĩ xung quanh không dám tới gần.","theLucLienQuan":["Hàn Lập"],"nguon":["@c0974"]},{"id":"hoang-cung-dai-noi-dai-tan","name":"Hoàng cung đại nội Đại Tấn","cn":"","capDo":"khac","parentId":"dai-tan","blurb":"Hoàng cung đại nội Đại Tấn là nơi Diệp gia tụ họp hơn mười tu sĩ Nguyên Anh trong một thiên điện. Cuộc gặp tại đây mở ra bí mật về Thất thúc Diệp gia.","detail":"Trong khu hoàng cung Đại Tấn, nhóm tu sĩ Diệp gia và người liên hệ với Diệp gia chờ quái nhân xuất hiện. Đây là bối cảnh xác minh thân phận Thất thúc và hé lộ kế hoạch liên quan vận mệnh Diệp gia.","theLucLienQuan":["Diệp gia","Đại Tấn"],"nguon":["@c0974"]},{"id":"thien-dien-trong-hoang-cung-dai-tan","name":"Thiên điện trong hoàng cung Đại Tấn","cn":"","capDo":"khac","parentId":"hoang-cung-dai-noi-dai-tan","blurb":"Thiên điện trong hoàng cung Đại Tấn là địa điểm nhóm Diệp gia kiểm chứng thân phận Thất thúc. Quái nhân xuất hiện tại đây và lộ ra bí mật chết giả nhiều năm trước.","detail":"Hơn mười tu sĩ Nguyên Anh tụ tập trong thiên điện, gồm tu sĩ mặt chữ điền, lão phụ nhân cầm kim sắc quải trượng, đạo sĩ râu tóc bạc trắng và Ô quan lão giả. Quái nhân tới nơi, đưa truyền âm ngọc giản và được xác nhận là Thất thúc Diệp gia.","theLucLienQuan":["Diệp gia"],"nguon":["@c0974"]},{"id":"dong-phu-bi-mat-ngoai-thanh","name":"Động phủ bí mật ngoài thành","cn":"","capDo":"khac","parentId":"hoang-thanh","blurb":"Động phủ bí mật ngoài hoàng thành Đại Tấn, nơi Cát Thiên Hào bàn chuyện truy tìm Hàn Lập với Lâm Ngân Bình.","detail":"Tại đây, Cát Thiên Hào báo tin Hàn Lập có thể ở Nam Cương, còn Lâm Ngân Bình nói về đội hộ điện tu sĩ Thiên Lan, việc điều tra Hàn Lập tại Thiên Nam và dự tính lợi dụng Âm La tông.","theLucLienQuan":["Âm La tông","Thiên Lan"],"nguon":["@c0975"]},{"id":"ngan-giao-son","name":"Ngân Giao sơn","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Khu vực gần Nam Cương xuất hiện thanh hồng cực nhanh trước khi Hàn Lập tới điểm hẹn.","detail":"Ở vùng gần Ngân Giao sơn, một tiếng thét vui sướng vang lên và đạo thanh hồng của Hàn Lập lao nhanh qua rừng nguyên thủy theo hướng tây.","theLucLienQuan":[],"nguon":["@c0975"]},{"id":"nguyen-thuy-sam-lam-nam-cuong","name":"Nguyên thủy sâm lâm Nam Cương","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Rừng rậm nguyên thủy rộng gần ngàn dặm ở Nam Cương.","detail":"Hàn Lập dùng độn quang cực nhanh bay qua khu rừng rậm nguyên thủy này trên đường tới điểm hẹn gần Vạn Độc cốc.","theLucLienQuan":[],"nguon":["@c0975"]},{"id":"tieu-ho-o-nam-cuong","name":"Tiểu hồ ở Nam Cương","cn":"","aliases":["Nam Cương tiểu hồ"],"capDo":"khac","parentId":"nam-cuong","blurb":"Điểm tập kết của nhóm tu sĩ Diệp gia tại Nam Cương khi bàn kế hoạch Côn Ngô sơn.","detail":"Trên tiểu hồ này, bảy tám tu sĩ Diệp gia tụ tập để nghe hắc y tu sĩ báo cáo về tàn bia thượng cổ, linh sơn Côn Ngô, hai kiện thông thiên linh bảo và kế hoạch phá cấm. Đây là nơi lộ rõ mưu đồ kéo dài bốn trăm năm của Diệp gia.","theLucLienQuan":["Diệp gia"],"nguon":["@c0976"]},{"id":"con-ngo-son","name":"Côn Ngô sơn","cn":"","aliases":["Linh sơn Côn Ngô","Côn Ngô Sơn","Côn Ngô tiên sơn"],"capDo":"khac","parentId":"dai-tan","blurb":"Linh sơn thượng cổ từng là thánh địa tiên gia, nay bị phong ấn và là mục tiêu của Diệp gia.","detail":"Côn Ngô sơn được tàn bia thượng cổ ghi là thánh địa tiên gia thời thượng cổ, bị thượng cổ tu sĩ dùng thần thông vùi lấp và phong ấn. Trong núi có nhiều động phủ cổ tu sĩ và trong bảo khố còn lưu hai kiện thông thiên linh bảo, khiến Diệp gia âm thầm mưu tính phá cấm suốt nhiều năm.","theLucLienQuan":["Diệp gia"],"nguon":["@c0976","@c1014","@c1035"]},{"id":"thong-dao-khong-lo-hac-sac-han-bang","name":"Thông đạo khổng lồ hắc sắc hàn băng","cn":"","capDo":"khac","parentId":"am-duong-quat","blurb":"Đoạn thông đạo cao hơn mười trượng trong Âm Dương Quật, hai bên là hắc sắc hàn băng.","detail":"Khu vực này có âm phong dày đặc hơn lối vào, khiến thần thức của nhóm Hàn Lập bị hạn chế và buộc họ phải dựa vào Tử U Châu cùng linh lực hộ thân khi tiến sâu.","theLucLienQuan":[],"nguon":["@c0977"]},{"id":"nga-re-ba-thong-dao","name":"Ngã rẽ ba thông đạo","cn":"","capDo":"khac","parentId":"am-duong-quat","blurb":"Điểm chia đường trong Âm Dương Quật gồm một đường lớn và hai đường nhỏ.","detail":"Tại đây Hàn Lập đề nghị nhóm tách ra hành động vì nếu cứ đi chung thì hai tháng không đủ tra xét toàn bộ huyệt động. Sau khi lưu tiêu ký pháp lực, nhóm chia thành ba hướng.","theLucLienQuan":[],"nguon":["@c0977"]},{"id":"huyet-dong-co-tieng-luyen-thi","name":"Huyệt động có tiếng luyện thi","cn":"","capDo":"khac","parentId":"am-duong-quat","blurb":"Huyệt động sâu trong Âm Dương Quật, nơi âm phong gào thét mạnh và vang ra tiếng như luyện thi.","detail":"Hàn Lập và Bạch Dao Di phát hiện nơi này sau hơn nửa ngày tìm kiếm không có kết quả. Gần lối vào huyệt động có lam sắc phi kiếm bị đóng băng cắm trong vách.","theLucLienQuan":[],"nguon":["@c0977"]},{"id":"huyet-dong-bo-hoang","name":"Huyệt động bỏ hoang","cn":"","capDo":"khac","parentId":null,"blurb":"Huyệt động âm hàn, tối đen mà Hàn Lập và Bạch Dao Di tiến vào sau khi xét lam sắc phi kiếm.","detail":"Không gian này có thông đạo tối dẫn tới khu vực tỏa lục quang. Hàn Lập dùng nguyệt quang thạch chiếu sáng khi cùng Bạch Dao Di đi sâu vào trong, trước khi phát hiện nhũ động có thây khô, pháp trận cổ và Nghiệt viên.","theLucLienQuan":[],"nguon":["@c0978"]},{"id":"nhu-dong-luc-quang","name":"Nhũ động lục quang","cn":"","capDo":"khac","parentId":"huyet-dong-bo-hoang","blurb":"Nhũ động rộng hơn ba mươi trượng, đỉnh và vách tỏa lục quang, là nơi thây khô bị xích trên thạch trụ xuất hiện.","detail":"Giữa nhũ động có thạch trụ buộc thây khô, xung quanh ẩn nhiều pháp trận cổ dưới đất đá. Đây cũng là nơi lam sắc phi kiếm phản ứng với thây khô, Nghiệt viên đánh lén Hàn Lập và Bạch Dao Di, và Hàn Lập nhận định có luyện hồn trận cổ.","theLucLienQuan":[],"nguon":["@c0978"]},{"id":"dong-quat-duoi-cot-da","name":"Động quật dưới cột đá","cn":"","capDo":"khac","parentId":null,"blurb":"Động quật nơi Hàn Lập và Bạch Dao Di rời đi sau khi thây khô bị kim hồ phá tan.","detail":"Sau khi hai người rời khỏi động quật dưới cột đá, bóng đen từ dưới mặt đất xuất hiện, dùng tro bụi và hắc khí hồi sinh thây khô rồi để thây khô giải phong nghiệt viên.","theLucLienQuan":[],"nguon":["@c0979"]},{"id":"thong-dao-sau-dong-quat-duoi-cot-da","name":"Thông đạo sau động quật dưới cột đá","cn":"","capDo":"khac","parentId":"dong-quat-duoi-cot-da","blurb":"Thông đạo mà Hàn Lập và Bạch Dao Di quay lại sau khi rời động quật.","detail":"Hàn Lập và Bạch Dao Di sau khi cho rằng thây khô đã bị phá tan thì trở lại thông đạo này để tiếp tục tiến lên phía trước.","theLucLienQuan":[],"nguon":["@c0979"]},{"id":"trang-vien-ha-gia-tren-dinh-nui","name":"Trang viên Hà gia trên đỉnh núi","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Chiến trường nơi Âm La tông vây công và tiêu diệt Hà gia tại Nam Cương.","detail":"Trang viên có cấm chế quầng sáng vàng bao phủ hơn nửa thôn trang, được hoàng bào tu sĩ Hà gia dùng trận kỳ chống đỡ trước gần trăm hắc bào tu sĩ Âm La tông. Cấm chế cuối cùng bị phá, tu sĩ Hà gia bị giết sạch và phàm nhân còn lại cũng bị hạ lệnh diệt trừ.","theLucLienQuan":["Hà gia","Âm La tông"],"nguon":["@c0979"]},{"id":"day-am-duong-quat","name":"Đáy Âm Dương Quật","cn":"","capDo":"khac","parentId":"am-duong-quat","blurb":"Khu vực đáy Âm Dương Quật nơi Hàn Lập hoạt động giữa hai Đại Phong Huyệt.","detail":"Đây là nơi Hàn Lập dùng phi kiếm màu vàng, Phệ kim trùng và Ích Tà thần lôi đối phó đàn bướm đen do âm khí huyễn hóa, đồng thời thu được khối Hắc tinh thạch thứ ba.","theLucLienQuan":[],"nguon":["@c0980"]},{"id":"dai-phong-huyet","name":"Đại Phong Huyệt","cn":"","capDo":"khac","parentId":"am-duong-quat","blurb":"Khu vực âm phong cực mạnh trong Âm Dương Quật, chứa Hắc tinh thạch và nhiều huyễn vật âm khí.","detail":"Trong Đại Phong Huyệt, thần thức Hàn Lập bị hạn chế, âm phong mạnh tới mức phải dựa vào Tử u thần quang và pháp lực bản thân. Sau khi Hàn Lập kéo Hắc tinh thạch khỏi thạch bích, âm phong quanh đó yếu đi rõ rệt.","theLucLienQuan":[],"nguon":["@c0980"]},{"id":"phong-huyet-nho","name":"Phong huyệt nhỏ","cn":"","capDo":"khac","parentId":"am-duong-quat","blurb":"Những nhánh phong huyệt nhỏ nơi Hàn Lập tiếp tục dò tìm Âm chi mã tuyệt sau khi rời Đại Phong Huyệt.","detail":"Hàn Lập tìm kiếm qua các phong huyệt nhỏ và thông đạo hẹp dần, có lúc gặp thạch bích chặn đường phải phá ra để tiếp tục tiến sâu trong Âm Dương Quật.","theLucLienQuan":[],"nguon":["@c0980"]},{"id":"giao-lo-thong-dao-am-duong-quat","name":"Giao lộ thông đạo","cn":"","capDo":"khac","parentId":"am-duong-quat","blurb":"Điểm tụ họp của nhóm Hàn Lập trước khi vào thông đạo nơi phát hiện Âm chi mã tuyệt.","detail":"Hàn Lập gặp đại hán họ Nguyên và lão giả họ Phú tại đây, rồi chờ Hắc y mỹ phụ và Bạch Dao Di tới đủ. Sau khi cả nhóm rời đi, ba thây khô đen thui xuất hiện tại giao lộ và nhìn theo hướng họ đi.","theLucLienQuan":[],"nguon":["@c0980"]},{"id":"thong-dao-phia-dong-am-duong-quat","name":"Thông đạo phía đông","cn":"","capDo":"khac","parentId":"am-duong-quat","blurb":"Nhánh thông đạo nơi Âm chi mã tuyệt được phát hiện trong Âm Dương Quật.","detail":"Sau khi tụ họp, nhóm Hàn Lập bố trí vài pháp trận đơn giản ở lối vào rồi cùng bay vào hướng đông của thông đạo để truy bắt Âm chi mã tuyệt.","theLucLienQuan":[],"nguon":["@c0980"]},{"id":"mat-dong-thong-dao","name":"Mặt đông thông đạo","cn":"","capDo":"khac","parentId":"giao-lo-thong-dao-am-duong-quat","blurb":"Mặt đông thông đạo là khu vực nhóm tu sĩ lần theo các hang bên để tìm Âm Chi Mã.","detail":"Nhóm tu sĩ đi dọc mặt đông thông đạo, chia nhau vào các hang bên thăm dò, thường ba người vào hang còn những người khác canh ngoài để phòng Âm Chi Mã nhân cơ hội bỏ trốn.","theLucLienQuan":[],"nguon":["@c0981"]},{"id":"hang-dong-nho-noi-dai-han-ho-nguyen-phat-hien-am-chi-ma","name":"Hang động nhỏ nơi đại hán họ Nguyên phát hiện âm chi mã","cn":"","capDo":"khac","parentId":"mat-dong-thong-dao","blurb":"Hang nhỏ này lưu lại dấu vết rõ ràng của Âm Chi Mã.","detail":"Hang có âm phong cực yếu, hơi ấm, đất cát mềm, vài khối noãn ngọc nguyên quáng, hương thơm lạ và dấu vó ngựa nhỏ; lão giả họ Phú xác nhận đây là nơi Âm Chi Mã từng ở.","theLucLienQuan":[],"nguon":["@c0981"]},{"id":"thong-dao-duoi-long-dat","name":"Thông đạo dưới lòng đất","cn":"","capDo":"khac","parentId":"am-duong-quat","blurb":"Hệ thống thông đạo dưới lòng đất dẫn Hàn Lập và Hắc y mỹ phụ tới hiện trường biến cố của nhóm truy đuổi Âm Chi Mã.","detail":"Sau khi ấn ký trên người Nguyên đạo hữu biến mất, Hàn Lập và Hắc y mỹ phụ men theo hướng thông đạo, liên tục vượt qua bảy tám thông đạo và đi thêm khoảng mười dặm để tới khu vực phát hiện quảng trường dưới lòng đất.","theLucLienQuan":[],"nguon":["@c0983"]},{"id":"khu-trong-trai-co-khoang-thach","name":"Khu trống trải có khoáng thạch","cn":"","capDo":"khac","parentId":"thong-dao-duoi-long-dat","blurb":"Khu vực sáng ngời phía trước thông đạo, khắp nơi có khoáng thạch và dẫn vào quảng trường nhỏ.","detail":"Đây là khu vực Hàn Lập và Hắc y mỹ phụ nhìn thấy sau khi đi qua nhiều thông đạo. Nơi này có ánh sáng và khoáng thạch, là vùng chuyển tiếp trước quảng trường nhỏ có cự trận.","theLucLienQuan":[],"nguon":["@c0983"]},{"id":"quang-truong-nho-duoi-long-dat","name":"Quảng trường nhỏ dưới lòng đất","cn":"","capDo":"khac","parentId":"khu-trong-trai-co-khoang-thach","blurb":"Hiện trường chính của biến cố nhóm truy bắt Âm Chi Mã, nơi Nguyên đạo hữu chết, Phú lão giả và Bạch Dao Di bị nhốt, Ngân Sí Dạ Xoa xuất hiện.","detail":"Quảng trường có thúy lục cự trúc ở giữa, cự trận phủ khắp mặt đất và hơn mười lăm cột đá trói hắc kiền thi. Tại đây Hàn Lập và Hắc y mỹ phụ phát hiện thi thể Nguyên đạo hữu, hai kén Sát Hồn Ti và lục mao quái vật lộ thân phận Ngân Sí Dạ Xoa.","theLucLienQuan":[],"nguon":["@c0983"]},{"id":"thuy-luc-cu-truc","name":"Thúy lục cự trúc","cn":"","capDo":"khac","parentId":"quang-truong-nho-duoi-long-dat","blurb":"Cây trúc lớn màu lục ở giữa quảng trường dưới lòng đất, bên dưới có cự trận và Ngân Sí Dạ Xoa xuất hiện.","detail":"Thúy lục cự trúc vươn lên tới đỉnh động, phía dưới bố trí cự trận gần như phủ khắp quảng trường. Ngân Sí Dạ Xoa ngồi dưới cây trúc này ăn thi thể Nguyên đạo hữu khi Hàn Lập và Hắc y mỹ phụ tới nơi.","theLucLienQuan":[],"nguon":["@c0983"]},{"id":"vung-suong-mu-ao-canh","name":"Vùng sương mù ảo cảnh","cn":"","capDo":"khac","parentId":"quang-truong-nho-duoi-long-dat","blurb":"Không gian huyễn cảnh do Ngân Đồng Huyễn Thuật tạo ra trong trận giữa Ngân Sí Dạ Xoa, Hàn Lập và hắc y mỹ phụ.","detail":"Khi ngân quang phát động, Hàn Lập và hắc y mỹ phụ mở mắt ra thì thấy quảng trường, kén xám và Ngân Sí Dạ Xoa đều biến mất, xung quanh chỉ còn sương mù, hắc khí, ngân nhãn và trăng lưỡi liềm. Huyễn cảnh bị Hàn Lập phá bằng kim hồ Tịch Tà Thần Lôi.","theLucLienQuan":[],"nguon":["@c0984"]},{"id":"quang-truong-trong-cam-che","name":"Quảng trường trong cấm chế","cn":"","capDo":"khac","parentId":"thong-dao-duoi-long-dat","blurb":"Không gian chiến đấu có các cột đá và thây khô bố trí quanh pháp trận.","detail":"Sau khi Ngân Sí Dạ Xoa kích hoạt Khốn ma trận, toàn bộ quảng trường bị hắc sắc quang mang bao phủ, nhốt Hàn Lập, hắc y mỹ phụ và chính Ngân Sí Dạ Xoa trong phạm vi cấm chế.","theLucLienQuan":[],"nguon":["@c0985"]},{"id":"cot-da-co-thay-kho","name":"Cột đá có thây khô","cn":"","capDo":"khac","parentId":"quang-truong-trong-cam-che","blurb":"Các cột đá quanh quảng trường có thây khô liên quan đến cấm chế Khốn ma trận.","detail":"Khi Ngân Sí Dạ Xoa đánh xuống đất, thây khô trên các cột đá đồng loạt phun hắc khí, tạo thành tầng quang mang đen khổng lồ bao phủ chiến trường.","theLucLienQuan":[],"nguon":["@c0985"]},{"id":"khe-phong-an-phia-bac-tieu-ho","name":"Khe phong ấn phía bắc tiểu hồ","cn":"","capDo":"khac","parentId":"tieu-ho-o-nam-cuong","blurb":"Khe phong ấn nằm phía bắc tiểu hồ hơn hai mươi dặm. Nó sâu dưới đất ngàn trượng, dài hơn mười trượng và là lối Diệp gia dùng để tiếp tục tiến vào Côn Ngô sơn.","detail":"Bạch phát lão giả dùng pháp trận tìm được vị trí khe phong ấn, sau đó Diệp gia tới rừng rậm phía bắc, xác nhận bằng pháp bàn và cưỡi cự hình ngô công thổ độn xuống đất.","theLucLienQuan":["Diệp gia"],"nguon":["@c0990"]},{"id":"rung-ram-phia-bac-tieu-ho","name":"Rừng rậm phía bắc tiểu hồ","cn":"","capDo":"khac","parentId":"tieu-ho-o-nam-cuong","blurb":"Khu rừng rậm ở phương bắc tiểu hồ, nơi bạch phát lão giả dừng lại xác nhận vị trí khe phong ấn. Từ đây nhóm Diệp gia cưỡi ngô công thổ độn xuống lòng đất.","detail":"Đoàn chín tu sĩ Diệp gia bay tới rừng rậm phía bắc, bạch phát lão giả lấy ngân sắc pháp bàn ra kiểm tra rồi Cửu muội thả cự hình ngô công để cả nhóm đi xuống.","theLucLienQuan":["Diệp gia"],"nguon":["@c0990"]},{"id":"dinh-nui-cao-tu-hoi-tu-si-thap-giai","name":"Đỉnh núi cao tụ hội tu sĩ thấp giai","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Một đỉnh núi cao ở Nam Cương nơi hơn trăm tu sĩ thấp giai đang tụ hội. Khi quang trụ xuất hiện, họ đồng loạt chú ý tới dị tượng phương xa.","detail":"Địa điểm này cho thấy thiên tượng Côn Ngô sơn ảnh hưởng tới cả các nhóm tu sĩ cấp thấp, không chỉ các đại thế lực quanh tiểu hồ.","theLucLienQuan":["Nhóm tu sĩ thấp giai tụ hội trên đỉnh núi"],"nguon":["@c0990"]},{"id":"chan-nui-hoang-vo-danh","name":"Chân núi hoang vô danh","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Một chân núi hoang vô danh ở Nam Cương, nơi lão giả béo đứng cạnh thạch môn vừa mở. Ông nhìn thấy quang trụ ở chân trời và lộ vẻ suy nghĩ.","detail":"Cảnh lão giả béo nhìn quang trụ từ chân núi hoang góp phần cho thấy dị tượng lan rất xa và thu hút nhiều loại tu sĩ khác nhau.","theLucLienQuan":[],"nguon":["@c0990"]},{"id":"dia-danh-khong-ten-co-cu-dai-truyen-tong-tran","name":"Địa danh không tên có cự đại truyền tống trận","cn":"","capDo":"khac","parentId":null,"blurb":"Một địa điểm không tên giống nhũ động, có cự đại truyền tống trận. Hàn Lập, Đề Hồn thú và Thi lang xuất hiện tại đây sau truyền tống, còn dấu tích giam cầm Ngân Sí Dạ Xoa đã vỡ.","detail":"Hàn Lập tỉnh ở chính giữa truyền tống trận, phát hiện lục sắc ngọc phù tự hủy, vòng giam cầm Ngân Sí Dạ Xoa vỡ nát và Thi lang bị tiêu diệt gần đó.","theLucLienQuan":[],"nguon":["@c0990"]},{"id":"son-dong-truyen-tong","name":"Sơn động truyền tống","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Sơn động nơi nhóm Hàn Lập bị truyền tống tới, linh khí cực kỳ dư thừa và có cự hình truyền tống trận một chiều.","detail":"Nơi này giống hang động ngầm nhưng không có âm phong, linh khí dồi dào đến mức Hàn Lập nghi ngờ nằm trên cực phẩm linh mạch. Truyền tống trận dưới chân chỉ có một chiều, không thể đưa nhóm trở lại nơi cũ.","theLucLienQuan":[],"nguon":["@c0991"]},{"id":"cuc-pham-linh-mach","name":"Cực phẩm linh mạch","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Linh mạch bậc cực phẩm mà Hàn Lập suy đoán nằm dưới sơn động truyền tống.","detail":"Lượng linh khí trong sơn động quá dư thừa khiến Hàn Lập phán đoán nơi này tựa hồ nằm trên một linh mạch cực phẩm. Đây là nguyên nhân trực tiếp khiến khu vực có linh khí kinh người.","theLucLienQuan":[],"nguon":["@c0991"]},{"id":"thong-dao-bac-thang-da","name":"Thông đạo bậc thang đá","cn":"","capDo":"khac","parentId":"son-dong-truyen-tong","blurb":"Lối bậc thang đá từ sơn động truyền tống hướng lên trên, dài bất thường.","detail":"Hàn Lập đi theo thềm đá rất lâu, ban đầu nghi ngờ có cấm chế kéo dài lộ trình nhưng không phát hiện dao động trận pháp. Lối này dẫn ra bình thai trong khe núi.","theLucLienQuan":[],"nguon":["@c0991"]},{"id":"binh-thai-trong-khe-nui","name":"Bình thai trong khe núi","cn":"","capDo":"khac","parentId":"kinh-thien-cu-son","blurb":"Bình thai đá rộng hơn một ngàn trượng nằm giữa hai vách núi dựng đứng dưới chân cự sơn.","detail":"Đây là nơi Hàn Lập ra khỏi thông đạo bậc thang đá. Bình thai nằm trong khe sâu giữa hai vách núi, mở đường cho hắn bay ra ngoài hạp cốc để thăm dò toàn cảnh cự sơn.","theLucLienQuan":[],"nguon":["@c0991"]},{"id":"kinh-thien-cu-son","name":"Kình Thiên cự sơn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Ngọn cự sơn khổng lồ Hàn Lập phát hiện sau truyền tống, lớn vượt xa Thánh sơn Thiên tinh thành và bị bạch quang cấm chế bao phủ.","detail":"Sau khi rời hạp cốc và thăm dò cả ngày, Hàn Lập nhận ra ngọn núi này lớn đến mức Thánh sơn ở Loạn tinh hải chỉ như một phần chân núi. Toàn núi bị bạch quang cấm chế bao phủ, linh khí dồi dào nhưng vắng tiếng chim thú, tạo cảm giác nguy hiểm như tử sơn.","theLucLienQuan":["Thượng cổ tu sĩ"],"nguon":["@c0991"]},{"id":"son-dong-trong-cu-son","name":"Sơn động trong cự sơn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Nơi nhóm Hàn Lập tạm trú sau khi bị truyền tống đến ngọn núi lạ, dùng để hồi phục, bố trí cấm chế và luyện Bồi Nguyên đan.","detail":"Sơn động nằm trong phạm vi cự sơn linh khí sung túc. Hàn Lập bố trí pháp trận có tác dụng ẩn náu và cảnh báo, về sau cả nhóm lập thêm tụ linh pháp trận cùng cấm chế phòng hộ để lão giả họ Phú luyện Bồi Nguyên đan trước khi tiếp tục thăm dò ngọn núi.","theLucLienQuan":[],"nguon":["@c0992"]},{"id":"thach-dinh-tren-suon-nui-con-ngo","name":"Thạch đình trên sườn núi","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Điểm dừng chân của nhóm Diệp gia trên đường tiến vào Côn Ngô sơn, nơi họ hồi phục pháp lực và bị Sư cầm thú tập kích.","detail":"Thạch đình nằm trên sườn núi trong Côn Ngô sơn. Sau khi vượt phong ấn khe nứt, phần lớn tu sĩ Diệp gia tụ tập tại đây, cầm linh thạch điều tức; đại trưởng lão Diệp gia và Diệp gia Thất thúc phụ trách cảnh giới. Tử vụ mang theo Sư cầm thú lao tới khu vực này, dẫn đến trận giao chiến dữ dội.","theLucLienQuan":["Diệp gia"],"nguon":["@c0992"]},{"id":"van-tu-chi-mon","name":"Vạn Tu chi môn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Cổng chào nổi tiếng trên tuyến đường vào nơi cổ tu sĩ từng sinh sống trong Côn Ngô sơn, hiện bị cấm chế bao phủ.","detail":"Vạn Tu chi môn nằm phía trước bậc thang hơn mười dặm theo hướng Diệp gia thăm dò. Diệp gia Thất thúc phát hiện nơi này bị cấm chế bao phủ, cho rằng nếu không phá cấm thì không thể tiếp tục đi tới khu vực cổ tu sĩ sinh sống trong Côn Ngô sơn.","theLucLienQuan":["Diệp gia"],"nguon":["@c0992"]},{"id":"bac-da-cam-thach-trang-con-ngo","name":"Bậc đá cẩm thạch trắng","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Đường bậc đá cực rộng trong Côn Ngô sơn, xa trông như đường lên trời và dẫn về phía Vạn Tu chi môn.","detail":"Bậc đá cẩm thạch trắng là tuyến đường lớn trong Côn Ngô sơn mà đại trưởng lão Diệp gia quan sát từ khu vực thạch đình. Từ xa, con đường bậc đá kéo dài lên cao như đường thông thiên, là hướng Diệp gia phải đi để tiếp cận Vạn Tu chi môn.","theLucLienQuan":["Diệp gia"],"nguon":["@c0992"]},{"id":"pho-van-phu","name":"Phổ Vân phủ","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Địa điểm ở Nam Cương liên quan trực tiếp đến thiên tượng bảy cột sáng và phong ấn lớn dưới hồ vô danh, khiến nhiều thế lực cùng hướng tới.","detail":"Phổ Vân phủ là nơi gần hồ vô danh xuất hiện bảy cột ánh sáng chiếu thẳng lên không trung và phát hiện phong ấn khổng lồ bên dưới. Tin tức này kinh động nhiều tông môn Nam Cương; đại trưởng lão bí ẩn gần Vạn Độc cốc quyết định tới đây, còn Độc Thánh Môn cũng huy động lực lượng lớn vì nhận định sự kiện liên quan Côn Ngô sơn xuất thế.","theLucLienQuan":["Độc Thánh Môn"],"nguon":["@c0992","@c1070"]},{"id":"ho-vo-danh-gan-pho-van-phu","name":"Hồ vô danh gần Phổ Vân phủ","cn":"","capDo":"khac","parentId":"pho-van-phu","blurb":"Hồ nhỏ gần Phổ Vân phủ, nơi xuất hiện thiên tượng bảy cột sáng và dấu vết phong ấn lớn bên dưới.","detail":"Hồ vô danh gần Phổ Vân phủ là điểm phát sinh dị tượng bảy cột ánh sáng. Dưới hồ bị phát hiện có phong ấn khổng lồ, trở thành đầu mối khiến phe áo trắng, nhiều tông môn Nam Cương và đội Độc Thánh Môn chú ý, đồng thời gắn với việc Côn Ngô sơn xuất thế.","theLucLienQuan":["Độc Thánh Môn"],"nguon":["@c0992"]},{"id":"tieu-ho-phong-an","name":"Tiểu hồ phong ấn","cn":"","capDo":"khac","parentId":"pho-van-phu","blurb":"Khu tiểu hồ ở Phổ Vân phủ nơi bảy cột sáng và phong ấn khổng lồ dưới đất bị nhiều tu sĩ phát hiện.","detail":"Nơi đây tụ tập mấy trăm tu sĩ các cấp. Có người bay lên quan sát bảy cột sáng trên không, có người dùng thổ độn phù hoặc thổ độn thuật chui xuống đất thăm dò phong ấn, nhưng khe rách do tu sĩ Diệp gia gây ra vẫn chưa bị người ngoài phát hiện.","theLucLienQuan":["Độc Thánh môn","Các tông môn và gia tộc quanh Phổ Vân phủ"],"nguon":["@c0993"]},{"id":"son-dong-luyen-dan-trong-long-dai-son","name":"Sơn động luyện đan trong lòng đại sơn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Sơn động trong lòng núi nơi Hàn Lập, Bạch Dao Di và lão giả họ Phú luyện Bồi Nguyên đan.","detail":"Ba người trú trong sơn động để luyện Bồi Nguyên đan bằng lô đỉnh ánh vàng. Sau khi đan thành và chia xong, sơn động rung chuyển dữ dội, Hàn Lập giải khai cấm chế rồi dẫn đầu rời khỏi nơi này.","theLucLienQuan":[],"nguon":["@c0993"]},{"id":"hoang-tuyen","name":"Hoàng tuyền","cn":"","capDo":"khac","parentId":null,"blurb":"Địa danh trong truyền thuyết được Bạch Dao Di nhắc tới khi nói về số phận Côn Ngô sơn. Một truyền thuyết cho rằng linh sơn này từng bị dìm xuống hoàng tuyền.","detail":"Khi đọc cổ văn trên bia đá và nhận ra Côn Ngô sơn, Bạch Dao Di nhắc hai truyền thuyết khác nhau về số phận linh sơn. Một trong đó nói Côn Ngô sơn bị thượng cổ tu sĩ dìm xuống hoàng tuyền.","theLucLienQuan":[],"nguon":["@c0994"]},{"id":"bac-thang-len-nui","name":"Bậc thang lên núi","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Tuyến bậc thang trên Côn Ngô Sơn mà nhóm Hàn Lập tiếp tục ẩn nặc đi lên. Khu vực này nối tới đoạn thềm đá có Vạn Tu chi môn.","detail":"Sau khi Hàn Lập thu lam sắc tinh bi, nhóm ba người quyết định tiếp tục ẩn nặc dọc bậc thang hướng lên núi theo tiếng gầm. Phía trên là khu vực Diệp gia đang bày trận phá cấm.","theLucLienQuan":["Diệp gia"],"nguon":["@c0995"]},{"id":"suon-nui-cao-con-ngo","name":"Sườn núi cao Côn Ngô","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Khu vực sườn núi nơi Diệp gia huyền phù quan sát và bày trận phá Vạn Tu chi môn. Đây là điểm cấm chế đang bị công kích dữ dội.","detail":"Trên sườn núi cao, Quái nhân Diệp gia và Đại trưởng lão Diệp gia huyền phù quan sát, còn các tu sĩ Diệp gia đứng theo phương vị pháp trận để thúc giục pháp bảo công kích Vạn Tu chi môn.","theLucLienQuan":["Diệp gia"],"nguon":["@c0995"]},{"id":"phong-an-con-ngo-khu-vuc-phong-an","name":"Phong ấn Côn Ngô / khu vực phong ấn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Khu vực phong ấn trung tâm trong Côn Ngô sơn, nơi các tuyến nhân vật bị trận pháp và cấm chế chia cắt. Bên ngoài, cửa vào dưới lòng đất trở thành mục tiêu tranh đoạt của nhiều phe.","detail":"Trong khu vực này có Cửu chân phục ma trận, Vạn Tu chi môn, ảo trận sau cửa và cấm chế trên thềm đá. Bên ngoài tiểu hồ, khe nứt phía bắc phong ấn bị phát hiện, khiến Độc Thánh môn, Kiền lão ma và nhiều tu sĩ cùng lao xuống tranh cửa vào.","theLucLienQuan":["Độc Thánh môn","Âm La tông","Diệp gia"],"nguon":["@c0996"]},{"id":"long-dat-phia-bac-tieu-ho-hon-hai-muoi-dam","name":"Lòng đất phía bắc tiểu hồ hơn hai mươi dặm","cn":"","capDo":"khac","parentId":"tieu-ho-o-nam-cuong","blurb":"Vị trí dưới lòng đất có manh mối cửa vào phong ấn, ban đầu bị ảo trận che giấu. Độc Thánh môn phát hiện và cho người phá cấm tại đây.","detail":"Nơi này cách tiểu hồ hơn hai mươi dặm về phía dưới lòng đất, bị một ảo trận cố ý che đậy. Sau khi bị tu sĩ báo tin công khai, khu vực này kéo theo đông đảo tu sĩ độn xuống tranh đoạt.","theLucLienQuan":["Độc Thánh môn"],"nguon":["@c0996"]},{"id":"khong-gian-sau-hon-nghin-truong-duoi-long-dat","name":"Không gian sâu hơn nghìn trượng dưới lòng đất","cn":"","capDo":"khac","parentId":"long-dat-phia-bac-tieu-ho-hon-hai-muoi-dam","blurb":"Không gian lớn tối đen dưới lòng đất, phía dưới là tầng bạch quang dày đặc kèm lôi điện. Một điểm không phát lôi điện bị Độc Thánh môn canh giữ như cửa vào phong ấn.","detail":"Ở độ sâu hơn nghìn trượng, đám tu sĩ phát hiện tầng bạch quang bảo vệ có lôi điện kinh người. Chỉ một vị trí không có lôi điện được bảy tám đệ tử Độc Thánh môn canh giữ, khiến nơi này trở thành điểm giằng co trực tiếp.","theLucLienQuan":["Độc Thánh môn"],"nguon":["@c0996"]},{"id":"bach-sac-quang-mac-loi-vao-ao-tran","name":"Bạch sắc quang mạc / lối vào ảo trận","cn":"","capDo":"khac","parentId":"phong-an-con-ngo-khu-vuc-phong-an","blurb":"Bạch sắc quang mạc là màn sáng trắng ở lối vào ảo trận trong khu vực phong ấn. Kiền lão ma, nhóm Độc Thánh môn và năm tán tu Nguyên Anh lần lượt tiến vào nơi này.","detail":"Khi có người xông vào, mặt quang mạc nổi lam quang rồi nuốt mất bóng dáng. Đây là cửa ngõ khiến các thế lực và tán tu phải cân nhắc vì bên trong có ảo trận nguy hiểm.","theLucLienQuan":["Độc Thánh môn","Âm La tông"],"nguon":["@c0997"]},{"id":"khong-gian-thai-van-trong-ao-tran","name":"Không gian thải vân trong ảo trận","cn":"","capDo":"khac","parentId":"bach-sac-quang-mac-loi-vao-ao-tran","blurb":"Không gian thải vân là nơi Hàn Lập bị nhốt sau khi cấm chế phát động. Bốn phía chỉ có thải vân đủ màu, không thấy trời đất và rất khó xác định phương hướng.","detail":"Hàn Lập bay mãi không thoát, dùng Minh Thanh Linh Mục và nhiều pháp bảo công kích cũng không phát hiện mục tiêu thật. Không gian này thể hiện uy lực mê hoặc và vây khốn của ảo trận trong phong ấn.","theLucLienQuan":[],"nguon":["@c0997"]},{"id":"bac-thang-va-khoi-nui-da-co-linh-thao","name":"Bậc thang và khối núi đá có linh thảo","cn":"","capDo":"khac","parentId":"phong-an-con-ngo-khu-vuc-phong-an","blurb":"Đây là nơi Hàn Lập, Bạch Dao Di và lão giả họ Phú từng đi qua trước khi bị tách ra. Một gốc linh thảo hiếm mọc cạnh bậc thang đã dẫn tới biến cố cấm chế.","detail":"Lão giả họ Phú vì sốt ruột hái linh thảo nên nhổ lên, khiến cấm chế ẩn phát động và Hàn Lập lập tức bị cuốn vào ảo trận, còn Bạch Dao Di cùng lão giả họ Phú biến mất khỏi tầm mắt hắn.","theLucLienQuan":[],"nguon":["@c0997"]},{"id":"them-da-gan-cu-thach-linh-thao","name":"Thềm đá gần cự thạch linh thảo","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Vị trí nhóm Hàn Lập trở lại sau khi phá ảo thuật cấm chế.","detail":"Sau khi năm viên châu ngũ sắc bạo liệt phá cấm, Hàn Lập cùng Bạch Dao Di và Phú lão giả được đưa trở lại thềm đá gần cự thạch có linh thảo thật.","theLucLienQuan":["Thượng cổ tu sĩ Côn Ngô sơn"],"nguon":["@c0998"]},{"id":"cu-thach-co-linh-thao-va-tu-sac-tuong-qua","name":"Cự thạch có linh thảo và tử sắc tương quả","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Điểm đặt bẫy ảo thuật cấm chế, nơi có linh thảo thật và chùm quả tím hiện trên đá.","detail":"Cự thạch là nơi nhóm Hàn Lập tiến gần rồi rơi vào thượng cổ ảo thuật cấm chế. Sau khi phá trận, trên đá vẫn hiện gốc linh thảo cùng tử sắc tương quả, khác với linh thảo giả Phú lão giả từng hái.","theLucLienQuan":["Thượng cổ tu sĩ Côn Ngô sơn"],"nguon":["@c0998"]},{"id":"cu-dien-tren-con-ngo-son","name":"Cự điện trên Côn Ngô sơn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Không gian sâu trong Côn Ngô sơn nơi đội Diệp gia giao chiến với thạch khôi lỗi.","detail":"Trong cự điện này, đại đầu quái nhân và các tu sĩ Diệp gia liên tục khu động pháp bảo đối phó vô số khôi lỗi thú cầm từ các hành lang tràn ra. Sau khi nguồn khôi lỗi ở cuối hành lang bị phá, số khôi lỗi còn lại mới bị dọn sạch.","theLucLienQuan":["Diệp gia"],"nguon":["@c1000"]},{"id":"thien-dien-cuoi-hanh-lang","name":"Thiên điện cuối hành lang","cn":"","capDo":"khac","parentId":"cu-dien-tren-con-ngo-son","blurb":"Thiên điện ở cuối hành lang, là nơi phát sinh thạch khôi lỗi trong cự điện.","detail":"Bạch bào nho sinh phá cấm chế tiến vào thiên điện này và, theo chỉ điểm của Hàn trưởng lão, phá hủy các then chốt bên trong. Khi thiên điện bị phá, khôi lỗi trong cự điện không còn tiếp viện mới.","theLucLienQuan":["Diệp gia"],"nguon":["@c1000"]},{"id":"quang-truong-bach-ngoc-dai-cao","name":"Quảng trường bạch ngọc / đài cao","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Điểm giao hội cao rộng trong vùng trọng yếu Côn Ngô sơn, được Diệp gia chọn làm nơi quan sát đường đi.","detail":"Sau khi rời thạch điện, nhóm Diệp gia thấy nhiều thềm đá dẫn tới các nơi khác nhau và bị sương trắng che khuất điểm cuối. Bạch bào nho sinh định lên quảng trường bạch ngọc trên đài cao để quan sát trước, nhưng cả nhóm vừa bay lên đã bị cấm không cấm chế kéo rơi xuống.","theLucLienQuan":["Diệp gia"],"nguon":["@c1000"]},{"id":"cac-them-da-tren-nui-con-ngo","name":"Các thềm đá trên núi","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Hơn mười lối thềm đá trong vùng trọng yếu Côn Ngô sơn, dẫn tới các địa phương khác nhau.","detail":"Các thềm đá này xuất hiện sau khi đội Diệp gia rời thạch điện. Điểm cuối của chúng đều bị sương trắng che phủ, khiến nhóm Diệp gia phải tìm vị trí cao quan sát trước khi chọn đường tiến tiếp.","theLucLienQuan":["Diệp gia"],"nguon":["@c1000"]},{"id":"quang-mac-ngan-quang-thong-dao","name":"Quang mạc ngân quang thông đạo","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Khu vực ngân quang nơi Hàn Lập bay vào kiểm tra sau khi lối ra bị hủy. Kết quả xác nhận thông đạo trong ngắn hạn không thể thông hành.","detail":"Sau biến cố ảo trận tự bạo, Hàn Lập tiến vào vùng ngân quang để kiểm tra tình trạng thông đạo. Hắn trở ra với sắc mặt âm trầm và xác nhận hiện tại không thể qua lại.","theLucLienQuan":["Diệp gia","Độc Thánh môn","Âm La tông"],"nguon":["@c1001"]},{"id":"kim-thach-cac","name":"Kim Thạch các","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Kim Thạch các là một địa điểm được ghi trên bia ngọc ở quảng trường bạch ngọc. Tu sĩ Diệp gia suy đoán nơi này liên quan việc tồn trữ đồ vật.","detail":"Khi Diệp gia đọc các bia ngọc trên quảng trường, Kim Thạch các được nêu như một trong những khu vực trên Côn Ngô sơn. Nó không được chọn là mục tiêu hàng đầu so với Côn Ngô điện, Linh Bảo các và Trấn Ma tháp.","theLucLienQuan":["Diệp gia"],"nguon":["@c1001"]},{"id":"tuong-van-dien","name":"Tường Vân điện","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Tường Vân điện là một địa điểm ghi trên bia ngọc tại quảng trường bạch ngọc. Tu sĩ Diệp gia suy đoán đây có thể là nơi tĩnh tu hoặc không quá trọng yếu.","detail":"Tường Vân điện được nhắc trong lúc Diệp gia phân tích các địa điểm trên Côn Ngô sơn. Dù có tên trên bia ngọc, nơi này không được xếp vào ba mục tiêu khả nghi nhất chứa Thông Thiên Linh Bảo.","theLucLienQuan":["Diệp gia"],"nguon":["@c1001"]},{"id":"ky-linh-vien","name":"Kỳ Linh viện","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Kỳ Linh viện là một địa điểm được tu sĩ Diệp gia nhắc tới trong quá trình đọc bia ngọc. Nó thuộc nhóm các kiến trúc được cân nhắc trước khi Diệp gia chọn ba hướng trọng yếu.","detail":"Kỳ Linh viện xuất hiện trong danh sách địa điểm trên núi mà Diệp gia phân tích tại quảng trường bạch ngọc. Nội dung chương chỉ cho biết nó được dùng làm cơ sở so sánh khi chọn mục tiêu tìm linh bảo.","theLucLienQuan":["Diệp gia"],"nguon":["@c1001"]},{"id":"con-ngo-dien","name":"Côn Ngô điện","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Côn Ngô điện là địa điểm trung tâm nối thẳng từ quảng trường bạch ngọc. Đại đầu quái nhân cho rằng nơi này là hạch tâm của Côn Ngô sơn nên không thể bỏ qua.","detail":"Trong ba nơi bị nghi có liên quan Thông Thiên Linh Bảo, Côn Ngô điện được xem là kiến trúc trung tâm. Vì nhân thủ Diệp gia không đủ chia đều, tu sĩ mặt chữ điền được cử đi một mình thăm dò nơi này, mang theo Di Thiên trạc phòng thân.","theLucLienQuan":["Diệp gia"],"nguon":["@c1001","@c1016"]},{"id":"linh-bao-cac","name":"Linh Bảo các","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Linh Bảo các là một trong ba nơi Diệp gia cho là có khả năng chứa Thông Thiên Linh Bảo nhất. Đại trưởng lão Diệp gia chọn dẫn ba người tới đây sưu tầm bảo vật.","detail":"Từ tên gọi và vị trí trên bia ngọc, Linh Bảo các được Diệp gia xem như nơi thượng cổ tu sĩ có thể cất giữ bảo vật. Khi chia lực lượng, Đại trưởng lão Diệp gia ưu tiên địa điểm này và tự dẫn đội đi khảo sát.","theLucLienQuan":["Diệp gia"],"nguon":["@c1001"]},{"id":"tran-ma-thap","name":"Trấn Ma tháp","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Trấn Ma tháp là địa điểm được suy đoán liên quan việc trấn áp yêu ma và có thể chứa Thông Thiên Linh Bảo. Đại đầu quái nhân chọn tự mình đi khảo sát nơi này.","detail":"Trấn Ma tháp được Diệp gia xem là một trong ba nơi đáng nghi nhất vì bảo vật trấn áp yêu ma có thể nằm tại đó. Đại đầu quái nhân tỏ ra hứng thú với nơi giam yêu quỷ hung ác và nhận dẫn đội đi thăm dò.","theLucLienQuan":["Diệp gia"],"nguon":["@c1001","@c1017","@c1046"]},{"id":"them-da-co-ghi-chu","name":"Thềm đá có ghi chú","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Một lối thềm đá trên Côn Ngô Sơn đã được ghi chú rõ. Đại đầu quái nhân dẫn ba Cổ ma chọn lối này sau khi nhóm Diệp gia chia đường.","detail":"Sau khi chia hướng, Đại đầu quái nhân mang ba Cổ ma đi vào thềm đá có ghi chú, tách khỏi nho sinh và tu sĩ mặt chữ điền.","theLucLienQuan":["Diệp gia"],"nguon":["@c1002"]},{"id":"them-da-ngay-chinh-giua","name":"Thềm đá ngay chính giữa","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Lối thềm đá ở giữa trong khu vực chia đường của Diệp gia. Tu sĩ mặt chữ điền cầm Di Thiên trạc đi theo lối này và biến mất trong sương trắng.","detail":"Tu sĩ mặt chữ điền ôm quyền với nho sinh, nắm chặt Di Thiên trạc rồi đi vào thềm đá ngay chính giữa, thân hình dần khuất trong sương trắng.","theLucLienQuan":["Diệp gia"],"nguon":["@c1002"]},{"id":"dai-thu-xanh-biec-di-thuong","name":"Đại thụ xanh biếc dị thường","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Cây lớn nơi Sư cầm thú bay xuống sau khi thoát khỏi thạch điện. Từ hốc cây, phụ nhân áo đen hiện ra khi bị gọi.","detail":"Sau khi trốn khỏi thạch điện, Sư cầm thú bay tới một đại thụ xanh biếc dị thường và gọi phụ nhân áo đen từ bên trong thân cây ra.","theLucLienQuan":[],"nguon":["@c1002"]},{"id":"thach-dien-con-ngo-son","name":"Thạch điện Côn Ngô Sơn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Đại điện cổ xưa trên Côn Ngô Sơn nơi từng có nhiều thạch linh hoặc thạch khôi lỗi. Đoàn Hàn Lập tới đây sau một ngày một đêm phá cấm chế và gặp lại Sư cầm thú.","detail":"Trong thạch điện còn mảnh vụn của thạch linh, khiến Hàn Lập nhận định chúng có thể do bí thuật thượng cổ tạo thành. Sư cầm thú lén tiếp cận tại đây nhưng bị Kiền lão ma phát hiện rồi bỏ chạy.","theLucLienQuan":["Diệp gia"],"nguon":["@c1002"]},{"id":"trong-dia-con-ngo-son","name":"Trọng địa Côn Ngô sơn","cn":"","aliases":["Khu thềm đá tử trúc lâm quảng trường bạch ngọc"],"capDo":"khac","parentId":"con-ngo-son","blurb":"Trọng địa Côn Ngô sơn là khu vực sau thạch điện, nơi nhóm Hàn Lập gặp cấm không và rừng tử trúc che kín quảng trường bạch ngọc. Đây là cửa ải trọng yếu trước khi đuổi kịp nhóm tu sĩ đi trước.","detail":"Vừa ra khỏi thạch điện, nhóm Hàn Lập gặp tình trạng cấm không và rơi xuống, từ đó biết đã đến nơi trọng yếu của Côn Ngô sơn. Phía trước là thềm đá dẫn vào rừng tử trúc lớn, tử khí và linh áp kinh người bao phủ, che khuất quảng trường bạch ngọc.","theLucLienQuan":["Diệp gia","Độc Thánh môn"],"nguon":["@c1003"]},{"id":"loi-vao-phong-an-duoi-long-dat-phuong-bac","name":"Lối vào phong ấn dưới lòng đất phương bắc","cn":"","capDo":"khac","parentId":"trong-dia-con-ngo-son","blurb":"Lối vào sâu dưới lòng đất ở phương bắc, hiện thành khe nứt rộng mấy trượng sau khi ảo trận tự bạo.","detail":"Khu vực này nằm sâu khoảng hai mươi dặm dưới đất, là nơi khe nứt phong ấn xuất hiện với ngân quang và ngân lãng dao động nguy hiểm. Sau khi tán tu và tiểu thế lực tránh xa, Hóa Tiên tông, phe Âm La tông–Thiên Lan và Thái Nhất môn giằng co quanh lối vào; sau đó các nhóm lần lượt dùng Linh Tê khổng tước, Nhật Nguyệt toa hoặc ở lại chờ Linh Quy phi xa để vượt qua.","theLucLienQuan":["Hóa Tiên tông","Âm La tông","Thiên Lan thảo nguyên","Thái Nhất môn","Thiên Ma tông"],"nguon":["@c1004"]},{"id":"khong-gian-giam-cu-vat","name":"Không gian giam cự vật","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Khu vực trong Côn Ngô sơn nơi một cự vật như ngọn núi nhỏ bị cấm phù, xiềng xích và pháp trận hoàng quang trấn áp. Tầng tầng cấm chế bao phủ khiến nơi này đặc biệt quỷ dị.","detail":"Không gian này chứa cự vật bị khóa chặt bằng cấm phù, xiềng xích và gương đồng phóng hoàng quang pháp trận. Những lớp cấm chế cuộn chồng vô tận cho thấy đây là nơi phong cấm trọng yếu.","theLucLienQuan":[],"nguon":["@c1005"]},{"id":"khong-gian-cung-dien-linh-khi-sung-man","name":"Không gian cung điện linh khí sung mãn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Không gian liền kề nơi giam cự vật, linh khí dày đặc như tiên cảnh. Bên trong có cung điện hoa lệ, kỳ hoa dị thảo và đại pháp trận cổ.","detail":"Nơi này có linh khí sung mãn, cảnh vật gần như tiên cảnh, nhưng lại chứa cung điện rộng lớn đặt trong đại pháp trận và nhiều tế đàn thờ thạch nhân, tạo cảm giác cổ xưa khó lường.","theLucLienQuan":[],"nguon":["@c1005"]},{"id":"cung-dien-than-bi","name":"Cung điện thần bí","cn":"","capDo":"khac","parentId":"khong-gian-cung-dien-linh-khi-sung-man","blurb":"Cung điện hoa lệ rộng mấy trăm trượng trong không gian linh khí sung mãn. Nó nằm ở trung tâm đại pháp trận, quanh đó có tám mươi mốt tế đàn nhỏ.","detail":"Cung điện yên tĩnh không bóng người, được xây ở trung tâm pháp trận lớn. Bố cục xung quanh gồm các tế đàn và bạch ngọc thạch nhân mặc kim giáp khiến nơi này giống trung tâm của một cơ quan cổ.","theLucLienQuan":[],"nguon":["@c1005"]},{"id":"tam-muoi-mot-te-dan-nho","name":"Tám mươi mốt tế đàn nhỏ","cn":"","capDo":"khac","parentId":"cung-dien-than-bi","blurb":"Hệ thống tế đàn cao khoảng mười trượng phân bố quanh cung điện thần bí. Mỗi tế đàn thờ một bạch ngọc thạch nhân mặc kim giáp và cầm kim sắc cự nhận.","detail":"Các tế đàn nằm trong bố cục đại pháp trận quanh cung điện. Số lượng tám mươi mốt và thạch nhân giống nhau cho thấy chúng là một phần quan trọng của nghi thức hoặc cấm chế cổ.","theLucLienQuan":[],"nguon":["@c1005"]},{"id":"quang-truong-sau-tu-vi-tinh-tran","name":"Quảng trường sau Tử Vi Tinh trận","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Quảng trường lộ ra sau khi Tử Vi Tinh trận bị phá. Nơi này có hơn mười bậc thang đá dẫn đến các khu vực khác nhau trong Côn Ngô sơn.","detail":"Khi tử vụ và ảo ảnh tan đi, nhóm tu sĩ đứng trên quảng trường với nhiều lối thềm đá phân nhánh. Các lối này khiến những người đến sau có thể tách hướng để tranh bảo hoặc tránh nhóm đi trước.","theLucLienQuan":[],"nguon":["@c1005"]},{"id":"chu-linh-duong","name":"Chú Linh đường","cn":"","capDo":"khac","parentId":"trong-dia-con-ngo-son","blurb":"Khu trang viên trong Côn Ngô Sơn được Hàn Lập chọn thăm dò sau khi tách nhóm.","detail":"Chú Linh đường nằm sau bậc thềm đá, bên ngoài có bạch sắc quang mạc bao phủ. Bên trong gồm lầu các, thạch ốc, kho hàng và Hóa Linh điện, nhưng khu ngoài mà Hàn Lập kiểm tra đều trống rỗng.","theLucLienQuan":[],"nguon":["@c1006"]},{"id":"quang-truong-bach-ngoc","name":"Quảng trường bạch ngọc","cn":"","capDo":"khac","parentId":"trong-dia-con-ngo-son","blurb":"Quảng trường nơi các nhóm tu sĩ chia đường sau khi phá trận.","detail":"Sau khi liên thủ phá trận, các nhóm tu sĩ từ quảng trường bạch ngọc chia nhau tiến vào những thềm đá khác nhau. Không lâu sau, Ngân Sí Dạ Xoa, xú phụ nhân và Sư Cầm Thú hiện thân tại đây để lần theo dấu các tu sĩ.","theLucLienQuan":[],"nguon":["@c1006"]},{"id":"thach-dinh-giua-suon-nui-con-ngo-son","name":"Thạch đình giữa sườn núi Côn Ngô Sơn","cn":"","capDo":"khac","parentId":"trong-dia-con-ngo-son","blurb":"Thạch đình nơi ngũ sắc khổng tước xuất hiện trong quang mạc.","detail":"Cùng thời điểm Hàn Lập tiến vào tuyến Chú Linh đường, tại thạch đình giữa sườn núi Côn Ngô Sơn có một ngũ sắc khổng tước vừa hiện ra nửa người từ trong quang mạc.","theLucLienQuan":[],"nguon":["@c1006"]},{"id":"hoa-linh-dien","name":"Hóa Linh điện","cn":"","capDo":"khac","parentId":"chu-linh-duong","blurb":"Thạch điện đỏ đậm nằm trong khu Chú Linh đường.","detail":"Hóa Linh điện tỏa khí nóng ra ngoài. Khi Hàn Lập vừa bước qua cửa điện, hai tai lập tức nghe tiếng lôi minh ầm vang và hắn phải đảo mắt quan sát bên trong.","theLucLienQuan":[],"nguon":["@c1006"]},{"id":"dai-dien-co-cu-dinh","name":"Đại điện có cự đỉnh","cn":"","capDo":"khac","parentId":"hoa-linh-dien","blurb":"Đại điện rộng hơn mười trượng, trung tâm đặt một cự đỉnh được mười hỏa trụ khắc xích giao phun hồng hà nung luyện.","detail":"Bên trong đại điện nhiệt độ cực cao, mười hỏa trụ vây quanh cự đỉnh và phun hồng hà vào thân đỉnh. Nơi này có pháp trận khống chế hỏa trụ, trận nhãn chôn ở góc điện; khi trận bị phá, Hàn Lập phát hiện bên dưới nền là hỏa trì cực phẩm cung cấp hỏa lực lâu dài. Đây cũng là nơi cự đỉnh đang luyện chân hỏa, về sau Thái Âm Chân Hỏa từ trong đỉnh thoát ra rồi bị Hàn Lập bắt giữ.","theLucLienQuan":["Cổ tu phụ trách hóa linh điện"],"nguon":["@c1007"]},{"id":"hoa-tri-cuc-pham-duoi-dai-dien","name":"Hỏa trì cực phẩm dưới đại điện","cn":"","capDo":"khac","parentId":"dai-dien-co-cu-dinh","blurb":"Mảng lửa đỏ nằm dưới đất hơn mười trượng, là nguồn hỏa lực cho hỏa trụ trong đại điện.","detail":"Hỏa trì cực phẩm ở sâu dưới nền đại điện, bị pháp trận phía trên che giấu cho tới khi Hàn Lập phá trận nhãn. Nguồn địa hỏa này giải thích vì sao mười hỏa trụ có thể liên tục phun hồng hà trong thời gian dài, đồng thời góp phần khiến cự đỉnh hấp thu địa hỏa lực suốt hơn vạn năm và biến hóa thành dị bảo hỏa thuộc tính có linh tính.","theLucLienQuan":["Cổ tu phụ trách hóa linh điện"],"nguon":["@c1007"]},{"id":"dai-dien-trong-hoa-linh-dien","name":"Đại điện trong Hóa Linh điện","cn":"","capDo":"khac","parentId":"hoa-linh-dien","blurb":"Đại điện nơi Hàn Lập thu hoạch Thái Âm Chân Hỏa, vật liệu trong suốt, chu hồng tiểu đỉnh và giao long hỏa trụ. Đây là không gian trung tâm của các diễn biến trong chương 1008.","detail":"Trong đại điện này, Ngân Nguyệt tỉnh lại và giúp Hàn Lập nhận diện Thái Âm Chân Hỏa. Hàn Lập phong cấm chân hỏa, phá băng cự đỉnh, thu vật liệu lạ, thu nhỏ cự đỉnh thành chu hồng tiểu đỉnh rồi chặt thu các giao long hỏa trụ trước khi rời Hóa Linh điện.","theLucLienQuan":[],"nguon":["@c1008"]},{"id":"dai-sanh-lam-quang-trong-tran-ma-thap","name":"Đại sảnh lam quang trong Trấn Ma tháp","cn":"","capDo":"khac","parentId":"tran-ma-thap","blurb":"Đại sảnh trong Trấn Ma tháp nơi nhóm Diệp gia và cổ ma bị đàn ác quỷ tóc đỏ bao vây, sau đó Độc Thánh môn tứ lão cũng xông vào.","detail":"Đại sảnh được bao phủ bởi lam quang trong Trấn Ma tháp. Tại đây đại đầu quái nhân, cổ ma và lão giả Diệp gia chống đỡ bảy tám ác quỷ tóc đỏ đã đạt âm phách ngưng hình; các pháp bảo đánh nát quỷ vật nhưng chúng lại hồi phục nhờ âm khí. Sau đó một lục sắc quang đoàn bay vào, hiện ra bốn người Độc Thánh môn, khiến cục diện trong sảnh chuyển thành đối đầu giữa nhiều phe giữa lúc Quỷ Vương vẫn ẩn nấp.","theLucLienQuan":["Diệp gia","Độc Thánh môn"],"nguon":["@c1009"]},{"id":"tang-thu-bay-tran-ma-thap","name":"Tầng thứ bảy của Trấn Ma tháp","cn":"","capDo":"khac","parentId":"tran-ma-thap","blurb":"Tầng trong Trấn Ma tháp nơi nhóm Diệp gia bị ác quỷ âm phách ngưng hình cản lại và Độc Thánh môn tứ lão tới sau.","detail":"Tầng thứ bảy là vị trí nhóm Diệp gia đã tiến tới sau khi vượt qua các tầng trước của Trấn Ma tháp. Tại tầng này, họ gặp đàn ác quỷ tóc đỏ khó tiêu diệt vì liên tục hấp thu âm khí hồi phục, đồng thời bị chân thân Quỷ Vương thao túng từ trong bóng tối. Độc Thánh môn tứ lão cũng đến tầng này theo manh mối kỳ bảo trong tháp, chạm mặt Diệp Nguyệt Thánh và nhóm Diệp gia.","theLucLienQuan":["Diệp gia","Độc Thánh môn"],"nguon":["@c1009"]},{"id":"dai-sanh-trong-ma-thap","name":"Đại sảnh trong ma tháp","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian trong ma tháp nơi nhóm Độc Thánh môn tách khỏi nhóm Diệp gia để đi xuống tầng kế tiếp.","detail":"Tại đại sảnh này, Hoa Thiên Kỳ dùng tiểu phiên xanh biếc cuốn bốn người Độc Thánh môn lao vào lối xuống, bỏ lại đại đầu quái nhân, cổ ma và Quỷ Vương. Sau đó lối xuống bị Tu Di Ngũ Hành Bích phong kín, khiến hai nhóm tạm thời bị ngăn cách.","theLucLienQuan":["Độc Thánh môn","Diệp gia"],"nguon":["@c1010"]},{"id":"loi-vao-tang-ke-tiep-trong-ma-thap","name":"Lối vào tầng kế tiếp","cn":"","capDo":"khac","parentId":"dai-sanh-trong-ma-thap","blurb":"Cửa xuống tầng dưới trong ma tháp, nơi nhóm Độc Thánh môn vượt qua trước khi bị phong bế.","detail":"Sau khi nhóm Hoa Thiên Kỳ đi qua, lối vào này bị một tinh bích lóng lánh do Tu Di Ngũ Hành Bích tạo thành chặn kín. Kiếm quang của đại đầu quái nhân đánh vào bị ngũ sắc hà quang hóa giải, khiến nhóm Diệp gia không thể lập tức truy kích.","theLucLienQuan":["Độc Thánh môn","Diệp gia"],"nguon":["@c1010"]},{"id":"tang-thu-tam-va-thu-chin-ma-thap","name":"Tầng thứ tám và tầng thứ chín của ma tháp","cn":"","capDo":"khac","parentId":null,"blurb":"Các tầng sâu hơn của ma tháp, được nhắc như khu vực có thể ẩn chứa nguy hiểm vượt tầng bảy.","detail":"Hoa Thiên Kỳ và những người liên quan suy đoán tầng tám, tầng chín có thể tồn tại vật bị tù cấm hoặc nguy hiểm đáng sợ hơn tầng bảy. Đây là hướng nhóm Độc Thánh môn mạo hiểm tiến xuống để tìm bảo vật nghi là thông thiên linh bảo.","theLucLienQuan":["Độc Thánh môn"],"nguon":["@c1010"]},{"id":"thach-that-co-hai-truyen-tong-tran","name":"Thạch thất có hai truyền tống trận","cn":"","capDo":"khac","parentId":"loi-vao-tang-ke-tiep-trong-ma-thap","blurb":"Thạch thất nhỏ dưới tầng, chứa hai truyền tống trận một đen một trắng.","detail":"Sau khi đi xuống hơn mười trượng, nhóm Độc Thánh môn tới một thạch thất vuông nhỏ, bốn vách trống trơn, chỉ có hai pháp trận đen trắng. Miêu sư đệ kiểm tra và xác nhận đây là truyền tống trận cự ly rất ngắn, khoảng cách không vượt quá trăm dặm; cuối cùng Hoa Thiên Kỳ chọn bạch truyền tống trận vì hắc trận gây cảm giác bất an.","theLucLienQuan":["Độc Thánh môn"],"nguon":["@c1010"]},{"id":"khong-gian-nhu-bong-lai-tien-canh","name":"Không gian như bồng lai tiên cảnh","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Điểm đến của bạch truyền tống trận, có linh khí nồng đậm và cảnh tượng như tiên cảnh.","detail":"Nhóm Hoa Thiên Kỳ được truyền tới một nơi có trời xanh mây trắng, linh hoa kỳ thảo và linh khí sung mãn. Bên trong còn có cung điện kim bích đặt trên pháp trận cực lớn, nhiều tế đàn và các thạch nhân cầm kim sắc cự nhận, tạo nên bố cục vừa kỳ dị vừa mang khí tức man hoang.","theLucLienQuan":["Độc Thánh môn"],"nguon":["@c1010"]},{"id":"cung-dien-kim-bich-co-nho","name":"Cung điện kim bích cỡ nhỏ","cn":"","capDo":"khac","parentId":"khong-gian-nhu-bong-lai-tien-canh","blurb":"Công trình kim bích trong không gian như bồng lai tiên cảnh, tọa lạc trên pháp trận siêu đại.","detail":"Cung điện này nằm phía trước điểm truyền tống của nhóm Độc Thánh môn, đặt trên một pháp trận cực lớn. Xung quanh có nhiều tế đàn và thạch nhân cầm kim sắc cự nhận, khiến cả nhóm kinh ngạc khi vừa đặt chân tới không gian mới.","theLucLienQuan":["Độc Thánh môn"],"nguon":["@c1010"]},{"id":"them-da-len-nui","name":"Thềm đá lên núi","cn":"","capDo":"khac","parentId":"trong-dia-con-ngo-son","blurb":"Lối thềm đá Hàn Lập dùng để thoát khỏi vòng vây sau khi vận dụng Tam Diễm phiến. Con đường này dẫn về hướng Côn Ngô điện.","detail":"Trong trận trên bạch ngọc quảng trường, Hàn Lập dùng Lôi độn lùi lên thềm đá rồi tiếp tục bay về phía đỉnh núi. Nhóm truy sát sau đó cũng lao theo hướng này, vì đây là con đường gần nhất dẫn tới Côn Ngô điện.","theLucLienQuan":["Thiên Lan","Âm La tông"],"nguon":["@c1011"]},{"id":"dinh-nui-con-ngo","name":"Đỉnh núi Côn Ngô","cn":"","capDo":"khac","parentId":"trong-dia-con-ngo-son","blurb":"Hướng Hàn Lập bay lên sau khi phá vây trên bạch ngọc quảng trường. Khu vực phía trước có thể còn Kiền lão ma và các tu sĩ khác.","detail":"Sau khi dùng Tam Diễm phiến, Hàn Lập không ở lại kiểm tra chiến quả mà lập tức bay lên hướng đỉnh núi. Hắn biết phía trước có thể có Kiền lão ma và các tu sĩ khác, nhưng vẫn phải chọn đường này do tình thế bị truy sát.","theLucLienQuan":[],"nguon":["@c1011"]},{"id":"them-da-dan-den-con-ngo-dien","name":"Thềm đá dẫn đến Côn Ngô điện","cn":"","capDo":"khac","parentId":"con-ngo-dien","blurb":"Đoạn thềm đá rất dài dẫn về phía Côn Ngô điện. Hàn Lập mất khoảng một ngày liên tục hóa thân hồ quang mới vượt hết nơi này.","detail":"Thềm đá nằm trên tuyến tiến vào Côn Ngô điện, dài đến mức Hàn Lập phải liên tục dùng lực lôi điện trong khoảng một ngày mới ra khỏi. Sau đoạn này, hắn tới khu thạch lâm cấm chế đã đổ nát.","theLucLienQuan":["Côn Ngô điện"],"nguon":["@c1012"]},{"id":"thach-lam-truoc-con-ngo-dien","name":"Thạch lâm trước Côn Ngô điện","cn":"","capDo":"khac","parentId":"con-ngo-dien","blurb":"Khu cột đá trước Côn Ngô điện, vốn là cấm chế đại trận. Khi Hàn Lập đi qua, nơi này đã bị phá hủy nặng.","detail":"Thạch lâm có các cột đá khắc văn phù và linh quang pháp chú, nhưng phần lớn cấm chế đã bị người khác dùng sức mạnh phá tan. Đá vụn và hố đá rải khắp, cho thấy đã có người mở đường qua đây trước Hàn Lập.","theLucLienQuan":["Côn Ngô điện"],"nguon":["@c1012"]},{"id":"suon-nui-da-truoc-son-mon-con-ngo","name":"Sườn núi đá trước sơn môn Côn Ngô","cn":"","capDo":"khac","parentId":"con-ngo-dien","blurb":"Đoạn dốc lát bằng tảng đá lớn nằm sau thạch lâm. Nơi này có thạch tượng nghiêng ngã và nhiều pháp khí rải rác trên mặt đất.","detail":"Sau khi vượt thạch lâm, Hàn Lập tới sườn núi đá có nền lát bằng những tảng đá lớn. Tại đây có nhiều thạch tượng bị nghiêng ngã, cùng các pháp khí dạng trường mâu và cự phủ nằm rải rác.","theLucLienQuan":["Côn Ngô điện"],"nguon":["@c1012"]},{"id":"thach-don-ben-canh-dai-cao","name":"Thạch đôn bên cạnh đài cao","cn":"","capDo":"khac","parentId":"bach-ngoc-quang-truong-truoc-son-mon","blurb":"Vật che khuất gần đài cao trước sơn môn. Ngân Sí Dạ Xoa cùng hai bóng mờ yêu vật ẩn nấp sau đó để quan sát chiến trường.","detail":"Thạch đôn nằm cạnh đài cao trước sơn môn, đủ để che giấu Ngân Sí Dạ Xoa và hai bóng mờ khác. Hàn Lập cảm thấy linh ba dị thường tại đây rồi dùng Minh Linh mục phát hiện sự mai phục.","theLucLienQuan":[],"nguon":["@c1012"]},{"id":"son-mon-bang-ngoc-bich","name":"Sơn môn bằng ngọc bích","cn":"","capDo":"khac","parentId":"con-ngo-dien","blurb":"Sơn môn tinh mỹ bằng ngọc bích nằm trước khu vực Côn Ngô điện. Hàn Lập đi tới đây sau khi bỏ lại thế giằng co trước quang mạc.","detail":"Sau khi thoát khỏi cấm chế, Hàn Lập đến một sơn môn bằng ngọc bích, nhìn thấy phía sau là đường đá trắng dẫn về cung điện cổ đại hùng vĩ. Hai bên có hàng đại thụ vàng cháy, nhưng thần thức của hắn không phát hiện dao động cấm chế rõ ràng.","theLucLienQuan":["Côn Ngô điện"],"nguon":["@c1013"]},{"id":"duong-da-trang","name":"Đường đá trắng","cn":"","capDo":"khac","parentId":"son-mon-bang-ngoc-bich","blurb":"Con đường trắng noãn từ sơn môn dẫn về Côn Ngô điện. Đây là nơi Hàn Lập bị cấm chế trọng áp vô hình ép quỳ.","detail":"Đường đá trắng nằm sau sơn môn bằng ngọc bích và dẫn về phía Côn Ngô điện. Khi Hàn Lập đi được hơn mười trượng, trọng áp vô hình bất ngờ giáng xuống khiến hắn gần như không thể động đậy.","theLucLienQuan":["Côn Ngô điện"],"nguon":["@c1013"]},{"id":"thach-lam-cuoi-duong-doc","name":"Thạch lâm cuối đường dốc","cn":"","capDo":"khac","parentId":"them-da-dan-den-con-ngo-dien","blurb":"Khu thạch lâm ở cuối đường dốc, nơi Mộc phu nhân và nữ tử tú lệ Hóa Tiên tông ẩn nấp quan sát các phe trước Côn Ngô điện.","detail":"Trong lúc các phe hợp lực công kích quang mạc, Mộc phu nhân và sư muội ẩn trong thạch lâm cuối đường dốc để theo dõi và bàn bạc về Kiền lão ma, Hàn Lập, Hóa long tỳ cùng phong ấn Côn Ngô Sơn.","theLucLienQuan":["Hóa Tiên tông"],"nguon":["@c1014"]},{"id":"son-mon-truoc-con-ngo-dien","name":"Sơn môn trước Côn Ngô điện","cn":"","aliases":[],"capDo":"khac","parentId":"con-ngo-son","blurb":"Sơn môn trước Côn Ngô điện là khu vực nhóm Kiền lão ma đuổi tới khi Hàn Lập đang bị kim từ trọng quang cản đường. Nơi đây có hai hàng kim từ linh mộc tạo thành cấm chế trọng lực.","detail":"Khu vực này nằm trước cung điện khổng lồ, có đường nhỏ giữa hai hàng cây nâu sẫm. Hàn Lập đang tiến từng bước nặng nề trong cấm chế, còn nhóm truy đuổi đứng ngoài đánh giá và tìm cách đốn cây phá cấm.","theLucLienQuan":["Diệp gia","Thiên Lan thánh điện","Âm La tông"],"nguon":["@c1015"]},{"id":"hai-hang-kim-tu-linh-moc","name":"Hai hàng kim từ linh mộc","cn":"","aliases":["Kim từ linh mộc"],"capDo":"khac","parentId":"son-mon-truoc-con-ngo-dien","blurb":"Hai hàng kim từ linh mộc là những đại thụ nâu sẫm hai bên đường trước Côn Ngô điện. Chúng sinh ra kim từ trọng quang và giấu phù chú thượng cổ trong thân cây.","detail":"Kim từ linh mộc hấp thu linh khí Côn Ngô Sơn nhiều vạn năm nên đã hóa thành linh tê mộc, rất khó bị chặt đổ. Chúng tạo trọng lực chồng chất, khắc chế bảo vật kim chúc tính, đồng thời trong mỗi cây có Minh ấn đại quang luân hàng ma chú mà Hàn Lập nhìn thấu.","theLucLienQuan":[],"nguon":["@c1015"]},{"id":"tran-ma-thap-tang-bay","name":"Trấn Ma Tháp tầng bảy","cn":"","capDo":"khac","parentId":"trong-dia-con-ngo-son","blurb":"Tầng thứ bảy dưới lòng đất của Trấn Ma Tháp trong Côn Ngô Sơn. Đây là nơi nhóm cổ ma phá tinh bích, phát hiện hai truyền tống trận đen trắng và xảy ra vụ giết trưởng lão Diệp gia.","detail":"Đại đầu quái nhân, cổ ma và trưởng lão Diệp gia dùng ba kiện bảo vật công kích tinh bích tại đây. Sau khi tinh bích vỡ, họ nhìn thấy hai truyền tống trận cỡ nhỏ, một đen một trắng.","theLucLienQuan":["Diệp gia","Độc Thánh môn","Thánh tộc"],"nguon":["@c1016","@c1065"]},{"id":"khong-gian-phong-an-song-thu-ngan-lang","name":"Không gian phong ấn song thủ ngân lang","cn":"","capDo":"khac","parentId":"trong-dia-con-ngo-son","blurb":"Không gian u ám mà hắc sắc truyền tống trận dẫn tới. Tại đây có song thủ ngân lang khổng lồ, tức hóa thân Nguyên Sát thánh tổ, bị nhiều tầng phong ấn giam giữ.","detail":"Không gian này có xích đen, phù cấm và hoàng sắc quang trụ từ gương đồng giam giữ hắc ảnh khổng lồ. Cổ ma và Diệp Nguyệt Thánh tới đây để câu thông thần hồn Nguyên Sát thánh tổ hóa thân.","theLucLienQuan":["Thánh tộc"],"nguon":["@c1016"]},{"id":"khong-gian-phong-be-gan-cung-dien","name":"Không gian phong bế gần cung điện","cn":"","capDo":"khac","parentId":"cung-dien-than-bi","blurb":"Không gian phong bế khác ở gần tòa cung điện. Trong đó có bàn thờ đặt ngân sắc hạp tử và thúy lục mộc xích lơ lửng phía trên.","detail":"Khi hắc sắc lang thủ của hóa thân Nguyên Sát bị đánh thức, ngân sắc hạp tử trong không gian này lóe sáng như có vật bên trong bừng tỉnh. Thúy lục mộc xích tiếp tục phát linh quang bao bọc hộp bạc.","theLucLienQuan":[],"nguon":["@c1016"]},{"id":"dien-co-ngan-hap","name":"Điện có ngân hạp","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Điện nơi ngân hạp được đặt dưới mộc xích phát lục quang. Hoa Thiên Kỳ đứng bất động trong điện, còn ba trưởng lão Độc Thánh môn khác không thấy bóng dáng.","detail":"Trong điện, mộc xích trên ngân hạp phát ra lồng lục quang làm ngân quang biến mất. Hoa Thiên Kỳ đứng cách bàn hơn mười trượng trong trạng thái đờ đẫn, còn ngoài cửa vang tiếng bạo liệt như có cấm chế đang vây người.","theLucLienQuan":["Độc Thánh môn"],"nguon":["@c1017"]},{"id":"cung-dien-an-tri-lang-hon","name":"Cung điện an trí lang hồn","cn":"","capDo":"khac","parentId":null,"blurb":"Cung điện nơi Ngân Nguyệt lang hồn đang ngủ say, được nối tới bằng truyền tống trận còn lại.","detail":"Đây là mục tiêu mà lang thủ màu đen sai Quái nhân đầu to tìm đến để giết Ngân Nguyệt lang hồn, nhằm ngăn việc dung hồn. Khu vực này có Diệt Tuyệt Đại Trận do Côn Ngô tam lão bố trí, dùng tám mươi mốt khẩu Tru Ma Đao hợp thành để diệt kẻ mang ma khí tới gần.","theLucLienQuan":["Côn Ngô tam lão"],"nguon":["@c1018"]},{"id":"bac-cuc-nguyen-quang","name":"Bắc Cực Nguyên Quang","cn":"","capDo":"khac","parentId":"con-ngo-dien","blurb":"Khu vực ngân sắc quang ti nguy hiểm bên trong hoặc gần Côn Ngô Điện.","detail":"Bắc Cực Nguyên Quang là trở ngại mà Kiền lão ma, tam yêu và Hàn Lập đều phải vượt qua khi tiến sâu vào Côn Ngô Điện. Bên trong khu vực này còn có ảo trận do cổ tu bố trí, bị Hàn Lập nhìn thấu bằng Minh Thanh linh nhãn.","theLucLienQuan":["Cổ tu"],"nguon":["@c1019"]},{"id":"duong-ngam-gan-nhat-nguyet-toa","name":"Đường ngầm gần Nhật Nguyệt Toa","cn":"","capDo":"khac","parentId":"con-ngo-dien","blurb":"Đường ngầm trong Côn Ngô Điện là lối Mộc phu nhân dùng ngân bài để âm thầm tới khu bàn án. Mộc Khôi cũng xuất hiện gần khu vực này mà nàng không phát hiện.","detail":"Lối ngầm này liên hệ với khả năng khống chế một phần cấm chế bằng ngân bài, giúp Mộc phu nhân cùng Nhật Nguyệt Toa tới trước các tu sĩ khác. Nó đồng thời là điểm Mộc Khôi lộ diện sau khi bí mật theo sau.","theLucLienQuan":["Côn Ngô tam lão"],"nguon":["@c1020"]},{"id":"ban-an-dat-bao-vat","name":"Bàn án đặt bảo vật","cn":"","capDo":"khac","parentId":"con-ngo-dien","blurb":"Bàn án đặt bảo vật là trung tâm cuộc tranh đoạt trong Côn Ngô Điện. Trên và quanh bàn án có tiểu kiếm, hàng ma trượng, thư cuốn, Hóa Long Tỳ cùng nhiều mộc bài.","detail":"Khu vực này chứng kiến Mộc Khôi bị cấm chế diệt, Hàn Lập và Mộc phu nhân tranh bảo, rồi huyết ảnh, ngân sắc quang đoàn và tử vụ từ Bắc Cực Nguyên Quang xông vào. Các bảo vật rơi xuống quanh bàn án khiến cục diện chuyển sang hỗn chiến.","theLucLienQuan":["Côn Ngô tam lão"],"nguon":["@c1020"]},{"id":"kim-ngan-cu-toa","name":"Kim Ngân Cự Toa","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Đại toa kim ngân sắc nơi nữ tử tú lệ Hóa Tiên Tông đứng thúc giục bạch sắc ngọc thước.","detail":"Trong chương này, Kim Ngân Cự Toa là vị trí của nữ tử tú lệ Hóa Tiên Tông khi nàng cố duy trì Tứ Tượng Xích để khốn Kiền lão ma cùng hai yêu.","theLucLienQuan":["Hóa Tiên Tông"],"nguon":["@c1021"]},{"id":"cu-dai-thai-lien","name":"Cự đại thải Liên","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Vùng uy năng thải Liên do Tứ Tượng Xích tạo ra trong cuộc tranh đoạt bảo vật.","detail":"Phụ nhân Hóa Tiên Tông nhập vào cự đại thải Liên để lấy Hóa Long Ấn và tiểu kiếm màu tím, trước khi uy năng Tứ Tượng Xích suy giảm khiến Kiền lão ma cùng hai yêu thoát khỏi áp chế.","theLucLienQuan":["Hóa Tiên Tông"],"nguon":["@c1021"]},{"id":"ngo-dien","name":"Ngô điện","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Khu vực điện phủ nơi Nhật Nguyệt toa bị Kiền lão ma, Ngân Sí Dạ Xoa và sư cầm thú truy đuổi. Từ phía sau điện, cuộc truy sát kéo tới Bắc cực nguyên quang.","detail":"Phía sau Ngô điện là đoạn mở đầu cuộc truy kích trong chương. Nhật Nguyệt toa do Mộc phu nhân điều khiển liên tục hứng công kích của Kiền lão ma cùng hai yêu trước khi tìm đường lao vào Bắc cực nguyên quang.","theLucLienQuan":["Hóa Tiên Tông","Âm La Tông"],"nguon":["@c1023"]},{"id":"dai-dien","name":"Đại điện","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Chiến trường hiện tại nơi Hàn Lập, Khuê Linh, Kiền lão ma và Ngũ tử đồng tâm ma giao chiến dữ dội.","detail":"Trong đại điện, Khuê Linh và đại khô lâu va chạm bằng cự phủ và cốt đao, khiến cả không gian rung lắc như sắp sập. Đây cũng là nơi Hàn Lập dùng Dương Hoàn tập kích Kiền lão ma và chuẩn bị chặn Huyết Ma Châu.","theLucLienQuan":["Âm La Tông"],"nguon":["@c1025"]},{"id":"cua-dai-dien","name":"Cửa đại điện","cn":"","capDo":"khac","parentId":"dai-dien","blurb":"Khu vực cửa điện nơi Hàn Lập đặt nhân hình khôi lỗi để chặn đường Kiền lão ma.","detail":"Hàn Lập đã bố trí nhân hình khôi lỗi ở cửa đại điện ngay từ đầu để đề phòng Kiền lão ma không giao chiến mà bỏ chạy. Mai phục tại đây khiến Kiền lão ma bị Lôi Hoả Cung và Lôi Mộc Tiễn đánh lén, buộc phải quay lại khu vực Hàn Lập đã chuẩn bị sẵn.","theLucLienQuan":[],"nguon":["@c1027"]},{"id":"thach-thai","name":"Thạch thai","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Vị trí Hàn Lập hạ xuống sau khi rời khu vực Bắc Cực Nguyên Quang. Từ đây, hắn tiếp tục đi theo Khuê Linh hướng tới lối bí ẩn rời khỏi Côn Ngô Sơn.","detail":"Sau khi vượt qua vùng cấm quang bên ngoài Côn Ngô Điện, Hàn Lập hạ xuống thạch thai rồi tiếp tục theo Khuê Linh. Đây là một điểm trung chuyển trên đường rút lui khỏi khu vực tranh đoạt.","theLucLienQuan":[],"nguon":["@c1028"]},{"id":"vet-nut-lon-tren-them-da","name":"Vết nứt lớn trên thềm đá","cn":"","capDo":"khac","parentId":"them-da-dan-den-con-ngo-dien","blurb":"Khe nứt khổng lồ dài hơn trăm trượng, sâu hơn ba mươi trượng trên thềm đá gần Côn Ngô Điện. Dấu vết này cho thấy bên ngoài điện từng xảy ra một đòn công kích kiểu đao kiếm cực mạnh.","detail":"Hàn Lập và Khuê Linh nhìn thấy khe nứt lớn trên đường rút lui, nhận ra đây là dấu vết của một kích bảo vật loại đao kiếm. Mức độ phá hoại khiến Hàn Lập tự thấy ngay cả dùng cự kiếm thuật cũng khó tạo thành cảnh tượng tương tự.","theLucLienQuan":[],"nguon":["@c1028"]},{"id":"vuc-sau-duoi-tran-ma-thap","name":"Vực sâu dưới Trấn Ma Tháp","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Vực sâu hiện ra ở cuối thềm đá khi khu vực Trấn Ma Tháp bị lún xuống.","detail":"Khi Hàn Lập và Khuê Linh đi tới cuối đường đá, bậc đá phía trước đã biến mất, đỉnh núi như bị gọt bay và bên dưới là vực sâu không thấy đáy. Cảnh tượng này cho thấy Trấn Ma Tháp đã chìm xuống dưới.","theLucLienQuan":[],"nguon":["@c1029"]},{"id":"binh-dai-hinh-vuong-lon","name":"Bình đài hình vuông lớn","cn":"","capDo":"khac","parentId":"vuc-sau-duoi-tran-ma-thap","blurb":"Bình đài lớn nơi Hàn Lập và Khuê Linh đặt chân sau khi xuống gần đáy vực. Từ đây có thềm đá dẫn vào Trấn Ma Tháp đảo ngược.","detail":"Bình đài nằm trong vùng kiến trúc lớn dưới vực sâu, là điểm dừng trước lối vào Trấn Ma Tháp. Hàn Lập đứng tại đây trước khi dùng Nguyệt quang thạch chiếu sáng và tiến vào tháp.","theLucLienQuan":["Cổ tu sĩ"],"nguon":["@c1030"]},{"id":"tang-ba-tran-ma-thap","name":"Tầng ba Trấn Ma Tháp","cn":"","capDo":"khac","parentId":"tran-ma-thap","blurb":"Một tầng trong Trấn Ma Tháp nơi Hàn Lập phát hiện thi thể hộ vệ nghi thuộc Diệp gia. Thi thể nằm cạnh cột đá và có dấu hiệu Nguyên Anh xuất khiếu.","detail":"Tầng ba đã có dấu vết chiến đấu sau khi tu sĩ đi trước tiến vào. Hàn Lập phát hiện một thi thể không quen biết, suy đoán thuộc nhóm Diệp gia, thiên linh mở rộng cho thấy Nguyên Anh từng rời thân xác.","theLucLienQuan":["Diệp gia"],"nguon":["@c1030"]},{"id":"tang-nam-tran-ma-thap","name":"Tầng năm Trấn Ma Tháp","cn":"","capDo":"khac","parentId":"tran-ma-thap","blurb":"Tầng trong Trấn Ma Tháp nơi xuất hiện hai thi thể, gồm một người toàn thân xanh biếc như trúng kỳ độc và đại hán tán tu bị chém nát.","detail":"Tầng năm cho thấy mức độ nguy hiểm tăng lên trong tháp. Hàn Lập phát hiện thi thể xanh biếc biến dạng và thi thể đại hán tán tu từng khiến hắn chú ý, sau đó xử lý thi thể rồi tiếp tục xuống tầng sáu.","theLucLienQuan":["Nhóm tán tu"],"nguon":["@c1030"]},{"id":"tang-sau-tran-ma-thap","name":"Tầng sáu Trấn Ma Tháp","cn":"","capDo":"khac","parentId":"tran-ma-thap","blurb":"Tầng nơi Hàn Lập phát hiện Bạch Dao Di còn sống nhưng bị phong trong khối băng lớn. Đây là điểm cho thấy bên trong Trấn Ma Tháp vẫn còn người sống sót sau giao chiến.","detail":"Tầng sáu chứa khối băng lớn phong Bạch Dao Di, bên trong vẫn còn dao động linh khí yếu. Hàn Lập kiểm tra rồi dùng tử sắc hỏa diễm hấp thu hàn khí, giải phong cho nàng tại đây.","theLucLienQuan":[],"nguon":["@c1030"]},{"id":"tang-thu-tam-tran-ma-thap","name":"Tầng thứ tám của Trấn Ma tháp","cn":"","capDo":"khac","parentId":"tran-ma-thap","blurb":"Tầng có cung điện, cự trận, tế đàn, thạch khôi lỗi và Bát Linh Thước.","detail":"Tầng thứ tám của Trấn Ma tháp là nơi Hàn Lập và Khuê Linh truyền tống tới theo trận màu trắng. Nơi đây có nhiều tu sĩ và yêu vật, cự trận quanh cung điện, hơn mười tế đàn, kim giáp thạch khôi lỗi và dị bảo Bát Linh Thước, tạo thành cục diện tranh đoạt hỗn loạn.","theLucLienQuan":["Âm La Tông","Hóa Tiên tông","Diệp gia","Thiên Lan"],"nguon":["@c1031"]},{"id":"cung-dien-tang-tam","name":"Cung điện tầng tám","cn":"","capDo":"khac","parentId":"tang-thu-tam-tran-ma-thap","blurb":"Cung điện tại tầng tám Trấn Ma tháp, phía trên treo Bát Linh Thước.","detail":"Phía trên cung điện tầng tám lơ lửng Bát Linh Thước. Quanh cung điện có cự trận và tế đàn, thạch khôi lỗi mặc kim giáp phối hợp cấm chế chém kim quang công kích tu sĩ.","theLucLienQuan":[],"nguon":["@c1031"]},{"id":"te-dan","name":"Tế đàn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Khu vực đặt pháp trận Thạch Khôi Lỗi và là điểm các phe hợp lực phá trận để tranh đoạt Bát Linh Thước.","detail":"Tế đàn có bạch quang và thạch nhân phòng thủ. Khi các tu sĩ cường công, thạch nhân bị đánh nát vẫn tái ngưng tụ, khiến nơi này trở thành nút thắt của cuộc đoạt bảo.","theLucLienQuan":["Diệp gia","Thiên Lan","Hóa Tiên Tông"],"nguon":["@c1032"]},{"id":"cung-dien","name":"Cung điện","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Đích đến phía sau cuộc phá trận, nơi Diệp gia hứa nhường các bảo vật khác cho Hàn Lập nếu họ đoạt được Bát Linh Thước.","detail":"Đại trưởng lão Diệp gia dùng toàn bộ bảo vật khác trong cung điện làm điều kiện lôi kéo Hàn Lập. Ông cũng đoán vị trưởng bối Diệp gia có thể đã lẻn vào trong cung điện.","theLucLienQuan":["Diệp gia"],"nguon":["@c1032"]},{"id":"cung-dien-trong-con-ngo-son","name":"Cung điện trong Côn Ngô Sơn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Cung điện nơi các tu sĩ đang hợp lực công kích pháp trận. Mộc Phu Nhân xem đây là địa điểm khả nghi nhất dẫn tới tầng chín Phong Ma tháp.","detail":"Trong cung điện, Bát Linh Thước và pháp trận hiện tại có thể liên quan cửa vào tầng thứ chín. Đây là điểm then chốt trong suy đoán của Mộc Phu Nhân khi tìm đường gia cố phong ấn Côn Ngô Sơn.","theLucLienQuan":["Hóa Tiên Tông"],"nguon":["@c1033"]},{"id":"phong-ma-thap-tang-thu-chin","name":"Phong Ma tháp tầng thứ chín","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Tầng cuối của Phong Ma tháp, nơi Mộc Phu Nhân nói có đầu mối cấm chế khống chế Côn Ngô Sơn. Muốn gia cố phong ấn phải đến đây.","detail":"Theo Mộc Phu Nhân, tầng thứ chín chứa mắt trận hoặc đầu mối then chốt của cấm chế khống chế cả Côn Ngô Sơn. Cửa vào tầng này có thể được pháp trận trong cung điện cùng Bát Linh Thước phong giữ.","theLucLienQuan":["Hóa Tiên Tông"],"nguon":["@c1033"]},{"id":"khong-gian-u-am-gan-do","name":"Không gian u ám gần đó","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Không gian nơi phân hồn Cổ Ma Thánh tổ trong Ngân Lang đang phá phong ấn. Tại đây có năm ma khí, gương đồng, Đại Chu Thiên Tinh Thần Liên và truyền tống trận màu đen.","detail":"Trong không gian u ám, cổ ma hai đầu bốn tay thúc năm ma khí rót vào Ngân Lang, còn phân hồn trong hắc sắc lang thủ liên tục dùng ma diễm, hắc điện và quang hà phá cấm. Khu vực này là trung tâm biến động của phong ấn cổ ma.","theLucLienQuan":[],"nguon":["@c1033"]},{"id":"con-ngo-son-loi-vao-vet-nut-phong-an","name":"Côn Ngô Sơn — lối vào vết nứt phong ấn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Khu vực ngoài vết nứt phong ấn, nơi hai ba trăm tu sĩ tụ tập. Huyền Thanh Tử ngồi chặn lối vào để ngăn họ xông vào trong.","detail":"Bên ngoài vết nứt có nhiều tu sĩ Kết Đan và hơn mười Nguyên Anh tụ lại. Huyền Thanh Tử dựa vào thanh danh Thái Nhất Môn cùng tu vi hậu kỳ để trì hoãn, trong khi La đạo hữu và Vũ đạo hữu gây sức ép đòi vào.","theLucLienQuan":["Thái Nhất Môn","Bích Lân Nhai","Âm La Tông","Hóa Tiên Tông"],"nguon":["@c1033"]},{"id":"vet-nut-phong-an-nam-cuong","name":"Vết nứt phong ấn Nam Cương","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Khu vực phong ấn tại Nam Cương, nơi nhiều nhóm tu sĩ đã tiến vào trước. Thiên Ma Tông và Thái Nhất Môn sau đó dùng cấm chế đại trận phong tỏa miệng vết nứt.","detail":"Vết nứt phong ấn Nam Cương là trung tâm biến cố trong chương này. Kiền lão ma, vài tán tu, Âm La Tông và người Thiên Lan Thảo Nguyên đã vào trước; sau đó Thất Diệu Chân Nhân cùng Huyền Thanh Tử dùng Linh Quy Phi Xa bay vào trong khi thuộc hạ dựng đại trận che kín miệng vết nứt.","theLucLienQuan":["Thiên Ma Tông","Thái Nhất Môn","Âm La Tông","Thiên Lan Thảo Nguyên"],"nguon":["@c1034"]},{"id":"chan-hoan-son","name":"Chân Hoàn Sơn","cn":"","capDo":"vuc","parentId":"dai-tan","blurb":"Một trong tứ đại linh mạch của Đại Tấn và là nơi Thái Nhất Môn tọa lạc. Khu vực gồm hơn mười vạn dặm sơn mạch cùng hàng trăm linh sơn lớn nhỏ.","detail":"Chân Hoàn Sơn được giới thiệu là địa bàn căn bản của Thái Nhất Môn, chính đạo đệ nhất tông môn. Trong phạm vi nơi này có Băng Hồn Cốc, một cấm địa bí mật ít đệ tử thường biết tới.","theLucLienQuan":["Thái Nhất Môn"],"nguon":["@c1034"]},{"id":"bang-hon-coc","name":"Băng Hồn Cốc","cn":"","capDo":"khac","parentId":"chan-hoan-son","blurb":"Sơn cốc nhỏ trong Chân Hoàn Sơn, linh khí ít ỏi, âm phong rét buốt và băng tuyết phủ lâu năm. Đây là cấm địa bí mật của Thái Nhất Môn.","detail":"Băng Hồn Cốc nằm trong Chân Hoàn Sơn, bên ngoài có ảo trận che đậy nhưng không có tu sĩ canh giữ. Dù điều kiện khắc nghiệt và ít người biết, hôi bào lão giả họ Hô vẫn xuyên qua ảo trận tới cuối cốc để gọi Bạch lão quỷ.","theLucLienQuan":["Thái Nhất Môn"],"nguon":["@c1034"]},{"id":"tran-ma-thap-tang-tam","name":"Trấn Ma Tháp tầng tám","cn":"","capDo":"khac","parentId":"tran-ma-thap","blurb":"Tầng tám Trấn Ma Tháp, khu vực trước cung điện nơi Hàn Lập và các tu sĩ đối phó thạch khôi lỗi. Đây cũng là nơi Ngân Nguyệt cảm ứng có thứ gì trong cung điện thức tỉnh.","detail":"Tầng tám có đại trận thạch khôi lỗi, các bạch ngọc thạch nhân cầm kim nhận và cấm chế ngăn đường. Khi số khôi lỗi còn lại không nhiều, Ngân Nguyệt đột nhiên đau đớn vì cảm ứng từ cung điện bên trong.","theLucLienQuan":[],"nguon":["@c1035"]},{"id":"ma-da-son","name":"Ma Đà Sơn","cn":"","capDo":"khac","parentId":"nhan-gioi","blurb":"Nơi Hô đạo hữu vốn tu thân dưỡng tĩnh trước khi tới Băng Hồn Cốc. Ông rời nơi này vì nhận tin Hướng Chi Lễ gặp nạn trong Côn Ngô Sơn.","detail":"Ma Đà Sơn được nhắc là địa bàn gắn với Hô đạo hữu, một Hóa Thần tu sĩ nhận truyền thư từ Phong lão quái rồi đi tìm Bạch đạo hữu để bàn chuyện cứu viện.","theLucLienQuan":[],"nguon":["@c1035"]},{"id":"ngoai-phap-tran","name":"Ngoài pháp trận","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Ngoài pháp trận là vị trí các tu sĩ như Hàn Lập, nhóm Diệp gia và thanh niên họ Từ quan sát biến cố tại cung điện. Tại đây, họ cũng trực tiếp chịu uy áp ánh mắt của Lung Mộng.","detail":"Khi linh áp trong cung điện bộc phát và hoàng quang lao ra nhắm Bát Linh Xích, nhiều tu sĩ đứng ngoài pháp trận quan sát. Sau khi Lung Mộng hiện thân, ánh mắt của nàng gây áp lực lên toàn trường, khiến tu sĩ yếu hơn phải lùi bước.","theLucLienQuan":["Diệp gia","Hóa Tiên Tông","Độc Thánh Môn"],"nguon":["@c1036"]},{"id":"truyen-tong-tran-gan-cung-dien","name":"Truyền tống trận gần cung điện","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Truyền tống trận gần cung điện là hướng mà Ngân Sí Dạ Xoa và Sư Cầm thú âm thầm lùi về. Hành động này diễn ra sau khi họ nghe các tên Linh Lung và Tuyết Linh.","detail":"Ngân Sí Dạ Xoa và Sư Cầm thú tỏ ra biết đôi chút lai lịch của Linh Lung, Tuyết Linh. Hai yêu trao đổi ánh mắt rồi nhẹ nhàng lùi về hướng truyền tống trận, thể hiện ý định tránh xa biến cố.","theLucLienQuan":[],"nguon":["@c1036"]},{"id":"truyen-tong-tran-mau-trang-dia-diem","name":"Truyền Tống Trận màu trắng","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Truyền Tống Trận màu trắng là đường lui mà Ngân Sí Dạ Xoa và Sư cầm thú định dùng. Hoa Thiên Kỳ cách không đánh sập nơi này để chặn hai yêu rút đi.","detail":"Trong khu vực cung điện, Ngân Sí Dạ Xoa và Sư cầm thú lặng lẽ lùi về phía Truyền Tống Trận màu trắng. Hoa Thiên Kỳ phát hiện và làm mặt đất nơi trận pháp sụp xuống thành hố sâu, khiến đường lui bị cắt đứt.","theLucLienQuan":[],"nguon":["@c1037"]},{"id":"cuu-chan-phuc-ma-dai-tran-khu-vuc","name":"Cửu Chân Phục Ma đại trận khu vực","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Khu vực chiến trường quanh Cửu Chân Phục Ma đại trận trong cung điện Côn Ngô Sơn. Hàn Lập đưa Ngân Nguyệt sang bên kia trận, còn nữ tử váy đen đứng ngoài trận phá kim quang nhưng không mạo hiểm xông vào.","detail":"Đây là nơi các phe đối diện ma vật hiện thân. Đại trận phun kim quang công kích nữ tử váy đen; nàng bắn tan đao quang nhưng vẫn tỏ ra kiêng kị, trong khi Hàn Lập, Ngân Nguyệt và những người khác tạm giữ khoảng cách quanh trận.","theLucLienQuan":["Diệp gia","Cổ ma xâm lấn nhân giới"],"nguon":["@c1038"]},{"id":"ha-dien","name":"Hạ điện","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Địa điểm được Khuê Linh dùng làm mốc so sánh về cấm chế. Nàng cho rằng trên không trung tại khu vực này cũng bị cổ tu bố trí pháp thuật cấm chế như hạ điện.","detail":"Hạ điện được nhắc trong nhận định của Khuê Linh về hệ thống cấm chế cổ tu. Theo nàng, cấm chế không chỉ có ở hạ điện mà cả không trung cũng bị phong tỏa, khiến Mộc phu nhân khó thoát.","theLucLienQuan":[],"nguon":["@c1038"]},{"id":"truyen-tong-tran-mau-den","name":"Truyền Tống Trận màu đen","cn":"","capDo":"khac","parentId":"thach-that","blurb":"Truyền Tống Trận màu đen là lối thoát còn nguyên vẹn phía sau lưng nhị ma trong thạch thất. Nó bị Cổ Ma hai đầu bốn tay canh giữ theo lệnh Hắc bào nữ tử.","detail":"Trận truyền tống này được trận kỳ che phủ và ban đầu trở thành mục tiêu rời khỏi nơi nguy hiểm của Hàn Lập, thanh niên họ Từ cùng các phe. Khi Hắc bào nữ tử sai Cổ Ma bay tới lơ lửng phía trên, ý định âm thầm thoát thân của mọi người bị phá hỏng.","theLucLienQuan":["Hắc bào nữ tử","Cổ ma hai đầu bốn tay"],"nguon":["@c1039"]},{"id":"thach-that","name":"Thạch thất","cn":"","capDo":"khac","parentId":"cung-dien","blurb":"Thạch thất là không gian nơi Hàn Lập, các phe và nhị ma cùng đối mặt trong chương 1039. Tại đây mọi người phát hiện Truyền Tống Trận màu đen và chứng kiến Hắc Phong Kỳ đối kháng Cửu Chân Phục Ma Trận.","detail":"Thạch thất bao gồm khu vực các phe quan sát, vị trí Diệp gia đứng quanh nho sinh áo trắng và lối truyền tống phía sau nhị ma. Thế cục trong thạch thất chuyển từ quan sát đại chiến sang tranh đoạt đường thoát khi Cổ Ma được lệnh canh Truyền Tống Trận.","theLucLienQuan":["Diệp gia","Thiên Lan Thảo Nguyên","Hắc bào nữ tử"],"nguon":["@c1039"]},{"id":"long-dat","name":"Lòng đất","cn":"","capDo":"khac","parentId":"thach-that","blurb":"Lòng đất dưới thạch thất là nơi Hàn Lập bố trí ngầm trong lúc đại chiến đang diễn ra. Khuê Linh độn xuống trước, sau đó mấy ngàn Phệ Kim Trùng cũng âm thầm dung nhập vào đây.","detail":"Khu vực này không phải địa điểm công khai của các phe mà là hướng bố trí bí mật của Hàn Lập. Việc Khuê Linh và Phệ Kim Trùng cùng nhập lòng đất tạo thành lớp chuẩn bị kín đáo trước khi Hắc Phong Kỳ bộc phát uy lực.","theLucLienQuan":["Hàn Lập","Khuê Linh"],"nguon":["@c1039"]},{"id":"khu-vuc-uy-nang-cua-hac-phong-ky","name":"Khu vực uy năng của Hắc Phong Kỳ","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Vùng ác phong vàng đen quanh Hắc Phong Kỳ, nơi thần thức và giác quan của Hàn Lập bị áp chế nghiêm trọng.","detail":"Tại khu vực này, thần thức vừa rời vòng bảo hộ đã bị ác phong thổi tan, phong trụ đen liên tục hình thành và hút màn hào quang. Hàn Lập chỉ còn dựa vào Minh Thanh Linh Mục để nhìn mơ hồ trong phạm vi mười trượng.","theLucLienQuan":["Cổ ma xâm lấn nhân giới"],"nguon":["@c1040"]},{"id":"buc-tuong-mau-xam","name":"Bức tường màu xám","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Tường cấm chế ở góc tối nơi cuồng phong yếu hơn, được Hàn Lập thử phá nhưng không thành.","detail":"Phi kiếm của Hàn Lập chỉ làm tường nứt rồi bị bạch quang hồi phục, còn Tam Diễm Phiến khoét sâu khoảng mười trượng nhưng không xuyên thủng. Hàn Lập nghi nơi này có liên hoàn cấm chế phản phệ nên không tiếp tục mạo hiểm.","theLucLienQuan":[],"nguon":["@c1040"]},{"id":"cung-dien-phia-sau","name":"Cung điện phía sau","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Hướng giao chiến dữ dội nơi Cửu Chân Phục Ma Trận, Hắc Phong Kỳ, hắc bào nữ tử và cổ ma còn đang vướng vào nhau.","detail":"Từ vị trí của Hàn Lập, phía cung điện vẫn truyền đến chấn động và giao chiến kịch liệt trong ác phong. Việc hắc bào nữ tử tạm không thể phân tâm khiến nhóm Hàn Lập có thời cơ thương lượng kế hoạch rời đi.","theLucLienQuan":["Cổ ma xâm lấn nhân giới"],"nguon":["@c1040"]},{"id":"khong-gian-cuong-phong","name":"Không gian cuồng phong","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Khu vực đầy cuồng phong và uy năng Hắc Phong Kỳ nơi các bên ẩn nấp, độn hành và giao chiến.","detail":"Trong chương này, nhóm Hàn Lập tách ra hành động trong cuồng phong, cổ ma canh giữ truyền tống trận màu đen, còn các mũi công kích từ mặt đất, trên cao và chính diện cùng đánh vào một điểm.","theLucLienQuan":["Cổ ma xâm lấn nhân giới","Thiên Lan Thảo Nguyên"],"nguon":["@c1041"]},{"id":"dinh-dien","name":"Đỉnh điện","cn":"","capDo":"khac","parentId":"cung-dien","blurb":"Vị trí Bát Linh Xích treo hiện và huyễn hóa tám linh thú vây công Hắc bào nữ tử.","detail":"Trên đỉnh điện, Bát Linh Xích phát uy huyễn hóa bát thú nhưng bị cuồng phong của Hắc Phong Kỳ ép đến mức khó trụ vững.","theLucLienQuan":[],"nguon":["@c1043"]},{"id":"khong-gian-phong-an","name":"Không gian phong ấn","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Không gian đang bị Hắc Phong Kỳ và Hỗn độn khai thiên làm dị biến dữ dội.","detail":"Mười trụ phong ấn đen trong không gian gần tàn, cuối chương cột sáng đen xuất hiện và chia nơi này thành hai nửa sáng tối, khiến bóng đêm phủ lên phía Hàn Lập.","theLucLienQuan":["Thánh tộc"],"nguon":["@c1043"]},{"id":"khong-gian-nho-bi-hac-phong-ky-phong-an","name":"Không gian nhỏ bị Hắc Phong kỳ phong ấn","cn":"","capDo":"khac","parentId":"khong-gian-phong-an","blurb":"Mảnh không gian nhỏ bị Hắc Phong kỳ phong ấn, khiến nhóm Hàn Lập bị vây và không thể truyền tống rời đi.","detail":"Sau khi hắc bào nữ tử thi triển không gian thần thông của Hắc Phong kỳ, mảnh không gian nhỏ trở nên mờ tối và bị phong kín; Truyền Tống Trận trong đó bị không gian chi lực phong trụ, buộc nhóm Hàn Lập phải tìm cách phá không gian hoặc chờ chủ nhân Hắc Phong kỳ buông cấm chế.","theLucLienQuan":["Nguyên Sát Thánh Tổ","Diệp gia"],"nguon":["@c1044"]},{"id":"truyen-tong-tran-trong-khong-gian-phong-be","name":"Truyền Tống Trận trong không gian phong bế","cn":"","capDo":"khac","parentId":"khong-gian-nho-bi-hac-phong-ky-phong-an","blurb":"Điểm thoát thân của nhóm Hàn Lập trong không gian phong bế, nhưng bị Hắc Phong kỳ ngăn kích phát.","detail":"Hàn Lập kiểm tra và xác định Truyền Tống Trận không hỏng, chỉ bị không gian chi lực của Hắc Phong kỳ phong trụ nên tạm thời không thể truyền tống người ra ngoài.","theLucLienQuan":[],"nguon":["@c1044"]},{"id":"khong-gian-cung-dien-co-bat-linh-xich","name":"Không gian cung điện có Bát Linh Xích","cn":"","capDo":"khac","parentId":"cung-dien-trong-con-ngo-son","blurb":"Chiến trường trong cung điện nơi các phe tranh đoạt Bát Linh Xích và đối đầu Nguyên Sát.","detail":"Tại không gian này, Lung Mộng ở trong cung điện can thiệp trận chiến, Hắc Phong Kỳ treo trên không được Nguyên Sát vận dụng, tu sĩ Diệp gia bị diệt thân thể và ba Nguyên Anh bị nuốt. Khi Ngân Lang yêu thể hiện hình, linh áp làm toàn bộ không gian rung động và mặt đất nứt ra.","theLucLienQuan":["Diệp gia","Cổ Ma xâm lấn nhân giới","Ngân Nguyệt tộc"],"nguon":["@c1045"]},{"id":"khong-gian-do-hac-phong-ky-vay-khon","name":"Không gian do Hắc Phong Kỳ vây khốn","cn":"","capDo":"khac","parentId":"khong-gian-phong-an","blurb":"Không gian hiện tại giam giữ nhóm Hàn Lập, được duy trì bởi uy lực của Hắc Phong Kỳ.","detail":"Hàn Lập nhận định muốn rời khỏi nơi này chỉ có thể dựa vào lực lượng mạnh mẽ hợp kích. Vì Nguyên Sát thánh tổ đang phân tâm ứng địch nên Hắc Phong Kỳ khó phát huy hết uy lực, tạo cơ hội để mọi người liên thủ đánh vào chướng bích không gian.","theLucLienQuan":[],"nguon":["@c1046"]},{"id":"ben-ngoai-chuong-bich","name":"Bên ngoài chướng bích","cn":"","capDo":"khac","parentId":"khong-gian-do-hac-phong-ky-vay-khon","blurb":"Khu vực phía sau lỗ thủng chướng bích, nơi nhóm đi trước lập tức rơi vào phục kích.","detail":"Sau khi lỗ thủng được mở, bên ngoài chướng bích bùng lên huyết quang, hắc ti và huyết hải, khiến thanh niên họ Từ, Linh Tê Khổng Tước và Lâm Ngân Bình rơi vào hiểm cảnh.","theLucLienQuan":["Thiên Lan thánh điện"],"nguon":["@c1047"]},{"id":"huyet-hai-ben-ngoai-chuong-bich","name":"Huyết hải","cn":"","capDo":"khac","parentId":"ben-ngoai-chuong-bich","blurb":"Vùng huyết vụ đặc quánh rộng hàng mẫu xuất hiện bên ngoài lỗ thủng chướng bích.","detail":"Huyết hải do quái vật lông trắng thao túng, phối hợp huyết nhận và huyết quang để vây chặt thanh niên họ Từ, đồng thời chia cắt chiến trường bên ngoài chướng bích.","theLucLienQuan":[],"nguon":["@c1047"]},{"id":"khong-gian-vach-tuong-giam-giu-ban-dau","name":"Không gian vách tường giam giữ ban đầu","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Khu vực có vách tường từng giam giữ nhóm Hàn Lập trước đó. Trong chương này vách bị kiếm khí xuyên thủng, mở đường cho Thất Diệu chân nhân và Huyền Thanh Tử xuất hiện.","detail":"Sau khi Hàn Lập vừa ổn định tình thế với người Thiên Lan, một đạo kiếm khí thô to từ vách tường nơi mọi người bị nhốt trước đó xuyên thủng, tạo thành cửa động lớn. Từ đó hai đạo kinh hồng bay ra, hóa thành Thất Diệu chân nhân và Huyền Thanh Tử.","theLucLienQuan":["Thiên Ma Tông","Thiên Lan thánh điện"],"nguon":["@c1051"]},{"id":"tang-thu-tam-con-ngo-son","name":"Tầng thứ tám Côn Ngô Sơn","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Không gian tầng tám nơi nhóm Hàn Lập, Huyền Thanh Tử và Thất Diệu chân nhân đang ở. Cuối chương, nơi này rung chuyển dữ dội khi phong ấn tầng chín bị mở.","detail":"Tầng thứ tám Côn Ngô Sơn là nơi mọi người trao đổi về cổ ma, Diệp gia, Thi hùng và thủ đoạn phá chướng bích. Khi cổ ma thánh tổ mở phong ấn tầng thứ chín, cung điện phát ra tiếng nổ, nhũ quang chuyển đen, mặt đất nứt, cảnh vật vặn vẹo và khe không gian xuất hiện.","theLucLienQuan":["Thái Nhất môn","Thiên Ma Tông","Diệp gia","Vạn Yêu Cốc"],"nguon":["@c1052"]},{"id":"tang-thu-chin","name":"Tầng thứ chín","cn":"","capDo":"khac","parentId":"tran-ma-thap","blurb":"Tầng có phong ấn bị cổ ma thánh tổ mở ra theo nhận định của Thất Diệu chân nhân. Việc mở phong ấn gây dị biến lan xuống tầng tám.","detail":"Thất Diệu chân nhân nhận ra cổ ma thánh tổ đang mở phong ấn của tầng thứ chín. Sự kiện này khiến không gian tầng tám chấn động, nứt vỡ và xuất hiện khe không gian nguy hiểm.","theLucLienQuan":["Cổ ma xâm lấn nhân giới"],"nguon":["@c1052"]},{"id":"cung-dien-hai-cot","name":"Cung điện hài cốt","cn":"","capDo":"khac","parentId":"tang-thu-tam-con-ngo-son","blurb":"Khu vực cung điện được Thất Diệu chân nhân nhìn về khi nói tới cổ ma. Từ hướng cung điện, tiếng nổ và các luồng sáng xuất hiện trước khi không gian tầng tám sụp vỡ.","detail":"Trong lúc Hàn Lập định kể sơ về cổ ma, hướng cung điện phát ra tiếng nổ lớn, phun hơn mười luồng nhũ quang trắng rồi chuyển thành đen. Dị biến từ khu vực này mở đầu cho cảnh không gian tầng tám bị xé rách.","theLucLienQuan":["Cổ ma xâm lấn nhân giới"],"nguon":["@c1052"]},{"id":"dien-con-ngo","name":"Điện Côn Ngô","cn":"","capDo":"khac","parentId":"con-ngo-son","blurb":"Địa điểm Hàn Lập nói mình đã chia tay Kiền lão ma. Sau khi chia tay tại đây, hắn không biết tung tích của lão.","detail":"Khi Thất Diệu chân nhân hỏi tung tích Kiền lão ma, Hàn Lập trả lời rằng Kiền đạo hữu đã chia tay hắn ở điện Côn Ngô và về sau không rõ tung tích.","theLucLienQuan":[],"nguon":["@c1052"]},{"id":"te-dan-ngoc-trang-tang-chin","name":"Tế đàn ngọc trắng tầng chín","cn":"","capDo":"khac","parentId":"tang-thu-chin","blurb":"Tế đàn ngọc trắng khổng lồ ở tầng thứ chín.","detail":"Tế đàn cao hơn trăm trượng, dưới rộng trên hẹp, bốn mặt có bậc thang và được thạch trụ trận pháp bao quanh. Đây là trung tâm chiến trường nơi cự lang hai đầu chiếm giữ và dường như cũng là nơi trấn áp đầu mối phong ấn.","theLucLienQuan":["Cổ ma xâm lấn nhân giới"],"nguon":["@c1053"]},{"id":"van-truong-ma-uyen-thien-nam","name":"Vạn trượng Ma Uyên Thiên Nam","cn":"","capDo":"khac","parentId":"thien-nam","blurb":"Nơi Hàn Lập từng thấy bia đá làm từ vật liệu giống Sất Linh Nhuyễn Ngọc.","detail":"Ký ức về bia đá ở vạn trượng Ma Uyên Thiên Nam giúp Hàn Lập nhận ra cảm giác quen thuộc của hai bia đá tại tế đàn tầng thứ chín.","theLucLienQuan":[],"nguon":["@c1053"]},{"id":"co-ma-gioi","name":"Cổ Ma giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Giới diện ma đạo được nói là nguồn gốc của Chân Ma Chi Khí truyền sang Nhân Giới.","detail":"Theo Lung Mộng, sau khi Cổ Ma mở thông đạo nối với Nhân Giới, Chân Ma Chi Khí từ Cổ Ma giới được truyền tới. Khí này mang tính chất đặc biệt, từng khiến tu sĩ thượng cổ bị ma hóa và có khả năng lâu dài chuyển hóa môi trường Nhân Giới.","theLucLienQuan":["Cổ Ma","Nguyên Sát Thánh Tổ"],"nguon":["@c1056"]},{"id":"nghich-linh-thong-dao","name":"Nghịch linh thông đạo","cn":"","capDo":"khac","parentId":null,"blurb":"Thông đạo mà Thi Hùng muốn mượn để phản hồi Linh Giới.","detail":"Thi Hùng bộc lộ ý định nhờ Lung Mộng tìm nghịch linh thông đạo để trở về Linh Giới. Lung Mộng cảnh báo tu vi chưa vượt Hóa Thần Kỳ khó chống đỡ không gian chi lực, đồng thời nói chỉ khi nàng hoàn toàn thu hồi thân thể vốn có mới có cách tìm lại vị trí thông đạo.","theLucLienQuan":["Lung Mộng","Vạn Niên Thi Hùng"],"nguon":["@c1056","@c1069"]},{"id":"bia-da-kham-hoa-long-ty","name":"Bia đá khảm Hóa Long Tỷ","cn":"","capDo":"khac","parentId":"te-dan","blurb":"Bia đá khảm Hóa Long Tỷ nằm bên cạnh hắc giáp nữ tử tại tế đàn. Nó bị mười đạo hắc ti bắn vào để kích hoạt biến hóa trên tế đàn.","detail":"Khi hắc giáp nữ tử muốn triệu hồi ma tượng, nàng bắn mười đạo hắc ti vào tấm bia đá khảm Hóa Long Tỷ. Hành động này khiến ô quang trên tế đàn, cột đá và ma khí dưới chân cùng biến động, dẫn đến ma tượng đen khổng lồ ngưng tụ.","theLucLienQuan":["Cổ ma xâm lấn nhân giới"],"nguon":["@c1058"]},{"id":"khong-trung-phia-tren-te-dan","name":"Không trung phía trên tế đàn","cn":"","capDo":"khac","parentId":"te-dan","blurb":"Không trung phía trên tế đàn là nơi ma tượng đen khổng lồ ngưng tụ. Đây cũng là vị trí hoàng hồng chi quang và ma trảo va chạm khi thế áp chế bị phá.","detail":"Sau khi ma khí từ tế đàn phóng lên, không trung phía trên tế đàn xuất hiện ma tượng đen mặc chiến giáp. Tại đây ma tượng vỗ tay tạo ma trảo đen khổng lồ, bắt giữ bảo vật trong hoàng hồng chi quang và phá thế liên thủ của tam bảo.","theLucLienQuan":["Cổ ma xâm lấn nhân giới"],"nguon":["@c1058"]},{"id":"khong-gian-chuong-bich","name":"Không gian chướng bích","cn":"","capDo":"khac","parentId":"te-dan-ngoc-trang-tang-chin","blurb":"Khu vực giao chiến bị không gian chướng bích ngăn cách, khiến việc thoát ra phải dựa vào thủ đoạn phá giới.","detail":"Trong lúc Nguyên Sát áp đảo chiến trường, Huyền Thanh Tử từng lấy Phá giới phù ra, chuẩn bị mạo hiểm phá không gian chướng bích để bỏ chạy nhưng còn chần chừ vì sợ thu hút ma tượng.","theLucLienQuan":[],"nguon":["@c1060"]},{"id":"cot-da-quanh-te-dan","name":"Cột đá quanh tế đàn","cn":"","capDo":"khac","parentId":"te-dan","blurb":"Hơn mười cột đá quanh tế đàn là bộ phận duy trì trận pháp và nguồn hắc ma khí. Gốc cột bị Phệ Kim Trùng cắn phá khiến linh quang tắt và trận pháp tạm dừng.","detail":"Các cột đá quanh tế đàn vốn góp phần vận chuyển hắc ma khí cho ma tượng thần niệm Nguyên Sát. Khi Phệ Kim Trùng cắn phá gốc cột, hơn mười cột đá mất tác dụng, khiến trận pháp đang kích phát dừng lại trong chốc lát.","theLucLienQuan":["Cổ Ma giới","Phân thân Nguyên Sát Thánh Tổ"],"nguon":["@c1061"]},{"id":"tam-bia-da-te-dan","name":"Tấm bia đá tế đàn","cn":"","capDo":"khac","parentId":"te-dan","blurb":"Tấm bia đá gắn với Hóa Long Tỳ là một trận cơ quan trọng của tế đàn. Khi nữ tử giáp đen đặt tay lên vật khảm trên bia, trận pháp tế đàn vận hành trở lại.","detail":"Tấm bia đá nằm tại khu vực tế đàn, có Hóa Long Tỳ khảm bên trên. Nó phát hắc mang sau khi phân thân Nguyên Sát đặt tay vào, kéo theo ma phong và trụ khí đen trồi lên để tái khởi trận pháp.","theLucLienQuan":["Cổ Ma giới"],"nguon":["@c1061"]},{"id":"vong-phong-an","name":"Vòng phong ấn","cn":"","capDo":"khac","parentId":"te-dan","blurb":"Khu vực trong phong ấn nơi Nguyên Sát nói đã đưa quái nhân đầu to vào từ đầu. Đây là mắt xích để truyền Chân Ma Khí và tạo điều kiện hóa ma.","detail":"Nguyên Sát tiết lộ đã dùng bí thuật đưa quái nhân đầu to vào vòng phong ấn, sau đó truyền Chân Ma Khí cho hắn. Vòng phong ấn vì vậy trở thành vị trí then chốt trong bố cục tạo Già Luân Chiến Ma và phá hoại phong ấn.","theLucLienQuan":["Cổ Ma Giới"],"nguon":["@c1062"]},{"id":"nui-con-ngo","name":"Núi Côn Ngô","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Hướng Chi Lễ vừa tiến vào thì bị phong ấn vào Không gian huyền diệu.","detail":"Được nhắc trong hồi ức — Hướng Chi Lễ trước đó vừa tiến vào núi Côn Ngô thì bị phong ấn.","theLucLienQuan":[],"nguon":["@c1064"]},{"id":"te-dan-con-ngo-son","name":"Tế Đàn (Côn Ngô Sơn)","cn":"","capDo":"khac","parentId":"nui-con-ngo","blurb":"Tế đàn khổng lồ nằm trong không gian phong ấn dưới Côn Ngô Sơn, là lõi của pháp trận phong ấn ma khí. Vốn cao hơn trăm trượng, bị phá huỷ hoàn toàn.","detail":"Tế Đàn vốn cao hơn trăm trượng nằm trong không gian phong ấn bên dưới Côn Ngô Sơn, là trung tâm của pháp trận phong ấn trấn áp ma khí. Sau vụ bạo dẫn Hắc Phong Kỳ bị chém mất nửa trên chỉ còn năm sáu trục trượng. Sau đó bị Hắc Lang phát tiếng rít phá huỷ hoàn toàn vỡ vụn, giải phóng ma khí đen như mực tràn ra bốn phía.","theLucLienQuan":[],"nguon":["@c1065"]},{"id":"tiet-diem-khong-gian","name":"Tiết điểm không gian","cn":"","capDo":"khac","parentId":null,"blurb":"Các điểm trời sinh bạc nhược trong Nhân Giới nơi bề mặt không gian yếu hơn, có thể tạo thông đạo đến Linh Giới bằng ngoại lực đủ lớn.","detail":"Ngoài Nghịch Linh Thông Đạo, trong Nhân Giới còn tồn tại một số ít tiết điểm không gian trời sinh bạc nhược. Cổ tu phát hiện hơn mười chỗ, một số cố định, một số thay đổi vị trí, không gian bất ổn cực kỳ nguy hiểm — nguy hiểm nhất là không gian phong bạo, đại thần thông bị cuốn vào cũng phải chết. Ma Giới xâm nhập Nhân Giới năm xưa cũng nhờ khám phá tiết điểm giữa Nhân Giới và Ma Giới.","theLucLienQuan":[],"nguon":["@c1067"]},{"id":"de-cuu-tang-khong-gian","name":"Đệ cửu tầng không gian","cn":"","capDo":"khac","parentId":"nui-con-ngo","blurb":"Tầng không gian thứ chín trong hệ thống không gian Côn Ngô Sơn, nơi phân thần Nguyên Sát Thánh Tổ chiếm giữ thân thể Linh Lung.","detail":"Nơi Linh Lung/Ngân Nguyệt cần trở về, nơi có phân thần Nguyên Sát Thánh Tổ đang chiếm giữ thân thể ban đầu của Linh Lung. Mục tiêu tiếp theo của Hàn Lập và Ngân Nguyệt là tiến nhập tầng này để đánh bại phân thần và đoạt lại thân thể.","theLucLienQuan":[],"nguon":["@c1067"]},{"id":"khong-gian-te-dan","name":"Không gian tế đàn (bên trong chướng bích)","cn":"","capDo":"khac","parentId":"nui-con-ngo","blurb":"Không gian bên trong chướng bích tại Côn Ngô Sơn, đầy ma khí nồng đặc, trung tâm có tế đàn đã bị phá với khô lâu đen phun ma khí và hắc động phía trên.","detail":"Không gian ma khí cực kỳ nồng đặc nằm sau chướng bích tại núi Côn Ngô. Trung tâm có tế đàn đã bị phá, một khô lâu đen cao khoảng một trượng phun ma khí liên tục, phía trên có hắc động. Trong đống đá vụn có hai tấm thạch bia sá linh nhuyễn ngọc. Sau khi Hàn Lập kích hoạt pháp trận bằng Thiên Tinh Bi, ma khí bị hút sạch, hắc động bị phong ấn hoàn toàn, chướng bích tái lập.","theLucLienQuan":[],"nguon":["@c1068"]},{"id":"kim-do-son","name":"Kim Đồ Sơn","cn":"","capDo":"khac","parentId":"trung-lau-phu","blurb":"Ngọn núi phong cảnh tuyệt đẹp ở Trung Lâu Phủ, Nam Cương. Nơi Hàn Lập bị Nghịch Tinh Bàn truyền tống tới sau khi thoát khỏi Trấn Ma tháp.","detail":"Có thạch đình nơi vài luyện khí kỳ tu sĩ tu luyện. Kim quang từ Nghịch Tinh Bàn truyền tống phá hơn nửa thạch đình khi Hàn Lập xuất hiện.","theLucLienQuan":[],"nguon":["@c1070"]},{"id":"trung-lau-phu","name":"Trung Lâu Phủ","cn":"","capDo":"khac","parentId":"nam-cuong","blurb":"Phủ thuộc Nam Cương, gần Phổ Vân Phủ (nơi phong ấn Côn Ngô Sơn). Hàn Lập xác nhận không bị truyền quá xa.","detail":"Hàn Lập nhận ra Trung Lâu Phủ gần với chỗ bị phong ấn là Phổ Vân Phủ, chứng tỏ Nghịch Tinh Bàn truyền tống hắn trong phạm vi không quá xa.","theLucLienQuan":[],"nguon":["@c1070"]},{"id":"suong-quan","name":"Sương Quận","cn":"霜郡","capDo":"chau","parentId":"dai-tan","blurb":"Châu quận phía bắc Đại Tấn, bảy tám phần bao phủ tuyết trắng sương mù, diện tích xếp thứ năm trong 26 quận lớn nhất.","detail":"Châu quận nằm ở phía bắc Đại Tấn, bảy tám phần diện tích bao phủ tuyết trắng sương mù. Diện tích xếp thứ năm trong 26 quận lớn nhất. Linh sơn linh mạch ít và phẩm chất kém. Sản sinh linh dược băng hàn thuộc tính nổi tiếng. Đại thế lực ít khai thác, chủ yếu tiểu thế gia và tán tu tu luyện công pháp âm hàn thuộc tính chiếm ưu thế.","theLucLienQuan":["Lý gia (Tuyết Liên Phong)"],"nguon":["@c1071"]},{"id":"tuyet-lien-phong","name":"Tuyết Liên Phong","cn":"雪莲峰","aliases":["Tuyết Liên sơn"],"capDo":"khac","parentId":"suong-quan","blurb":"Ngọn núi hoang vu hiểm trở trong Sương Quận, có linh mạch phẩm chất khá. Bị Hàn Lập chiếm từ Lý gia.","detail":"Ngọn núi hoang vu hiểm trở nằm trong Sương Quận, có linh mạch phẩm chất khá tốt, linh khí dày đặc. Trước là lãnh địa Lý gia (tộc trưởng Lý Trung Khiêm, Kết Đan trung kỳ). Bị Hàn Lập chiếm làm nơi ẩn cư tu luyện.","theLucLienQuan":["Lý gia (Tuyết Liên Phong)"],"nguon":["@c1071"]},{"id":"bac-minh-bang-dao","name":"Bắc Minh Băng Đảo","cn":"北冥冰岛","capDo":"vuc","parentId":null,"blurb":"Vùng đất thiên hàn, nơi tọa lạc Tiểu Cực Cung. Mục tiêu tiếp theo của Hàn Lập để tìm Huyền Băng Hoa và tin tức Thái Dương Tinh Hỏa.","detail":"Vùng đất thiên hàn nổi tiếng, nơi tọa lạc tông môn Tiểu Cực Cung. Hàn Lập dự định tới đây sau khi ẩn cư vài năm, với mục đích kép: tìm Huyền Băng Hoa (chủ tài liệu luyện Huyền Băng Đan) và dò tin tức về Thái Dương Tinh Hỏa.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1071"]},{"id":"bang-thanh","name":"Băng Thành","cn":"冰城","capDo":"thanh","parentId":"bac-minh-bang-dao","blurb":"Tòa thành trì phủ sương trắng tỏa hào quang nằm trước cự sơn Tiểu Cực cung trên Bắc Minh đảo, giống Thiên Sơn tiên cảnh.","detail":"Dưới ánh mặt trời Băng Thành tỏa đủ mọi hào quang, sương trắng nhàn nhạt vờn quanh. Phía trước có phiến sông băng ẩn giấu nhiều cấm chế vô hình nguy hiểm. Phía sau là cự sơn vạn trượng hình trụ — tổng đàn Tiểu Cực cung.","theLucLienQuan":["Tiểu Cực cung"],"nguon":["@c1076"]},{"id":"cu-son-tieu-cuc-cung","name":"Cự sơn Tiểu Cực cung","cn":"","capDo":"khac","parentId":"bac-minh-bang-dao","blurb":"Ngọn núi cao vạn trượng hình trụ bàn thẳng tắp phủ đầy băng tuyết đứng phía sau Băng Thành, trên đỉnh ẩn hiện kiến trúc Tiểu Cực cung.","detail":"Bề mặt phủ dày băng tuyết trắng xóa, thỉnh thoảng có vài mảnh xanh biếc. Hàn Lập so sánh: nếu đem so với Côn Ngô thì núi này chỉ như hài tử trước đại nhân. Trên đỉnh là tổng đàn Tiểu Cực cung.","theLucLienQuan":["Tiểu Cực cung"],"nguon":["@c1076"]},{"id":"khu-vuc-mua-da-quy-di","name":"Khu vực mưa đá quỷ dị","cn":"","capDo":"khac","parentId":"bac-minh-bang-dao","blurb":"Vùng gió tuyết mưa đá dữ dội bao quanh Băng Thành, mỗi hạt mưa đá nện vào vòng bảo hộ như cự thạch.","detail":"Khu vực tự nhiên với mưa đá cực kỳ dữ dội, mỗi hạt đá nện vào vòng bảo hộ phát tiếng trầm thấp như cự thạch. Hàn Lập vượt qua trong nửa canh giờ.","theLucLienQuan":[],"nguon":["@c1076"]},{"id":"han-ly-bi-canh","name":"Hàn Ly bí cảnh","cn":"寒厉秘境","capDo":"khac","parentId":"cu-son-tieu-cuc-cung","blurb":"Bí cảnh thực sự của Tiểu Cực cung, nằm sau băng bích cao mấy trăm trượng trên sườn cự sơn. Sơn cốc phong bế bốn bề, bên trong ấm áp như mùa xuân, có ba tòa đại điện bạch ngọc.","detail":"Nằm phía sau băng bích cao mấy trăm trượng, phải dùng ngọc bài phát ngân quang mới mở được thông đạo rộng hai trượng đi vào. Bên trong là sơn cốc rộng lớn, bốn bề phong bế bởi vách tường xanh đậm, đầy kỳ hoa dị thảo, ánh nắng tươi sáng, mùi hương nhẹ nhàng, lúc nào cũng như mùa xuân. Giữa núi có ba tòa đại điện bạch ngọc chiếm một phần ba diện tích sơn cốc. Bán dựa vào vách núi có lầu quỳnh đài tinh mỹ. Nơi cao giai đệ tử nội cung tu luyện, được Nhâm Bích xác nhận đây mới đích thực là Tiểu Cực cung.","theLucLienQuan":["Tiểu Cực cung"],"nguon":["@c1077"]},{"id":"bach-ngung-cac","name":"Bạch Ngưng các","cn":"白凝阁","capDo":"khac","parentId":"han-ly-bi-canh","blurb":"Nơi Bạch Dao Di ở và mời Hàn Lập đến gặp mặt, nằm trong Tiểu Cực cung.","detail":"Nơi Bạch Dao Di bế quan tu luyện trong Tiểu Cực cung. Khi nghe tin Hàn Lập đến, nàng kết thúc bế quan và gửi Truyền Âm phù mời hắn đến đây.","theLucLienQuan":["Tiểu Cực cung"],"nguon":["@c1077"]},{"id":"bang-thanh-tieu-cuc-cung","name":"Băng thành Tiểu Cực cung","cn":"","capDo":"thanh","parentId":"cu-son-tieu-cuc-cung","blurb":"Thành trì bên ngoài Tiểu Cực cung, tường băng hơn ba mươi trượng trong suốt nhất thể không ghép nối.","detail":"Thành trì bao quanh chân cự sơn Tiểu Cực cung. Tường băng cao hơn ba mươi trượng, trong suốt, nhất thể liền khối không có ghép nối. Bên trong đường xá rộng lớn, phòng ốc chỉnh tề, tu sĩ mặc phục sắc vàng trắng. Cửa thành có hơn mười tu sĩ phục sắc trắng canh giữ cùng tuyết vượn. Bầu trời bao trùm cấm chế ánh sáng mờ nhạt, buộc hạ độn quang.","theLucLienQuan":["Tiểu Cực cung"],"nguon":["@c1077"]},{"id":"hu-linh-dien","name":"Hư Linh điện","cn":"","capDo":"khac","parentId":"bang-thanh-tieu-cuc-cung","blurb":"Ba tòa đại điện bạch ngọc trong Tiểu Cực cung, kiểu dáng y hệt Hư Thiên điện ở Loạn Tinh Hải (thể tích bằng 1/3), do tổ sư lập phái cùng hảo hữu tu kiến, bị phong bế.","detail":"Ba tòa đại điện bạch ngọc trong Tiểu Cực cung, kiểu dáng y hệt Hư Thiên điện ở Loạn Tinh Hải nhưng thể tích chỉ bằng một phần ba. Do tổ sư lập phái cùng vài vị hảo hữu dùng pháp lực tu kiến, tồn tại từ ngày lập phái. Cửa điện không có bảng hiệu. Bị phong bế, chỉ khi quá nửa hội đồng trưởng lão đồng ý mới mở được.","theLucLienQuan":["Tiểu Cực cung"],"nguon":["@c1078"]},{"id":"qui-tan-lau","name":"Quí Tân Lâu","capDo":"khac","parentId":"cu-son-tieu-cuc-cung","blurb":"Khu lầu các dành cho khách quý trong Tiểu Cực Cung, hơn mười tòa kiến trúc kề bên vách núi.","detail":"Khu kiến trúc hơn mười tòa lầu các kiểu dáng giống nhau kề bên vách núi, dành cho khách quý của Tiểu Cực Cung. Mỗi lầu hai tầng, tầng hai có cấm chế chống dò xét. Hàn Lập cư ngụ tại đây khi đến Tiểu Cực Cung.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1079"]},{"id":"thach-mon-han-ly","name":"Thạch môn nơi ở Hàn Ly thượng nhân","capDo":"khac","parentId":"cu-son-tieu-cuc-cung","blurb":"Kiến trúc trên vách núi trong Tiểu Cực Cung, nơi ở của đại trưởng lão Hàn Ly thượng nhân.","detail":"Kiến trúc trên vách núi, trước có thạch môn cao năm sáu trượng, tỏa hào quang vàng nhạt, phù văn chớp động, bị hạ cấm chế vô cùng lợi hại.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1079"]},{"id":"dai-sanh-bang-han-han-ly","name":"Đại sảnh băng hàn (nơi ở Hàn Ly thượng nhân)","cn":"","capDo":"khac","parentId":"cu-son-tieu-cuc-cung","blurb":"Đại sảnh dưới lòng đất xây bằng huyền băng ngàn năm, nơi ở của Hàn Ly thượng nhân — Đại trưởng lão Tiểu Cực Cung.","detail":"Phòng lớn xây bằng huyền băng ngàn năm (ngọc thạch bán trong suốt tản hàn mang), bốn góc có tinh trụ lớn, giữa đặt cự đỉnh màu lam chứa Kiền lam băng diễm. Nhiệt độ cực thấp. Nằm cuối thông đạo đi sâu xuống dưới lòng đất, vách thông đạo phủ sương lạnh. Cửa đá phía trên mở ra khi Phong Ly thú dẫn đường.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1080"]},{"id":"tang-kinh-cac-tieu-cuc-cung","name":"Tàng kinh các Tiểu Cực Cung","cn":"","capDo":"khac","parentId":"cu-son-tieu-cuc-cung","blurb":"Nơi chứa thượng cổ điển tịch của Tiểu Cực Cung, sách có cấm chế đặc thù không thể phục chế, chỉ có thể tự đọc ghi nhớ. Cần ngọc bội mới vào được.","detail":"Tàng kinh các bên trong Tiểu Cực Cung, chứa thượng cổ điển tịch. Sách bên trong có cấm chế đặc thù khiến không thể phục chế, chỉ có thể tự đọc rồi ghi nhớ. Hàn Lập được phép vào mười ngày.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1081","@c1082"]},{"id":"bang-ngoc-dong","name":"Băng ngọc động","cn":"冰玉洞","capDo":"khac","parentId":"hu-linh-dien","blurb":"Hang động bên trong Hư Linh điện, mỗi ngàn năm mở ra một lần, nơi có thể sưu tập hàn tủy — vật trọng yếu tu luyện tam đại hàn diễm.","detail":"Nằm trong Hư Linh điện của Tiểu Cực Cung. Mỗi ngàn năm mở ra một lần, có thể sưu tập thêm hàn tủy. Thời điểm mở sắp tới.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1081"]},{"id":"bang-hai","name":"Băng hải","cn":"","capDo":"vuc","parentId":null,"blurb":"Vùng biển băng bao la ngoài Bắc Minh đảo, thiên hạ của yêu thú, càng xa đảo cấp bậc yêu thú càng cao.","detail":"Vùng biển băng ngoài Bắc Minh đảo, là thiên hạ của yêu thú. Càng xa đảo cấp bậc yêu thú càng cao, có cả thập cấp yêu vật. Hai đời Đại trưởng lão Tiểu Cực Cung từng gặp một con Băng Phượng thập cấp thượng cổ, chân chính huyết mạch thượng cổ linh thú, một mình đủ chống hơn phân nửa tu sĩ Tiểu Cực Cung. Tổ sư khai phái Tiểu Cực Cung lập giao ước với yêu thú mạnh nhất băng hải: Tiểu Cực Cung không tùy ý đánh cao giai yêu thú, cao giai yêu thú không được xuất hiện trong trăm vạn dặm Bắc Minh đảo; đê giai yêu thú không chịu ràng buộc.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1082"]},{"id":"ho-bang-sao-huyet-tuyet-hong","name":"Hố băng (sào huyệt Tuyết Hống thú)","cn":"","capDo":"khac","parentId":"bac-minh-bang-dao","blurb":"Hố băng sâu không lường gần Bắc Minh đảo, là sào huyệt Tuyết Hống thú. Đáy hố lộ mạch Vạn Niên Huyền Băng quý hiếm và ba đóa Huyền Băng Hoa.","detail":"Hố băng sâu không lường, miệng hố thổi ra hàn phong lạnh thấu xương. Bên trong tối đen, tường hố có Huyền Băng bình thường phát ảm quang. Đáy hố lộ ra mạch Vạn Niên Huyền Băng quý hiếm bạch sắc quang mang tựa thạch anh và ba đóa Huyền Băng Hoa. Nằm cách Bắc Minh đảo không xa, là nơi Tuyết Hống thú và Băng Nanh thú thất cấp trú ngụ.","theLucLienQuan":["Bắc Minh đảo"],"nguon":["@c1083"]},{"id":"bang-khe-bac-minh","name":"Băng khe (phụ cận Bắc Minh đảo)","cn":"","capDo":"khac","parentId":"bac-minh-bang-dao","blurb":"Khe băng gần Bắc Minh đảo, nơi Hàn Lập luyện đan và giao chiến với nhị yêu bát cấp.","detail":"Sau khi Hàn Lập và Bạch Dao Di rời đi, một đạo kinh hồng bắn ra biến mất, rồi mây đen bí ẩn kéo tới bao phủ băng khe phát tiếng huýt sáo kinh sợ rồi biến mất, cho thấy có kẻ đến tìm dấu vết.","theLucLienQuan":[],"nguon":["@c1085"]},{"id":"dai-sanh-van-nien-huyen-bang","name":"Đại sảnh Vạn Niên Huyền Băng (Tiểu Cực Cung)","cn":"","capDo":"khac","parentId":"cu-son-tieu-cuc-cung","blurb":"Đại sảnh xây bằng Vạn Niên Huyền Băng trong Tiểu Cực Cung, nơi Hàn Ly Thượng Nhân tiếp khách và bàn bạc đối sách.","detail":"Hàn Ly Thượng Nhân tiếp Hàn Lập và Bạch Dao Di tại đây, nghe báo cáo về liên minh yêu thú và ra lệnh phòng bị khẩn cấp.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1085"]},{"id":"hu-linh-dien-cam-dia","name":"Hư Linh Điện (cấm địa)","cn":"虚灵殿","capDo":"khac","parentId":"cu-son-tieu-cuc-cung","blurb":"Cấm địa của Tiểu Cực Cung nằm sâu dưới lòng đất, có ba tòa, bình thường chỉ mở khi đại nạn. Thạch môn trắng ngà cao ba mươi trượng phủ pháp trận cổ quái, lối vào Huyền Ngọc Động.","detail":"Lối vào chính thức không phải cửa trước đại điện mà là mật đạo ngầm dưới cự đỉnh, đi qua băng đạo huyền băng dài trăm trượng với nguyệt quang thạch chiếu sáng. Bí cảnh giữa ba tòa Hư Linh Điện bên ngoài chỉ là trung gian, lối vào Huyền Ngọc Động nằm ở một trong ba tòa. Cần mười sáu ngọc bội trưởng lão tế luyện đồng thời để mở phong ấn thạch môn. Khi mở, hàn phong cực mạnh bùng ra từ bên trong.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1087"]},{"id":"huyen-ngoc-dong","name":"Huyền Ngọc Động","cn":"玄玉洞","capDo":"khac","parentId":"hu-linh-dien-cam-dia","blurb":"Nằm bên trong thạch môn Hư Linh Điện, chứa cực hàn chi khí mà Hàn Ly cần để đột phá bình cảnh.","detail":"Khi thạch môn mở, hàn phong bạch sắc mãnh liệt bùng ra kèm tiếng vang kinh thiên động địa như hàng vạn mãnh thú gầm rú, chạm đất gây tiếng sấm rền, càn quét toàn bộ điện phủ.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1087","@c1090"]},{"id":"dien-phu-ngam","name":"Điện phủ ngầm","cn":"","capDo":"khac","parentId":"hu-linh-dien-cam-dia","blurb":"Tiền sảnh xây bằng ngọc phổ thông phong cách cổ xưa, nằm cuối băng đạo sâu trăm trượng, trước thạch môn Hư Linh Điện.","detail":"Nằm cuối băng đạo dưới lòng đất, xây bằng ngọc phổ thông, phong cách cổ xưa. Cuối điện là thạch môn trắng ngà cao ba mươi trượng phủ đầy ký hiệu pháp trận và hoa văn cổ quái chớp linh quang. Trước thạch môn có khoảng mười sáu mười bảy tu sĩ Nguyên Anh sơ kỳ chờ sẵn.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1087"]},{"id":"te-dan-linh-hu-dien","name":"Tế Đàn (Linh Hư Điện)","cn":"","capDo":"khac","parentId":"hu-linh-dien","blurb":"Tòa tế đàn trắng tinh khiết như ngọc nằm bên trong Linh Hư Điện, cao hơn mười trượng, rộng hơn trăm trượng, giữa có thiên môn vàng nhạt và pháp trận cổ quái với đồ án cự đỉnh.","detail":"Tế đàn trắng tinh khiết bao phủ quầng sáng lam nhạt, giữa có thiên môn vàng nhạt cao bảy tám trượng dán bùa chú thượng cổ. Trung tâm chứa pháp trận cổ quái hơn hai mươi trượng với đồ án cự đỉnh giống Hư Thiên Đỉnh. Nằm sau khu vực 1008 huyền băng trụ của trận Băng Phách Hàn Liệt.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1088"]},{"id":"thai-duong-tinh-thach-oc","name":"Thái Dương tinh thạch ốc","cn":"","capDo":"khac","parentId":"huyen-ngoc-dong","blurb":"Thạch ốc trong Huyền Ngọc động xây bằng Thái Dương tinh thạch bán trong suốt hồng quang, cách ly hàn khí, dùng làm nơi nghỉ ngơi và giảng giải.","detail":"Toàn bộ xây bằng Thái Dương tinh thạch bán trong suốt phát hồng quang lấp lánh, tản nhiệt cực nóng đủ cách ly hoàn toàn hàn khí bên ngoài. Được Hàn Ly thượng nhân dùng làm nơi dẫn đoàn vào nghỉ ngơi và chuẩn bị giảng giải về đột phá bình cảnh.","theLucLienQuan":["Tiểu Cực Cung"],"nguon":["@c1090"]},{"id":"bang-uyen-dao","name":"Băng Uyên đảo","cn":"","capDo":"khac","parentId":null,"blurb":"Lãnh địa của Phượng tiên tử (thập cấp yêu thú), nàng bế quan tại đây hai ngàn năm.","detail":"Đảo riêng của Phượng tiên tử, nơi nàng bế quan hai ngàn năm không rời. Lần này tự mình xuất mã rời đảo dẫn quân tấn công Tiểu Cực cung.","theLucLienQuan":["Băng Uyên đảo"],"nguon":["@c1092"]}]};
